fn zero_state_root() -> Hash {
    Hash::prehashed([0u8; 32])
}

fn deterministic_keypair(seed: impl AsRef<[u8]>, algorithm: Algorithm) -> KeyPair {
    let seed_hash = Hash::new(seed.as_ref());
    KeyPair::from_seed(seed_hash.as_ref().to_vec(), algorithm)
}

fn insert_validated_pending(actor: &mut Actor, block: SignedBlock) -> HashOf<BlockHeader> {
    let block_hash = block.hash();
    let height = block.header().height().get();
    let view = block.header().view_change_index();
    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(u64::MAX);
    assert!(
        committed_height < height,
        "test requires pending block height above committed height (committed={committed_height}, pending={height})"
    );
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block, payload_hash, height, view);
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());
    actor.pending.pending_blocks.insert(block_hash, pending);
    actor.note_proposal_seen(height, view, payload_hash);
    block_hash
}

fn seed_near_quorum_commit_votes_for_block(
    actor: &mut Actor,
    keypairs: &[KeyPair],
    block_hash: HashOf<BlockHeader>,
    height: u64,
    view_idx: u64,
) -> usize {
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit().max(1);
    assert!(required >= 2, "test requires at least two validators");
    let epoch = actor.epoch_for_height(height);
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology =
        super::topology_for_view(&topology, height, view_idx, mode_tag, prf_seed);

    for peer in signature_topology
        .as_ref()
        .iter()
        .take(required.saturating_sub(1))
    {
        let signer_idx = signature_topology
            .as_ref()
            .iter()
            .position(|candidate| candidate == peer)
            .expect("signer in topology");
        let signer = ValidatorIndex::try_from(signer_idx).expect("signer fits u32");
        let keypair = keypairs
            .iter()
            .find(|kp| kp.public_key() == peer.public_key())
            .expect("matching signer keypair");
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view: view_idx,
            epoch,
            highest_qc: None,
            signer,
            bls_sig: Vec::new(),
        };
        let preimage = super::vote_preimage(&actor.common_config.chain, mode_tag, &vote);
        let signature = Signature::new(keypair.private_key(), &preimage);
        vote.bls_sig = signature.payload().to_vec();
        actor.handle_vote(vote);
    }

    required
}

fn pending_session_key(height: u64) -> SessionKey {
    let height_byte = u8::try_from(height).expect("height fits in u8 for test session key");
    (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([height_byte; Hash::LENGTH])),
        height,
        0,
    )
}

fn commit_qc_with_signers(
    chain_id: &ChainId,
    mode_tag: &str,
    header: &BlockHeader,
    parent_state_root: Hash,
    post_state_root: Hash,
    signers: &[&KeyPair],
    signers_bitmap: Vec<u8>,
) -> Qc {
    let validator_set: Vec<_> = signers
        .iter()
        .map(|keypair| PeerId::new(keypair.public_key().clone()))
        .collect();
    let mut qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: header.hash(),
        parent_state_root,
        post_state_root,
        height: header.height().get(),
        view: 0,
        epoch: 0,
        mode_tag: mode_tag.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };
    let preimage = super::qc_bls_preimage(&qc, chain_id, mode_tag);
    let signatures: Vec<Vec<u8>> = signers
        .iter()
        .map(|keypair| {
            Signature::new(keypair.private_key(), &preimage)
                .payload()
                .to_vec()
        })
        .collect();
    let sig_refs: Vec<&[u8]> = signatures.iter().map(Vec::as_slice).collect();
    let aggregate_signature = iroha_crypto::bls_normal_aggregate_signatures(&sig_refs)
        .expect("aggregate commit QC signatures");
    qc.aggregate = QcAggregate {
        signers_bitmap,
        bls_aggregate_signature: aggregate_signature,
    };
    qc
}

fn sample_lane_relay_envelope(
    height: u64,
    lane_id: LaneId,
    chain_id: &ChainId,
    mode_tag: &str,
    signers: &[&KeyPair],
    signers_bitmap: u8,
) -> LaneRelayEnvelope {
    sample_lane_relay_envelope_with_bitmap(
        height,
        lane_id,
        chain_id,
        mode_tag,
        signers,
        signers_bitmap,
    )
}

fn sample_lane_relay_envelope_with_bitmap(
    height: u64,
    lane_id: LaneId,
    chain_id: &ChainId,
    mode_tag: &str,
    signers: &[&KeyPair],
    signers_bitmap: u8,
) -> LaneRelayEnvelope {
    let header = BlockHeader::new(
        NonZeroU64::new(height).expect("non-zero height"),
        None,
        None,
        None,
        1_700_000_000_000,
        0,
    );
    let qc = commit_qc_with_signers(
        chain_id,
        mode_tag,
        &header,
        Hash::new([0xBC; 4]),
        Hash::new([0xAB; 4]),
        signers,
        vec![signers_bitmap],
    );
    let settlement = LaneBlockCommitment {
        block_height: height,
        lane_id,
        dataspace_id: DataSpaceId::GLOBAL,
        tx_count: 1,
        total_local_micro: 1,
        total_xor_due_micro: 1,
        total_xor_after_haircut_micro: 1,
        total_xor_variance_micro: 0,
        swap_metadata: None,
        receipts: vec![LaneSettlementReceipt {
            source_id: [0xAA; 32],
            local_amount_micro: 1,
            xor_due_micro: 1,
            xor_after_haircut_micro: 1,
            xor_variance_micro: 0,
            timestamp_ms: 1_700_000_000_000,
        }],
    };
    let envelope =
        LaneRelayEnvelope::new(header, Some(qc), None, settlement, 0).expect("valid envelope");
    let verified_at_height = Some(height);
    let proof_digest = envelope.expected_fastpq_proof_digest(verified_at_height);
    envelope.with_fastpq_proof_material(Some(LaneFastpqProofMaterial {
        proof_digest,
        verified_at_height,
    }))
}

fn account_id_for_keypair(keypair: &KeyPair) -> AccountId {
    AccountId::new(keypair.public_key().clone())
}

fn install_lane_manifest_registry(state: &State, lanes: &[(LaneId, DataSpaceId, Vec<AccountId>)]) {
    let mut statuses = BTreeMap::new();
    for (lane_id, dataspace_id, validators) in lanes {
        let rules = GovernanceRules {
            validators: validators.clone(),
            ..GovernanceRules::default()
        };
        let status = LaneManifestStatus {
            lane: *lane_id,
            alias: format!("lane-{}", lane_id.as_u32()),
            dataspace: *dataspace_id,
            visibility: LaneVisibility::Public,
            storage: LaneStorageProfile::FullReplica,
            governance: Some("parliament".to_string()),
            manifest_path: Some(PathBuf::from("/tmp/manifest.json")),
            governance_rules: Some(rules),
            privacy_commitments: Vec::new(),
        };
        statuses.insert(*lane_id, status);
    }
    let registry = Arc::new(LaneManifestRegistry::from_statuses(statuses));
    state.install_lane_manifests(&registry);
}

fn seed_npos_epochs(
    actor: &mut Actor,
    epoch_len: u64,
    seed_epoch0: [u8; 32],
    seed_epoch1: [u8; 32],
) {
    let roster_len = actor.effective_commit_topology().len();
    let record0 = iroha_data_model::consensus::VrfEpochRecord {
        epoch: 0,
        seed: seed_epoch0,
        epoch_length: epoch_len,
        commit_deadline_offset: 0,
        reveal_deadline_offset: 0,
        roster_len: u32::try_from(roster_len).unwrap_or(0),
        finalized: true,
        updated_at_height: epoch_len,
        participants: Vec::new(),
        late_reveals: Vec::new(),
        committed_no_reveal: Vec::new(),
        no_participation: Vec::new(),
        penalties_applied: false,
        penalties_applied_at_height: None,
        validator_election: None,
    };
    let record1 = iroha_data_model::consensus::VrfEpochRecord {
        epoch: 1,
        seed: seed_epoch1,
        epoch_length: epoch_len,
        commit_deadline_offset: 0,
        reveal_deadline_offset: 0,
        roster_len: u32::try_from(roster_len).unwrap_or(0),
        finalized: true,
        updated_at_height: epoch_len.saturating_mul(2),
        participants: Vec::new(),
        late_reveals: Vec::new(),
        committed_no_reveal: Vec::new(),
        no_participation: Vec::new(),
        penalties_applied: false,
        penalties_applied_at_height: None,
        validator_election: None,
    };

    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    let mut block = state.world.block();
    let params = block.parameters.get_mut();
    let npos_params = iroha_data_model::parameter::system::SumeragiNposParameters {
        epoch_length_blocks: epoch_len,
        epoch_seed: seed_epoch0,
        evidence_horizon_blocks: 0,
        ..iroha_data_model::parameter::system::SumeragiNposParameters::default()
    };
    params.custom.insert(
        iroha_data_model::parameter::system::SumeragiNposParameters::parameter_id(),
        npos_params.into_custom_parameter(),
    );
    block.vrf_epochs.insert(0, record0);
    block.vrf_epochs.insert(1, record1.clone());
    block.commit();

    if let Some(manager) = actor.epoch_manager.as_mut() {
        manager.set_params(epoch_len, 0, 0);
        manager.restore_from_record(&record1);
    }
}

fn sign_vote_for_view(
    vote: &mut crate::sumeragi::consensus::Vote,
    chain: &ChainId,
    topology: &super::network_topology::Topology,
    keypairs: &[KeyPair],
) {
    let prf_seed = Some(prf_seed_for_chain(chain));
    sign_vote_for_view_with_seed(
        vote,
        chain,
        topology,
        keypairs,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
}

fn prf_seed_for_chain(chain: &ChainId) -> [u8; 32] {
    let chain_id = chain.clone().into_inner();
    let hash = Hash::new(chain_id.as_bytes());
    <[u8; 32]>::from(hash)
}

fn sign_vote_for_view_with_seed(
    vote: &mut crate::sumeragi::consensus::Vote,
    chain: &ChainId,
    topology: &super::network_topology::Topology,
    keypairs: &[KeyPair],
    mode_tag: &str,
    prf_seed: Option<[u8; 32]>,
) {
    let rotated = super::topology_for_view(topology, vote.height, vote.view, mode_tag, prf_seed);
    let signer_idx = usize::try_from(vote.signer).expect("signer fits usize");
    let peer = rotated
        .as_ref()
        .get(signer_idx)
        .expect("signer present in rotated topology");
    let kp = keypairs
        .iter()
        .find(|kp| kp.public_key() == peer.public_key())
        .expect("matching keypair for signer");
    let preimage = super::vote_preimage(chain, mode_tag, vote);
    let sig = Signature::new(kp.private_key(), &preimage);
    vote.bls_sig = sig.payload().to_vec();
}

fn sign_vote_for_canonical_signer(
    vote: &mut crate::sumeragi::consensus::Vote,
    chain: &ChainId,
    topology: &super::network_topology::Topology,
    keypairs: &[KeyPair],
) {
    let canonical_roster = super::roster::canonicalize_roster_for_mode(
        topology.as_ref().to_vec(),
        ConsensusMode::Permissioned,
    );
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let prf_seed = Some(prf_seed_for_chain(chain));
    let signature_topology = super::topology_for_view(
        &canonical_topology,
        vote.height,
        vote.view,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
    let canonical = ValidatorIndex::try_from(vote.signer).expect("signer fits u32");
    let view_idx =
        super::view_index_for_canonical_signer(canonical, &signature_topology, &canonical_topology)
            .expect("canonical signer maps to view index");
    vote.signer = u32::try_from(view_idx).expect("view index fits u32");
    sign_vote_for_view_with_seed(
        vote,
        chain,
        &canonical_topology,
        keypairs,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
}

