#[test]
fn handshake_fingerprint_uses_wsv_params_for_npos() {
    use iroha_config::{base::WithOrigin, parameters::actual::Common as CommonConfig};
    use iroha_data_model::{
        block::consensus::{ConsensusGenesisParams, NPOS_TAG, NposGenesisParams},
        parameter::system::{
            BlockParameter, Parameter, SumeragiConsensusMode, SumeragiNposParameters,
            SumeragiParameter,
        },
    };
    use iroha_p2p::ConsensusConfigCaps;

    let (peer, _pop, key_pair) = bls_peer("127.0.0.1:0");
    let trusted = trusted_with_pops(peer.clone(), Vec::new(), BTreeMap::new());
    let common_config = CommonConfig {
        chain: "test-chain".parse().expect("chain id parses"),
        key_pair: key_pair.clone(),
        peer,
        trusted_peers: WithOrigin::inline(trusted),
        default_account_domain_label: WithOrigin::inline(
            iroha_config::parameters::defaults::common::default_account_domain_label(),
        ),
        chain_discriminant: WithOrigin::inline(
            iroha_config::parameters::defaults::common::chain_discriminant(),
        ),
    };

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.npos.epoch_length_blocks = 3;
    consensus_cfg.collectors.k = 1;
    consensus_cfg.collectors.redundant_send_r = 1;

    let npos_params = SumeragiNposParameters {
        epoch_seed: [0x11; 32],
        k_aggregators: 5,
        redundant_send_r: 4,
        vrf_commit_window_blocks: 100,
        vrf_reveal_window_blocks: 40,
        max_validators: 21,
        min_self_bond: 10,
        min_nomination_bond: 5,
        max_nominator_concentration_pct: 25,
        seat_band_pct: 5,
        max_entity_correlation_pct: 30,
        finality_margin_blocks: 9,
        evidence_horizon_blocks: 500,
        activation_lag_blocks: 7,
        slashing_delay_blocks: 9,
        epoch_length_blocks: 12,
    };

    let world = World::default();
    {
        let mut block = world.block();
        let params = block.parameters.get_mut();
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::DaEnabled(false)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::BlockTimeMs(1600)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::CommitTimeMs(1600)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::MinFinalityMs(100)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::PacingFactorBps(
            25_000,
        )));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::MaxClockDriftMs(400)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::CollectorsK(3)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::RedundantSendR(2)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::NextMode(
            SumeragiConsensusMode::Npos,
        )));
        params.set_parameter(Parameter::Sumeragi(
            SumeragiParameter::ModeActivationHeight(0),
        ));
        params.set_parameter(Parameter::Block(BlockParameter::MaxTransactions(nonzero!(
            11_u64
        ))));
        params.set_parameter(Parameter::Custom(npos_params.into_custom_parameter()));
        block.commit();
    }

    let kura = Kura::blank_kura_for_testing();
    let state = State::new_for_testing(world, Arc::clone(&kura), LiveQueryStore::start_test());
    let view = state.view();
    let config_caps = ConsensusConfigCaps {
        collectors_k: 0,
        redundant_send_r: 0,
        da_enabled: false,
        rbc_chunk_max_bytes: 0,
        rbc_session_ttl_ms: 0,
        rbc_store_max_sessions: 0,
        rbc_store_soft_sessions: 0,
        rbc_store_max_bytes: 0,
        rbc_store_soft_bytes: 0,
    };

    let (mode_tag, bls_domain, caps) =
        crate::sumeragi::consensus::compute_consensus_handshake_caps_from_view(
            &view,
            &common_config,
            &consensus_cfg,
            &config_caps,
        );
    let (mode_tag_from_world, bls_domain_from_world, caps_from_world) = {
        let world = state.world_view();
        let height = u64::try_from(state.committed_height()).unwrap_or(u64::MAX);
        crate::sumeragi::consensus::compute_consensus_handshake_caps_from_world(
            &world,
            height,
            &common_config,
            &consensus_cfg,
            &config_caps,
        )
    };
    assert_eq!(mode_tag_from_world, mode_tag);
    assert_eq!(bls_domain_from_world, bls_domain);
    assert_eq!(caps_from_world, caps);
    assert_eq!(mode_tag, NPOS_TAG.to_string());
    assert_eq!(bls_domain, "bls-iroha2:npos-sumeragi:v1");

    let duration_ms = |value: Duration| -> u64 {
        let ms = value.as_millis();
        u64::try_from(ms).expect("timeout exceeds millisecond range")
    };
    // Handshake fingerprints must use canonical genesis timing and must not drift with adaptive
    // pacing-factor changes that occur at runtime.
    let resolved_timeouts = consensus_cfg
        .npos
        .timeouts_overrides
        .resolve(Duration::from_millis(1600));
    let expected = crate::sumeragi::consensus::compute_consensus_fingerprint_from_params(
        &common_config.chain,
        &ConsensusGenesisParams {
            block_time_ms: 1600,
            commit_time_ms: 1600,
            min_finality_ms: 100,
            max_clock_drift_ms: 400,
            collectors_k: 3,
            redundant_send_r: 2,
            block_max_transactions: 11,
            da_enabled: false,
            epoch_length_blocks: 12,
            bls_domain: bls_domain.clone(),
            npos: Some(NposGenesisParams {
                block_time_ms: 1600,
                timeout_propose_ms: duration_ms(resolved_timeouts.propose),
                timeout_prevote_ms: duration_ms(resolved_timeouts.prevote),
                timeout_precommit_ms: duration_ms(resolved_timeouts.precommit),
                timeout_commit_ms: duration_ms(resolved_timeouts.commit),
                timeout_da_ms: duration_ms(resolved_timeouts.da),
                timeout_aggregator_ms: duration_ms(resolved_timeouts.aggregator),
                k_aggregators: 5,
                redundant_send_r: 4,
                epoch_seed: npos_params.epoch_seed,
                vrf_commit_window_blocks: 100,
                vrf_reveal_window_blocks: 40,
                max_validators: 21,
                min_self_bond: 10,
                min_nomination_bond: 5,
                max_nominator_concentration_pct: 25,
                seat_band_pct: 5,
                max_entity_correlation_pct: 30,
                finality_margin_blocks: 9,
                evidence_horizon_blocks: 500,
                activation_lag_blocks: 7,
                slashing_delay_blocks: 9,
            }),
        },
        &mode_tag,
    );
    assert_eq!(caps.consensus_fingerprint, expected);
}

#[test]
fn handshake_fingerprint_uses_chain_seed_without_npos_params() {
    use iroha_config::{base::WithOrigin, parameters::actual::Common as CommonConfig};
    use iroha_data_model::{
        block::consensus::{ConsensusGenesisParams, NPOS_TAG, NposGenesisParams},
        parameter::system::{BlockParameter, Parameter, SumeragiParameter},
    };
    use iroha_p2p::ConsensusConfigCaps;

    let (peer, _pop, key_pair) = bls_peer("127.0.0.1:0");
    let trusted = trusted_with_pops(peer.clone(), Vec::new(), BTreeMap::new());
    let common_config = CommonConfig {
        chain: "test-chain-fallback".parse().expect("chain id parses"),
        key_pair: key_pair.clone(),
        peer,
        trusted_peers: WithOrigin::inline(trusted),
        default_account_domain_label: WithOrigin::inline(
            iroha_config::parameters::defaults::common::default_account_domain_label(),
        ),
        chain_discriminant: WithOrigin::inline(
            iroha_config::parameters::defaults::common::chain_discriminant(),
        ),
    };

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.npos.epoch_length_blocks = 9;
    consensus_cfg.npos.timeouts_overrides.propose = Some(Duration::from_millis(200));
    consensus_cfg.npos.timeouts_overrides.prevote = Some(Duration::from_millis(220));
    consensus_cfg.npos.timeouts_overrides.precommit = Some(Duration::from_millis(240));
    consensus_cfg.npos.timeouts_overrides.commit = Some(Duration::from_millis(260));
    consensus_cfg.npos.timeouts_overrides.da = Some(Duration::from_millis(280));
    consensus_cfg.npos.timeouts_overrides.aggregator = Some(Duration::from_millis(300));
    consensus_cfg.collectors.k = 2;
    consensus_cfg.collectors.redundant_send_r = 3;
    consensus_cfg.npos.vrf.commit_window_blocks = 42;
    consensus_cfg.npos.vrf.reveal_window_blocks = 7;
    consensus_cfg.npos.election.max_validators = 10;
    consensus_cfg.npos.election.min_self_bond = 5;
    consensus_cfg.npos.election.min_nomination_bond = 3;
    consensus_cfg.npos.election.max_nominator_concentration_pct = 20;
    consensus_cfg.npos.election.seat_band_pct = 4;
    consensus_cfg.npos.election.max_entity_correlation_pct = 30;
    consensus_cfg.npos.election.finality_margin_blocks = 6;
    consensus_cfg.npos.reconfig.evidence_horizon_blocks = 500;
    consensus_cfg.npos.reconfig.activation_lag_blocks = 7;

    let world = World::default();
    {
        let mut block = world.block();
        let params = block.parameters.get_mut();
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::DaEnabled(false)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::BlockTimeMs(1600)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::CommitTimeMs(1600)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::MinFinalityMs(100)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::MaxClockDriftMs(400)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::CollectorsK(3)));
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::RedundantSendR(2)));
        params.set_parameter(Parameter::Block(BlockParameter::MaxTransactions(nonzero!(
            11_u64
        ))));
        block.commit();
    }

    let kura = Kura::blank_kura_for_testing();
    let state = State::new_for_testing(world, Arc::clone(&kura), LiveQueryStore::start_test());
    let view = state.view();
    let config_caps = ConsensusConfigCaps {
        collectors_k: 0,
        redundant_send_r: 0,
        da_enabled: false,
        rbc_chunk_max_bytes: 0,
        rbc_session_ttl_ms: 0,
        rbc_store_max_sessions: 0,
        rbc_store_soft_sessions: 0,
        rbc_store_max_bytes: 0,
        rbc_store_soft_bytes: 0,
    };

    let (mode_tag, bls_domain, caps) =
        crate::sumeragi::consensus::compute_consensus_handshake_caps_from_view(
            &view,
            &common_config,
            &consensus_cfg,
            &config_caps,
        );
    assert_eq!(mode_tag, NPOS_TAG.to_string());
    assert_eq!(bls_domain, "bls-iroha2:npos-sumeragi:v1");

    let chain_bytes = common_config.chain.clone().into_inner();
    let chain_hash = iroha_crypto::Hash::new(chain_bytes.as_bytes());
    let expected_seed = <[u8; 32]>::from(chain_hash);
    let duration_ms = |value: Duration| -> u64 {
        let ms = value.as_millis();
        u64::try_from(ms).expect("timeout exceeds millisecond range")
    };
    let resolved_timeouts = consensus_cfg
        .npos
        .timeouts_overrides
        .resolve(Duration::from_millis(1600));
    let expected = crate::sumeragi::consensus::compute_consensus_fingerprint_from_params(
        &common_config.chain,
        &ConsensusGenesisParams {
            block_time_ms: 1600,
            commit_time_ms: 1600,
            min_finality_ms: 100,
            max_clock_drift_ms: 400,
            collectors_k: 3,
            redundant_send_r: 2,
            block_max_transactions: 11,
            da_enabled: false,
            epoch_length_blocks: 9,
            bls_domain: bls_domain.clone(),
            npos: Some(NposGenesisParams {
                block_time_ms: 1600,
                timeout_propose_ms: duration_ms(resolved_timeouts.propose),
                timeout_prevote_ms: duration_ms(resolved_timeouts.prevote),
                timeout_precommit_ms: duration_ms(resolved_timeouts.precommit),
                timeout_commit_ms: duration_ms(resolved_timeouts.commit),
                timeout_da_ms: duration_ms(resolved_timeouts.da),
                timeout_aggregator_ms: duration_ms(resolved_timeouts.aggregator),
                k_aggregators: consensus_cfg
                    .collectors
                    .k
                    .try_into()
                    .expect("collectors.k fits u16"),
                redundant_send_r: consensus_cfg.collectors.redundant_send_r,
                epoch_seed: expected_seed,
                vrf_commit_window_blocks: consensus_cfg.npos.vrf.commit_window_blocks,
                vrf_reveal_window_blocks: consensus_cfg.npos.vrf.reveal_window_blocks,
                max_validators: consensus_cfg.npos.election.max_validators,
                min_self_bond: consensus_cfg.npos.election.min_self_bond,
                min_nomination_bond: consensus_cfg.npos.election.min_nomination_bond,
                max_nominator_concentration_pct: consensus_cfg
                    .npos
                    .election
                    .max_nominator_concentration_pct,
                seat_band_pct: consensus_cfg.npos.election.seat_band_pct,
                max_entity_correlation_pct: consensus_cfg.npos.election.max_entity_correlation_pct,
                finality_margin_blocks: consensus_cfg.npos.election.finality_margin_blocks,
                evidence_horizon_blocks: consensus_cfg.npos.reconfig.evidence_horizon_blocks,
                activation_lag_blocks: consensus_cfg.npos.reconfig.activation_lag_blocks,
                slashing_delay_blocks: consensus_cfg.npos.reconfig.slashing_delay_blocks,
            }),
        },
        &mode_tag,
    );
    assert_eq!(caps.consensus_fingerprint, expected);
}

struct TestActorHarness {
    actor: Actor,
    background_rx: std::sync::mpsc::Receiver<BackgroundPost>,
    shutdown: iroha_futures::supervisor::ShutdownSignal,
    _network_child: iroha_futures::supervisor::Child,
    _gossiper_child: iroha_futures::supervisor::Child,
    _spool_dir: TestTempDir,
    key_pairs: Vec<KeyPair>,
}

impl Drop for TestActorHarness {
    fn drop(&mut self) {
        self.shutdown.send();
    }
}

static TEST_TEMP_COUNTER: AtomicU64 = AtomicU64::new(0);

struct TestTempDir {
    path: PathBuf,
}

impl TestTempDir {
    fn new(prefix: &str) -> Self {
        let id = TEST_TEMP_COUNTER.fetch_add(1, Ordering::Relaxed);
        let pid = std::process::id();
        let path = std::env::temp_dir().join(format!("iroha-{prefix}-{pid}-{id}"));
        let _ = fs::remove_dir_all(&path);
        fs::create_dir_all(&path).expect("create test temp dir");
        Self { path }
    }

    fn path(&self) -> &PathBuf {
        &self.path
    }
}

impl Drop for TestTempDir {
    fn drop(&mut self) {
        let _ = fs::remove_dir_all(&self.path);
    }
}

struct LocalRemovedGuard {
    previous: bool,
    _guard: crate::sumeragi::status::TestLockGuard,
}

impl LocalRemovedGuard {
    fn new(removed: bool) -> Self {
        let guard = super::status::local_removed_test_guard();
        let previous = super::status::local_peer_removed();
        super::status::set_local_removed_from_world(removed);
        Self {
            previous,
            _guard: guard,
        }
    }
}

impl Drop for LocalRemovedGuard {
    fn drop(&mut self) {
        super::status::set_local_removed_from_world(self.previous);
    }
}

const NETWORK_START_TIMEOUT: Duration = Duration::from_secs(5);

fn real_network_requested_for_tests() -> bool {
    std::env::var_os("IROHA_TEST_REAL_NETWORK").is_some()
}

fn real_network_allowed_for_tests(real_network_requested: bool) -> bool {
    if !real_network_requested {
        return false;
    }
    let flavor = tokio::runtime::Handle::try_current()
        .map(|handle| handle.runtime_flavor())
        .ok();
    !matches!(flavor, Some(tokio::runtime::RuntimeFlavor::CurrentThread))
}

async fn start_network_or_closed(
    key_pair: KeyPair,
    network_cfg: iroha_config::parameters::actual::Network,
    chain_id: Option<ChainId>,
    shutdown: iroha_futures::supervisor::ShutdownSignal,
    real_network_requested: bool,
) -> (crate::IrohaNetwork, iroha_futures::supervisor::Child) {
    // Unit tests do not need a live P2P network and concurrent sockets can introduce flakiness.
    // Opt in to real networking only when explicitly requested.
    if !real_network_allowed_for_tests(real_network_requested) {
        if real_network_requested {
            eprintln!(
                "warning: IROHA_TEST_REAL_NETWORK ignored on current-thread runtime; using closed handle"
            );
        }
        let handle = crate::IrohaNetwork::closed_for_tests();
        let child = iroha_futures::supervisor::Child::from(tokio::spawn(async {}));
        return (handle, child);
    }
    let start = tokio::time::timeout(
        NETWORK_START_TIMEOUT,
        crate::IrohaNetwork::start(key_pair, network_cfg, chain_id, None, None, shutdown),
    )
    .await;
    match start {
        Ok(Ok(started)) => started,
        Ok(Err(err)) => {
            let permission_denied = matches!(
                err,
                iroha_p2p::Error::BindListener { ref error, .. }
                    if error.kind() == io::ErrorKind::PermissionDenied
            );
            if permission_denied {
                eprintln!("warning: network bind unavailable in tests; using closed handle: {err}");
            } else {
                eprintln!("warning: network start failed in tests; using closed handle: {err}");
            }
            let handle = crate::IrohaNetwork::closed_for_tests();
            let child = iroha_futures::supervisor::Child::from(tokio::spawn(async {}));
            (handle, child)
        }
        Err(_) => {
            eprintln!(
                "warning: network start timed out after {:?} in tests; using closed handle",
                NETWORK_START_TIMEOUT
            );
            let handle = crate::IrohaNetwork::closed_for_tests();
            let child = iroha_futures::supervisor::Child::from(tokio::spawn(async {}));
            (handle, child)
        }
    }
}

#[tokio::test(flavor = "current_thread")]
async fn real_network_opt_in_is_ignored_on_current_thread() {
    assert!(
        !real_network_allowed_for_tests(false),
        "real networking should remain disabled without explicit opt-in"
    );
    assert!(
        !real_network_allowed_for_tests(true),
        "current-thread runtime should not attempt real networking in tests"
    );
}

