#[test]
fn effective_commit_topology_falls_back_to_genesis_roster_when_empty() {
    use iroha_config::base::WithOrigin;
    use iroha_config::parameters::actual::Common as CommonConfig;
    use iroha_genesis::{GenesisBuilder, GenesisTopologyEntry};

    let (peer_a, pop_a, _kp_a) = bls_peer("127.0.0.1:20001");
    let (peer_b, pop_b, _kp_b) = bls_peer("127.0.0.1:20002");
    let chain_id: ChainId = "genesis-roster-fallback".parse().expect("chain id parses");
    let genesis = GenesisBuilder::new_without_executor(chain_id.clone(), "ivm/libs/not/installed")
        .set_topology(vec![
            GenesisTopologyEntry::new(peer_a.id().clone(), pop_a),
            GenesisTopologyEntry::new(peer_b.id().clone(), pop_b),
        ])
        .build_and_sign(&SAMPLE_GENESIS_ACCOUNT_KEYPAIR)
        .expect("genesis block should be built");

    let kura = Kura::blank_kura_for_testing();
    kura.store_block(genesis.0.clone())
        .expect("store genesis block");

    let genesis_id = SAMPLE_GENESIS_ACCOUNT_ID.clone();
    let genesis_domain = Domain::new(iroha_genesis::GENESIS_DOMAIN_ID.clone()).build(&genesis_id);
    let genesis_account = iroha_data_model::prelude::Account::new(
        genesis_id
            .clone()
            .to_account_id(iroha_genesis::GENESIS_DOMAIN_ID.clone()),
    )
    .build(&genesis_id);
    let world = World::with([genesis_domain], [genesis_account], []);
    let mut state = State::new_for_testing(world, Arc::clone(&kura), LiveQueryStore::start_test());
    state.chain_id = chain_id.clone();
    state.push_block_hash_for_testing(genesis.0.hash());
    let state = Arc::new(state);

    let key_pair = deterministic_keypair(b"genesis-roster-fallback-peer", Algorithm::Ed25519);
    let address: SocketAddr = "127.0.0.1:0".parse().expect("socket address parses");
    let local_peer = Peer::new(address.into(), PeerId::new(key_pair.public_key().clone()));
    let trusted_peers = trusted_with_pops(local_peer.clone(), Vec::new(), BTreeMap::new());
    let common_config = CommonConfig {
        chain: chain_id.clone(),
        key_pair: key_pair.clone(),
        peer: local_peer,
        trusted_peers: WithOrigin::inline(trusted_peers),
        default_account_domain_label: WithOrigin::inline(
            iroha_config::parameters::defaults::common::default_account_domain_label(),
        ),
        chain_discriminant: WithOrigin::inline(
            iroha_config::parameters::defaults::common::chain_discriminant(),
        ),
    };

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;

    let time_source = TimeSource::new_system();
    let queue = Arc::new(Queue::test(QueueConfig::default(), &time_source));
    let events_sender: crate::EventsSender = tokio::sync::broadcast::Sender::new(1);
    let network = crate::IrohaNetwork::closed_for_tests();
    let peers_gossiper = crate::peers_gossiper::PeersGossiperHandle::closed_for_tests();
    let spool_dir = tempfile::tempdir().expect("tempdir");
    let genesis_network = crate::sumeragi::GenesisWithPubKey {
        genesis: Some(genesis.clone()),
        public_key: key_pair.public_key().clone(),
    };
    let rbc_status_handle = rbc_status::register_handle();
    let block_sync_gossip_limit =
        usize::try_from(iroha_config::parameters::defaults::network::BLOCK_GOSSIP_SIZE.get())
            .unwrap_or(usize::MAX);
    let block_payload_dedup = Arc::new(Mutex::new(crate::sumeragi::BlockPayloadDedupCache::new(
        crate::sumeragi::BLOCK_PAYLOAD_DEDUP_CACHE_PER_KIND,
        crate::sumeragi::BLOCK_PAYLOAD_DEDUP_CACHE_TTL,
    )));

    #[cfg(feature = "telemetry")]
    let telemetry =
        crate::telemetry::Telemetry::new(Arc::new(crate::telemetry::Metrics::default()), true);

    #[cfg(feature = "telemetry")]
    let actor = Actor::new(
        consensus_cfg,
        common_config,
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_CONSENSUS.get(),
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_BLOCK_SYNC.get(),
        events_sender,
        Arc::clone(&state),
        Arc::clone(&queue),
        Arc::clone(&kura),
        network,
        spool_dir.path().to_path_buf(),
        peers_gossiper,
        genesis_network,
        crate::kura::BlockCount(1),
        block_sync_gossip_limit,
        telemetry,
        None,
        None,
        None,
        None,
        block_payload_dedup,
        rbc_status_handle,
    )
    .expect("actor init");

    #[cfg(not(feature = "telemetry"))]
    let actor = Actor::new(
        consensus_cfg,
        common_config,
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_CONSENSUS.get(),
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_BLOCK_SYNC.get(),
        events_sender,
        Arc::clone(&state),
        Arc::clone(&queue),
        Arc::clone(&kura),
        network,
        spool_dir.path().to_path_buf(),
        peers_gossiper,
        genesis_network,
        crate::kura::BlockCount(1),
        block_sync_gossip_limit,
        None,
        None,
        None,
        None,
        block_payload_dedup,
        rbc_status_handle,
    )
    .expect("actor init");

    let expected = super::roster::canonicalize_roster_for_mode(
        vec![peer_a.id().clone(), peer_b.id().clone()],
        ConsensusMode::Permissioned,
    );
    let roster = actor.effective_commit_topology();
    assert_eq!(
        roster, expected,
        "empty topology should fall back to genesis roster"
    );
}

#[tokio::test(flavor = "current_thread")]
async fn merge_committee_signatures_commit_merge_entry() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    actor.state.nexus.write().enabled = true;
    let lane_keypairs = [
        harness.key_pairs[0].clone(),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
    ];
    let lane_validators: Vec<AccountId> =
        lane_keypairs.iter().map(account_id_for_keypair).collect();
    install_lane_manifest_registry(
        &actor.state,
        &[(LaneId::new(0), DataSpaceId::GLOBAL, lane_validators)],
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut block = state.world.block();
        let lane_peers: Vec<_> = lane_keypairs
            .iter()
            .map(|keypair| PeerId::new(keypair.public_key().clone()))
            .collect();
        insert_consensus_keys_for_peers(&mut block, &lane_peers, &lane_keypairs);
        block.commit();
    }
    let mut topo = actor.state.commit_topology.block();
    topo.clear();
    topo.push(actor.common_config.peer.id().clone());
    topo.commit();

    let signers: Vec<&KeyPair> = lane_keypairs.iter().collect();
    let (_, mode_tag, _) = actor.consensus_context_for_height(1);
    let envelope = sample_lane_relay_envelope(
        1,
        LaneId::new(0),
        &actor.chain_id,
        mode_tag,
        &signers,
        0b0000_1111,
    );
    actor
        .on_lane_relay_message(super::LaneRelayMessage::Envelope(envelope.clone()))
        .expect("lane relay handled");

    let entry = actor
        .state
        .merge_ledger()
        .latest()
        .expect("merge entry committed");
    assert_eq!(entry.epoch_id, 1);
    assert_eq!(
        entry.lane_tips().as_slice(),
        &[envelope.block_header.hash()]
    );
    assert_eq!(
        entry.merge_hint_roots().as_slice(),
        &[*envelope.settlement_hash]
    );
    assert_eq!(entry.merge_qc.signers_bitmap, vec![0x01]);
    assert!(!entry.merge_qc.aggregate_signature.is_empty());

    let candidate = crate::merge::MergeLedgerCandidate::from(entry.as_ref());
    let expected = crate::merge::merge_qc_message_digest(&actor.chain_id, &candidate);
    assert_eq!(entry.merge_qc.message_digest, expected);
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn merge_committee_accepts_remote_signature() {
    let mut harness = test_actor_harness(2).await;
    let actor = &mut harness.actor;

    actor.state.nexus.write().enabled = true;
    let lane_keypairs = [
        harness.key_pairs[0].clone(),
        harness.key_pairs[1].clone(),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
    ];
    let lane_validators: Vec<AccountId> =
        lane_keypairs.iter().map(account_id_for_keypair).collect();
    install_lane_manifest_registry(
        &actor.state,
        &[(LaneId::new(0), DataSpaceId::GLOBAL, lane_validators)],
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut block = state.world.block();
        let lane_peers: Vec<_> = lane_keypairs
            .iter()
            .map(|keypair| PeerId::new(keypair.public_key().clone()))
            .collect();
        insert_consensus_keys_for_peers(&mut block, &lane_peers, &lane_keypairs);
        block.commit();
    }
    let mut topo = actor.state.commit_topology.block();
    topo.clear();
    topo.push(actor.common_config.peer.id().clone());
    topo.push(PeerId::new(harness.key_pairs[1].public_key().clone()));
    topo.commit();

    let signers: Vec<&KeyPair> = lane_keypairs.iter().collect();
    let (_, mode_tag, _) = actor.consensus_context_for_height(1);
    let envelope = sample_lane_relay_envelope(
        1,
        LaneId::new(0),
        &actor.chain_id,
        mode_tag,
        &signers,
        0b0000_1111,
    );
    actor
        .on_lane_relay_message(super::LaneRelayMessage::Envelope(envelope))
        .expect("lane relay handled");
    assert!(
        actor.state.merge_ledger().latest().is_none(),
        "quorum requires remote signature"
    );

    let candidates = actor.state.merge_entry_candidates_from_lane_relays();
    assert_eq!(candidates.len(), 1);
    let candidate = &candidates[0];
    let message_digest = crate::merge::merge_qc_message_digest(&actor.chain_id, candidate);
    let signature = Signature::new(harness.key_pairs[1].private_key(), message_digest.as_ref());
    let merge_signature = MergeCommitteeSignature {
        epoch_id: candidate.epoch_id,
        view: 0,
        signer: 1,
        message_digest,
        bls_sig: signature.payload().to_vec(),
    };

    actor
        .on_lane_relay_message(super::LaneRelayMessage::MergeSignature(merge_signature))
        .expect("merge signature handled");

    let entry = actor
        .state
        .merge_ledger()
        .latest()
        .expect("merge entry committed");
    assert_eq!(entry.epoch_id, candidate.epoch_id);
    assert_eq!(entry.merge_qc.signers_bitmap, vec![0x03]);
    assert!(!entry.merge_qc.aggregate_signature.is_empty());
    harness.shutdown.send();
}

