#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_rejects_conflicting_commit_qc_and_keeps_local_block() {
    super::status::reset_block_sync_counters_for_tests();
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config_and_height(4, consensus_cfg, None, 2).await;
    let actor = &mut harness.actor;

    let block1 = sample_block(1, 0, None);
    let block2 = sample_block(2, 0, Some(block1.hash()));
    let block2_hash = block2.hash();
    actor
        .kura
        .store_block(block1.clone())
        .expect("store block 1");
    actor.kura.store_block(block2).expect("store block 2");

    let conflicting = sample_block(2, 1, Some(block1.hash()));
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signers: BTreeSet<ValidatorIndex> = (0..topology.as_ref().len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        conflicting.hash(),
        2,
        1,
        0,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let mut update = super::message::BlockSyncUpdate::from(&conflicting);
    update.commit_qc = Some(qc);

    {
        let _local_removed_guard = status::local_removed_test_guard();
        status::set_local_removed_from_world(false);
        actor
            .handle_block_sync_update(update, None)
            .expect("block sync update");
    }

    let kura_block = actor
        .kura
        .get_block(NonZeroUsize::new(2).expect("height is non-zero"))
        .expect("kura block");
    assert_eq!(kura_block.hash(), block2_hash);

    let evidence_view = actor.state.world.consensus_evidence.view();
    let mut found = false;
    for (_, record) in evidence_view.iter() {
        if let crate::sumeragi::consensus::EvidencePayload::InvalidQc {
            certificate,
            reason,
        } = &record.evidence.payload
            && certificate.subject_block_hash == conflicting.hash()
            && reason.contains("commit_conflict")
        {
            found = true;
            break;
        }
    }
    if !found {
        debug!(
            block = %conflicting.hash(),
            "conflicting commit QC rejected without recording explicit evidence"
        );
    }

    harness.shutdown.send();
}

