    Actor::apply_cached_qcs_to_block_sync_update(
        &mut update,
        &actor.qc_cache,
        &actor.vote_log,
        block_hash,
        height,
        view,
        expected_epoch,
        actor.state.as_ref(),
        actor.config.consensus_mode,
    );
