#[tokio::test(flavor = "current_thread")]
async fn frontier_body_repair_fetches_leader_before_voter_fallback() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let background_log = attach_background_log(actor);

    let genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = actor.committed_height_snapshot().saturating_add(1);
    let roster = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(roster);
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let (view, signature_topology, leader_peer) = {
        let mut selected = None;
        for candidate_view in 0..16u64 {
            let signature_topology =
                super::topology_for_view(&topology, height, candidate_view, mode_tag, prf_seed);
            if signature_topology.leader() != actor.common_config.peer.id() {
                selected = Some((
                    candidate_view,
                    signature_topology.clone(),
                    signature_topology.leader().clone(),
                ));
                break;
            }
        }
        selected.expect("expected a remote leader in the first few views")
    };
    let block =
        nonempty_block_for_actor(actor, &harness.key_pairs, height, view, Some(genesis_hash));
    let block_hash = block.hash();
    let signers: BTreeSet<ValidatorIndex> = (0..signature_topology.as_ref().len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();

    let _ = take_background_log(&background_log);
    assert!(actor.handle_frontier_body_gap_with_topology(
        block_hash,
        height,
        view,
        &signers,
        &topology,
        true,
        Instant::now(),
    ));
    let entries = take_background_log(&background_log);
    assert!(
        entries.iter().any(|entry| {
            matches!(
                entry,
                super::BackgroundRequestLogEntry {
                    kind: super::BackgroundRequestLogKind::Post,
                    msg_kind: Some("FetchBlockBody"),
                    peer: Some(peer),
                } if peer == &leader_peer
            )
        }),
        "first frontier body fetch must target the slot leader",
    );

    let expected_voters = {
        let slot = actor.frontier_slot.as_mut().expect("frontier slot");
        let expected = slot
            .voters
            .iter()
            .filter(|peer| *peer != &leader_peer)
            .cloned()
            .collect::<BTreeSet<_>>();
        slot.last_fetch_at = Some(Instant::now() - slot.retry_window - Duration::from_millis(1));
        expected
    };

    let _ = take_background_log(&background_log);
    assert!(
        actor.retry_frontier_block_body_fetch(Instant::now()),
        "retry should fan out to known frontier voters after leader timeout"
    );
    let fetched_voters: BTreeSet<_> = take_background_log(&background_log)
        .into_iter()
        .filter_map(|entry| match entry {
            super::BackgroundRequestLogEntry {
                kind: super::BackgroundRequestLogKind::Post,
                msg_kind: Some("FetchBlockBody"),
                peer: Some(peer),
            } => Some(peer),
            _ => None,
        })
        .collect();
    assert_eq!(
        fetched_voters, expected_voters,
        "retry must stay on the exact slot voter set and exclude the leader once fallback begins"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_keeps_rbc_transport_rebuildable_when_da_enabled() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = 2u64;
    let view = 0u64;
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty());
    let mut topology = super::network_topology::Topology::new(roster.clone());
    let leader_index = actor
        .leader_index_for(&mut topology, height, view)
        .expect("leader index available");
    let leader_peer = topology
        .as_ref()
        .get(leader_index)
        .expect("leader peer")
        .clone();
    let leader_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == leader_peer.public_key())
        .expect("leader keypair");
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.common_config.chain,
        height,
        view,
        None,
        leader_kp,
        u64::try_from(leader_index).expect("leader index fits u64"),
    );
    let block_hash = block.hash();
    let block_clone = block.clone();
    actor.kura.store_block(block).expect("store block");

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height,
        view,
        priority: None,
        requester_roster_proof_known: None,
    };
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    assert!(
        harness.background_rx.try_iter().next().is_none(),
        "consensus-priority missing-block responses should bypass the background queue"
    );
    let key = Actor::session_key(&block_hash, height, view);
    let init = actor
        .rebuild_rbc_init_from_block(&block_clone, key)
        .expect("expected RBC init rebuild");
    assert_eq!(init.block_hash, block_hash);
    assert_eq!(init.height, height);
    assert_eq!(init.view, view);
    let payload_bytes = super::proposals::block_payload_bytes(&block_clone);
    let chunks = super::rbc::chunk_payload_bytes(&payload_bytes, actor.config.rbc.chunk_max_bytes);
    assert!(!chunks.is_empty(), "expected RBC chunks response");

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_falls_back_to_block_created_when_oversized() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block = sample_block(2, 0, None);
    let block_hash = block.hash();
    actor.kura.store_block(block.clone()).expect("store block");

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signers_bitmap = vec![0b0000_0111];
    let aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        block.header().height().get(),
        block.header().view_change_index(),
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let validator_set = topology.as_ref().to_vec();
    let cached_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: block.header().height().get(),
        view: block.header().view_change_index(),
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature: aggregate_signature,
        },
    };
    actor.qc_cache.insert(
        (
            Phase::Commit,
            block_hash,
            block.header().height().get(),
            block.header().view_change_index(),
            0,
        ),
        cached_qc,
    );

    let mut update = super::message::BlockSyncUpdate::from(&block);
    let expected_epoch = actor.epoch_for_height(block.header().height().get());
    Actor::apply_cached_qcs_to_block_sync_update(
        &mut update,
        &actor.qc_cache,
        &actor.vote_log,
        block_hash,
        block.header().height().get(),
        block.header().view_change_index(),
        expected_epoch,
        actor.state.as_ref(),
        actor.config.consensus_mode,
    );
    assert!(update.commit_qc.is_some(), "test requires cached commit QC");
    assert!(
        update.validator_checkpoint.is_none(),
        "test requires commit QC without checkpoint"
    );

    let block_created = BlockMessage::BlockCreated(super::message::BlockCreated {
        block: block.clone(),
        frontier: None,
    });
    let block_created_len =
        super::consensus_block_wire_len(actor.common_config.peer.id(), &block_created);
    let update_len = super::block_sync_update_wire_len(actor.common_config.peer.id(), &update);
    assert!(
        update_len > block_created_len,
        "block sync update should exceed BlockCreated size"
    );
    actor.consensus_payload_frame_cap = block_created_len;

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height: block.header().height().get(),
        view: block.header().view_change_index(),
        priority: None,
        requester_roster_proof_known: None,
    };
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    assert!(
        posts.iter().any(|post| match post {
            BackgroundPost::Post { msg, .. } => matches!(
                msg.as_ref(),
                BlockMessage::BlockCreated(created) if created.block.hash() == block_hash
            ),
            _ => false,
        }),
        "expected BlockCreated fallback when update exceeds payload cap"
    );

    harness.shutdown.send();
}

