#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_stashes_and_serves_when_block_arrives() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let _guard = super::status::message_handling_test_guard();
    super::status::reset_message_handling_for_tests();
    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(0);
    let height = committed_height.saturating_add(1).max(1);
    let view = 0u64;
    let parent_hash = actor.state.view().latest_block_hash();
    let block = sample_block(height, view, parent_hash);
    let block_hash = block.hash();

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height,
        view,
        priority: None,
        requester_roster_proof_known: None,
    };
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    assert!(
        actor
            .pending
            .pending_fetch_requests
            .contains_key(&block_hash),
        "expected fetch request to be stashed"
    );
    assert!(
        harness.background_rx.try_iter().next().is_none(),
        "no payload response should be sent before the block arrives"
    );

    let created = super::message::BlockCreated {
        block: block.clone(),
        frontier: None,
    };
    let queued_response_expected = !matches!(
        actor.build_fetch_pending_block_payload(&block),
        BlockMessage::BlockCreated(_)
    );
    actor
        .handle_block_created(created, None)
        .expect("block created");

    assert!(
        !actor
            .pending
            .pending_fetch_requests
            .contains_key(&block_hash),
        "expected stashed fetch requests to flush once payload is available"
    );
    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    if queued_response_expected {
        assert!(
            posts.iter().any(|post| match post {
                BackgroundPost::Post { msg, .. } => {
                    matches!(
                        msg.as_ref(),
                        BlockMessage::BlockCreated(created) if created.block.hash() == block_hash
                    ) || matches!(
                        msg.as_ref(),
                        BlockMessage::BlockSyncUpdate(update) if update.block.hash() == block_hash
                    )
                }
                _ => false,
            }),
            "expected missing-block fetch response after payload is available"
        );
    }

    super::status::reset_message_handling_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_stash_uses_explicit_roster_proof_signal() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let block_hash = HashOf::from_untyped_unchecked(Hash::prehashed([0xBC; Hash::LENGTH]));
    let peer = actor.common_config.peer.id.clone();
    let height = 2_u64;
    let view = 0_u64;

    actor
        .handle_fetch_pending_block(super::message::FetchPendingBlock {
            requester: peer.clone(),
            block_hash,
            height,
            view,
            priority: Some(super::message::FetchPendingBlockPriority::Consensus),
            requester_roster_proof_known: None,
        })
        .expect("first fetch request");

    let first = actor
        .pending
        .pending_fetch_requests
        .get(&block_hash)
        .and_then(|entry| entry.get(&peer))
        .expect("stashed request metadata after first fetch");
    assert_eq!(
        first.priority,
        super::message::FetchPendingBlockPriority::Consensus
    );
    assert!(
        !first.requester_roster_proof_known,
        "consensus priority must not imply roster proof knowledge"
    );

    actor
        .handle_fetch_pending_block(super::message::FetchPendingBlock {
            requester: peer.clone(),
            block_hash,
            height,
            view,
            priority: None,
            requester_roster_proof_known: Some(true),
        })
        .expect("second fetch request");

    let second = actor
        .pending
        .pending_fetch_requests
        .get(&block_hash)
        .and_then(|entry| entry.get(&peer))
        .expect("stashed request metadata after second fetch");
    assert_eq!(
        second.priority,
        super::message::FetchPendingBlockPriority::Consensus,
        "priority should remain max(consensus, background)"
    );
    assert!(
        second.requester_roster_proof_known,
        "explicit requester signal should be persisted"
    );

    actor
        .handle_fetch_pending_block(super::message::FetchPendingBlock {
            requester: peer.clone(),
            block_hash,
            height,
            view,
            priority: Some(super::message::FetchPendingBlockPriority::Consensus),
            requester_roster_proof_known: None,
        })
        .expect("third fetch request");

    let third = actor
        .pending
        .pending_fetch_requests
        .get(&block_hash)
        .and_then(|entry| entry.get(&peer))
        .expect("stashed request metadata after third fetch");
    assert!(
        third.requester_roster_proof_known,
        "roster proof signal should not be cleared by later requests without the flag"
    );

    harness.shutdown.send();
}

#[test]
fn build_fetch_pending_block_request_uses_explicit_roster_proof_signal() {
    let requester = PeerId::from(KeyPair::random().public_key().clone());
    let block_hash = HashOf::from_untyped_unchecked(Hash::prehashed([0xBD; Hash::LENGTH]));

    let consensus_without_signal = super::build_fetch_pending_block_request(
        requester.clone(),
        block_hash,
        9,
        1,
        super::MissingBlockPriority::Consensus,
        false,
    );
    assert_eq!(
        consensus_without_signal.priority,
        Some(super::message::FetchPendingBlockPriority::Consensus)
    );
    assert_eq!(
        consensus_without_signal.requester_roster_proof_known, None,
        "consensus priority alone must not set roster-proof signal"
    );

    let background_with_signal = super::build_fetch_pending_block_request(
        requester,
        block_hash,
        9,
        1,
        super::MissingBlockPriority::Background,
        true,
    );
    assert_eq!(background_with_signal.priority, None);
    assert_eq!(
        background_with_signal.requester_roster_proof_known,
        Some(true),
        "explicit requester signal should be encoded regardless of priority"
    );
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_stashes_exact_body_request_when_only_rbc_transport_exists() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let _guard = super::status::message_handling_test_guard();
    super::status::reset_message_handling_for_tests();
    let height = 2u64;
    let view = 0u64;
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty());
    let mut topology = super::network_topology::Topology::new(roster.clone());
    let leader_index = actor
        .leader_index_for(&mut topology, height, view)
        .expect("leader index available");
    let leader_peer = topology
        .as_ref()
        .get(leader_index)
        .expect("leader peer")
        .clone();
    let leader_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == leader_peer.public_key())
        .expect("leader keypair");
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.common_config.chain,
        height,
        view,
        None,
        leader_kp,
        u64::try_from(leader_index).expect("leader index fits u64"),
    );
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let key = Actor::session_key(&block_hash, height, view);
    actor
        .seed_rbc_session_from_block(key, &block, payload_hash, false)
        .expect("seed rbc session");
    assert!(
        actor.subsystems.da_rbc.rbc.sessions.contains_key(&key),
        "expected RBC session to be seeded"
    );

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height,
        view,
        priority: None,
        requester_roster_proof_known: None,
    };
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    assert!(
        actor
            .pending
            .pending_fetch_requests
            .contains_key(&block_hash),
        "frontier exact-body fetches should stay stashed until the authoritative block is available"
    );
    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    assert!(
        posts.iter().all(|post| match post {
            BackgroundPost::Post { msg, .. } => !matches!(
                msg.as_ref(),
                BlockMessage::RbcInit(_) | BlockMessage::RbcChunk(_)
            ),
            BackgroundPost::Broadcast { msg, .. } => !matches!(
                msg.as_ref(),
                BlockMessage::RbcInit(_) | BlockMessage::RbcChunk(_)
            ),
            BackgroundPost::PostControlFlow { .. }
            | BackgroundPost::BroadcastControlFlow { .. } => true,
        }),
        "exact-body fetches must not fall back to RBC transport sidecars"
    );

    super::status::reset_message_handling_for_tests();
    harness.shutdown.send();
}

