#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_votes_highest_view_first_for_same_height() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let _genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let state_view = actor.state.view();
    let parent_hash = state_view.latest_block_hash();
    let height = u64::try_from(state_view.height())
        .unwrap_or(0)
        .saturating_add(1);
    drop(state_view);

    let mut candidates = Vec::new();
    for view in 0_u64..32 {
        let block = sample_block(height, view, parent_hash);
        let hash = block.hash();
        candidates.push((view, block, hash));
    }

    let mut selected = None;
    for i in 0..candidates.len() {
        for j in (i + 1)..candidates.len() {
            let (view_a, block_a, hash_a) = &candidates[i];
            let (view_b, block_b, hash_b) = &candidates[j];
            if view_a < view_b && hash_a > hash_b {
                selected = Some((block_a.clone(), block_b.clone()));
                break;
            }
            if view_b < view_a && hash_b > hash_a {
                selected = Some((block_b.clone(), block_a.clone()));
                break;
            }
        }
        if selected.is_some() {
            break;
        }
    }

    let (low_view_block, high_view_block) =
        selected.expect("failed to find view pair with inverse hash ordering");
    let low_view = low_view_block.header().view_change_index();
    let high_view = high_view_block.header().view_change_index();
    assert!(low_view < high_view);

    let low_payload = super::proposals::block_payload_bytes(&low_view_block);
    let low_payload_hash = Hash::new(&low_payload);
    let mut low_pending =
        PendingBlock::new(low_view_block.clone(), low_payload_hash, height, low_view);
    low_pending.validation_status = ValidationStatus::Valid;
    low_pending.parent_state_root = Some(zero_state_root());
    low_pending.post_state_root = Some(zero_state_root());
    actor
        .pending
        .pending_blocks
        .insert(low_view_block.hash(), low_pending);

    let high_payload = super::proposals::block_payload_bytes(&high_view_block);
    let high_payload_hash = Hash::new(&high_payload);
    let mut high_pending = PendingBlock::new(
        high_view_block.clone(),
        high_payload_hash,
        height,
        high_view,
    );
    high_pending.validation_status = ValidationStatus::Valid;
    high_pending.parent_state_root = Some(zero_state_root());
    high_pending.post_state_root = Some(zero_state_root());
    actor
        .pending
        .pending_blocks
        .insert(high_view_block.hash(), high_pending);
    actor.note_proposal_seen(height, high_view, high_payload_hash);

    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);
    actor.process_commit_candidates();

    let local_precommits: Vec<_> = actor
        .vote_log
        .values()
        .filter(|vote| vote.phase == Phase::Commit && vote.height == height)
        .collect();
    assert!(!local_precommits.is_empty());
    let highest = local_precommits
        .iter()
        .max_by_key(|vote| vote.view)
        .expect("at least one precommit");
    assert_eq!(highest.view, high_view);
    assert_eq!(highest.block_hash, high_view_block.hash());
    assert!(
        !local_precommits
            .iter()
            .any(|vote| vote.view == low_view && vote.block_hash == low_view_block.hash()),
        "should not emit a lower-view precommit when a higher-view block is available"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_uses_commit_qc_roster_for_validation() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let active_roster = actor.effective_commit_topology();
    assert!(
        active_roster.len() >= 2,
        "test needs at least two validators to rotate roster"
    );
    let mut history_roster = active_roster.clone();
    let rotate_at = super::network_topology::commit_quorum_from_len(history_roster.len());
    if rotate_at > 0 {
        history_roster[..rotate_at].rotate_right(1);
    }
    assert_ne!(
        history_roster, active_roster,
        "history roster should differ from active roster"
    );

    let parent_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x42; Hash::LENGTH]));
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(parent_hash);
        hashes.commit_for_tests();
    }

    let height = 2u64;
    let view = 0u64;
    let signature_topology = super::topology_for_view(
        &super::network_topology::Topology::new(history_roster.clone()),
        height,
        view,
        PERMISSIONED_TAG,
        None,
    );
    let signer_peer = signature_topology
        .as_ref()
        .first()
        .expect("commit topology not empty");
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair exists in harness");
    let header = BlockHeader {
        height: NonZeroU64::new(height).expect("block height must be non-zero"),
        prev_block_hash: Some(parent_hash),
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        prev_roster_evidence_hash: None,
        creation_time_ms: 0,
        view_change_index: view,
        confidential_features: None,
    };
    let signature = SignatureOf::from_hash(signer_kp.private_key(), header.hash());
    let block_signature = BlockSignature::new(0, signature);
    let block = SignedBlock::presigned(block_signature, header, Vec::new());
    let block_hash = block.hash();

    let mut signers = BTreeSet::new();
    for idx in 0..history_roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, history_roster.len());
    let topology = super::network_topology::Topology::new(history_roster.clone());
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&history_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: history_roster,
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };
    status::record_commit_qc(commit_qc);

    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block, payload_hash, height, view);
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());
    actor.pending.pending_blocks.insert(block_hash, pending);
    actor.note_proposal_seen(height, view, payload_hash);
    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    let has_vote = actor.vote_log.values().any(|vote| {
        vote.phase == Phase::Commit
            && vote.block_hash == block_hash
            && vote.height == height
            && vote.view == view
    });
    assert!(
        has_vote,
        "commit pipeline should validate and emit precommit vote using commit certificate roster"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_validates_inline_for_local_only_commit_topology() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let parent_hash = seed_genesis_block_for_state(&actor.state);
    let height = u64::try_from(actor.state.view().height())
        .unwrap_or(0)
        .saturating_add(1);
    let view = 0_u64;
    let block =
        nonempty_block_for_actor(actor, &harness.key_pairs, height, view, Some(parent_hash));
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);

    let (work_tx, work_rx) = std::sync::mpsc::sync_channel::<super::validation::ValidationWork>(1);
    actor.subsystems.validation.work_txs = vec![work_tx];
    actor.subsystems.validation.result_rx = None;

    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );
    actor.note_proposal_seen(height, view, payload_hash);

    let mut session = Actor::build_rbc_session_from_payload(
        &payload_bytes,
        payload_hash,
        actor.config.rbc.chunk_max_bytes,
        actor.epoch_for_height(height),
    )
    .expect("session");
    assert_eq!(session.total_chunks(), 1, "test expects a single RBC chunk");
    session.ingest_chunk(0, payload_bytes, None);
    session.test_set_delivered(true);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert((block_hash, height, view), session);

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    let pending = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending block retained");
    assert_eq!(
        pending.validation_status,
        ValidationStatus::Valid,
        "single-validator commit pipeline should validate inline"
    );
    assert!(
        pending.local_commit_vote_emitted(),
        "single-validator commit pipeline should emit a local precommit vote"
    );
    assert!(
        work_rx.try_recv().is_err(),
        "local-only commit topology should not dispatch background validation work"
    );
    let has_vote = actor.vote_log.values().any(|vote| {
        vote.phase == Phase::Commit
            && vote.block_hash == block_hash
            && vote.height == height
            && vote.view == view
    });
    assert!(
        has_vote,
        "single-validator commit pipeline should record a precommit vote"
    );

    harness.shutdown.send();
}

