#[tokio::test(flavor = "current_thread")]
async fn commit_rejection_records_invalid_proposal_view() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let height = 5u64;
    let view = 2u64;
    let parent_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x22; Hash::LENGTH]));
    let block = sample_block(height, view, Some(parent_hash));
    let failed_block = block.clone();
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let pending = PendingBlock::new(block, payload_hash, height, view);
    let lock = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: parent_hash,
        height: height.saturating_sub(1),
        view: view.saturating_sub(1),
        epoch: 0,
    };
    let commit_topology = actor.effective_commit_topology();
    let signature_topology = commit_topology.clone();
    let topology = super::network_topology::Topology::new(signature_topology.clone());
    let min_votes_for_commit = topology.min_votes_for_commit();
    let mut signers = BTreeSet::new();
    for idx in 0..min_votes_for_commit {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let inflight = CommitInFlight {
        id: 12,
        lock,
        block_hash,
        pending,
        commit_topology,
        signature_topology,
        qc_signers: Some(signers),
        commit_qc: None,
        allow_quorum_bypass: false,
        post_commit_qc: None,
        enqueue_time: Instant::now(),
    };
    actor.subsystems.commit.inflight = Some(inflight);

    let (result_tx, result_rx) = mpsc::sync_channel(1);
    actor.subsystems.commit.result_rx = Some(result_rx);

    let outcome = commit::CommitOutcome::Rejected {
        failed_block,
        error: BlockValidationError::EmptyBlock,
        pipeline_events: Vec::new(),
    };
    result_tx
        .send(commit::CommitResult {
            id: 12,
            outcome,
            timings: commit::CommitStageTimings::default(),
        })
        .expect("send commit result");

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    let evidence_view = actor.state.world.consensus_evidence.view();
    let mut recorded_view = None;
    for (_, record) in evidence_view.iter() {
        if let crate::sumeragi::consensus::EvidencePayload::InvalidProposal { proposal, .. } =
            &record.evidence.payload
        {
            recorded_view = Some(proposal.header.view);
        }
    }
    let recorded_view = recorded_view.expect("invalid proposal evidence recorded");
    assert_eq!(recorded_view, view);
    assert_ne!(recorded_view, height);

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_inflight_timeout_triggers_view_change_and_retains_aborted_pending() {
    let mut cfg = test_sumeragi_config();
    cfg.consensus_mode = ConsensusMode::Permissioned;
    cfg.da.enabled = true;
    cfg.persistence.commit_inflight_timeout = Duration::from_millis(10);
    let mut harness = test_actor_harness_with_config(1, cfg, None).await;

    // This test asserts on global view-change cause counters. Hold the test guard for the full
    // duration so other concurrently running unit tests do not record into the same counters.
    let _view_change_guard = super::status::view_change_cause_test_guard();
    super::status::reset_view_change_cause_counters_for_tests();

    let height = 1;
    let view = 0u64;
    let block = sample_block(height, view, None);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let pending = PendingBlock::new(block, payload_hash, height, view);
    let lock = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        height,
        view,
        epoch: 0,
    };
    let commit_topology = harness.actor.effective_commit_topology();
    let signature_topology = commit_topology.clone();
    let inflight = CommitInFlight {
        id: 17,
        lock,
        block_hash,
        pending,
        commit_topology,
        signature_topology,
        qc_signers: None,
        commit_qc: None,
        allow_quorum_bypass: false,
        post_commit_qc: None,
        enqueue_time: Instant::now() - Duration::from_millis(50),
    };
    harness.actor.subsystems.commit.inflight = Some(inflight);
    harness
        .actor
        .subsystems
        .propose
        .proposals_seen
        .insert((height, view));

    harness
        .actor
        .process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    assert!(harness.actor.subsystems.commit.inflight.is_none());
    let pending = harness
        .actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("aborted pending should remain available after timeout");
    assert!(pending.aborted, "pending payload should be marked aborted");
    assert!(
        !harness
            .actor
            .subsystems
            .propose
            .proposals_seen
            .contains(&(height, view)),
        "timed-out view should be pruned after view change"
    );
    assert_eq!(
        harness.actor.phase_tracker.current_view(height),
        Some(view.saturating_add(1))
    );
    assert_eq!(
        harness.actor.subsystems.propose.forced_view_after_timeout,
        Some((height, view.saturating_add(1)))
    );
    let snapshot = super::status::snapshot().view_change_causes;
    assert_eq!(snapshot.commit_failure_total, 1);
    assert_eq!(snapshot.last_cause.as_deref(), Some("commit_failure"));

    super::status::reset_view_change_cause_counters_for_tests();

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_vote_targets_collectors_or_topology() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let height = 1;
    let block = sample_block(height, 0, None);
    let block_hash = block.hash();
    let parent_hash = block.header().prev_block_hash();
    insert_validated_pending(actor, block.clone());
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let epoch = actor.epoch_for_height(height);

    let _ = harness.background_rx.try_iter().count();

    let emitted = actor.emit_precommit_vote(
        block_hash,
        1,
        0,
        epoch,
        ValidationStatus::Valid,
        &topology,
        parent_hash,
        Some((Hash::new([]), Hash::new([]))),
    );
    assert!(emitted, "expected local commit vote to be emitted");

    let signature_topology =
        super::topology_for_view(&topology, 1, 0, actor.mode_tag(), actor.npos_prf_seed());
    let (collectors_k, redundant_r) = on_chain_permissioned_collector_params(actor);
    let collectors = super::collectors::deterministic_collectors(
        &signature_topology,
        ConsensusMode::Permissioned,
        collectors_k,
        None,
        1,
        0,
    );
    let limit = usize::from(redundant_r.max(1));
    let mut expected_targets: Vec<_> = if collectors.is_empty() {
        signature_topology.as_ref().to_vec()
    } else {
        collectors.into_iter().take(limit).collect()
    };
    let local_peer_id = actor.common_config.peer.id().clone();
    expected_targets.retain(|peer| peer != &local_peer_id);
    let fallback_to_topology = expected_targets.is_empty();
    if fallback_to_topology {
        expected_targets = signature_topology.as_ref().to_vec();
        expected_targets.retain(|peer| peer != &local_peer_id);
    } else {
        let parallel = actor.config.collectors.parallel_topology_fanout;
        if parallel > 0 {
            let mut parallel_targets: Vec<_> = signature_topology
                .topology_fanout_from_tail(parallel)
                .into_iter()
                .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
                .collect();
            parallel_targets.retain(|peer| peer != &local_peer_id);
            for peer in parallel_targets {
                if !expected_targets.contains(&peer) {
                    expected_targets.push(peer);
                }
            }
        }
        let remote_floor = usize::from(actor.subsystems.propose.collector_redundant_limit.max(1))
            .min(signature_topology.as_ref().len().saturating_sub(1));
        if expected_targets.len() < remote_floor {
            for peer in signature_topology.as_ref() {
                if peer == &local_peer_id || expected_targets.contains(peer) {
                    continue;
                }
                expected_targets.push(peer.clone());
                if expected_targets.len() >= remote_floor {
                    break;
                }
            }
        }
    }
    let expected_set: BTreeSet<_> = expected_targets.into_iter().collect();

    let actual_targets: BTreeSet<_> = harness
        .background_rx
        .try_iter()
        .filter_map(|post| match post {
            BackgroundPost::Post { peer, msg, .. }
                if matches!(msg.as_ref(), BlockMessage::QcVote(_)) =>
            {
                Some(peer)
            }
            _ => None,
        })
        .collect();

    assert_eq!(
        actual_targets, expected_set,
        "commit votes should target deterministic collectors or topology fallback"
    );

    harness.shutdown.send();
}

