#[tokio::test(flavor = "current_thread")]
async fn commit_quorum_timeout_uses_npos_commit_floor() {
    use iroha_data_model::parameter::system::SumeragiNposParameters;

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut block = state.world.block();
        let params = block.parameters.get_mut();
        params.sumeragi.block_time_ms = 9_000;
        params.sumeragi.commit_time_ms = 9_000;
        let npos_params = SumeragiNposParameters::default();
        params.custom.insert(
            SumeragiNposParameters::parameter_id(),
            npos_params.into_custom_parameter(),
        );
        block.commit();
    }

    let view = actor.state.view();
    let block_time = crate::sumeragi::resolve_npos_block_time(&view);
    let commit_time = actor.commit_timeout_for_mode(&view, ConsensusMode::Npos);
    let stage_commit = crate::sumeragi::resolve_npos_timeouts(&view, &actor.config.npos).commit;
    let canonical_commit = view.world.parameters().sumeragi().effective_commit_time();
    assert_eq!(commit_time, canonical_commit);
    assert!(stage_commit < canonical_commit);
    let da_enabled = view.world.parameters().sumeragi().da_enabled();
    drop(view);

    let expected = super::commit_quorum_timeout_from_durations(
        block_time,
        commit_time,
        da_enabled,
        actor.config.da.quorum_timeout_multiplier.max(1),
    );
    assert_eq!(actor.commit_quorum_timeout(), expected);

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn precommit_vote_skips_payload_fallback_across_rapid_votes_without_roster() {
    let mut harness = test_actor_harness(4).await;

    let block = sample_block(1, 0, None);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    harness
        .actor
        .pending
        .pending_blocks
        .insert(block_hash, PendingBlock::new(block, payload_hash, 1, 0));

    let _ = harness.background_rx.try_iter().count();

    let topology =
        super::network_topology::Topology::new(harness.actor.effective_commit_topology());
    let view = 0;
    let rotated = super::topology_for_view(&topology, 1, view, super::PERMISSIONED_TAG, None);
    let local_peer = harness.actor.common_config.peer.id().clone();
    let signer_idx = rotated
        .as_ref()
        .iter()
        .position(|peer| peer == &local_peer)
        .expect("local peer in topology");

    let chain = harness.actor.common_config.chain.clone();
    let keypair = harness.actor.common_config.key_pair.clone();

    let mut vote_a = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        height: 1,
        view,
        epoch: 0,
        highest_qc: None,
        signer: u32::try_from(signer_idx).expect("signer index fits u32"),
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(
        &mut vote_a,
        &chain,
        &topology,
        std::slice::from_ref(&keypair),
    );
    harness.actor.handle_vote(vote_a);

    let mut vote_b = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        height: 1,
        view,
        epoch: 1,
        highest_qc: None,
        signer: u32::try_from(signer_idx).expect("signer index fits u32"),
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(
        &mut vote_b,
        &chain,
        &topology,
        std::slice::from_ref(&keypair),
    );
    harness.actor.handle_vote(vote_b);

    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    let fallback_posts = posts
        .iter()
        .filter(|post| {
            matches!(
                post,
                BackgroundPost::Post { msg, .. }
                    if matches!(
                        msg.as_ref(),
                        BlockMessage::BlockCreated(created) if created.block.hash() == block_hash
                    )
            )
        })
        .count();
    assert_eq!(
        fallback_posts, 0,
        "rapid precommit votes should not trigger payload fallback without verifiable roster evidence"
    );

    harness.shutdown.send();
}

