#[tokio::test(flavor = "current_thread")]
async fn known_block_commit_qc_replay_targets_snapshot_roster() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let _genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let parent_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::new(
        b"precommit_vote_block_sync_update_targets_snapshot_roster",
    ));
    let block = sample_block(2, 0, Some(parent_hash));
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block.clone(), payload_hash, 2, 0),
    );

    let mut snapshot_roster = actor.effective_commit_topology();
    let local_peer = actor.common_config.peer.id().clone();
    let removed_peer = snapshot_roster
        .iter()
        .find(|peer| *peer != &local_peer)
        .cloned()
        .expect("non-local roster entry");
    snapshot_roster.retain(|peer| peer != &removed_peer);

    let topology = super::network_topology::Topology::new(snapshot_roster.clone());
    let signers: BTreeSet<ValidatorIndex> = (0..snapshot_roster.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, snapshot_roster.len());
    let view_idx = block.header().view_change_index();
    let commit_qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        2,
        view_idx,
        0,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        block_hash,
        2,
        view_idx,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        2,
        view_idx,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        snapshot_roster.clone(),
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let mut journal = actor.state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
    }
    actor.qc_cache.insert(
        (
            Phase::Commit,
            block_hash,
            2,
            view_idx,
            actor.epoch_for_height(2),
        ),
        qc_with_bitmap(
            &actor.common_config.chain,
            block_hash,
            2,
            view_idx,
            actor.epoch_for_height(2),
            super::build_signers_bitmap(
                &(0..snapshot_roster.len())
                    .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
                    .collect(),
                snapshot_roster.len(),
            ),
            Phase::Commit,
            &topology,
            &harness.key_pairs,
        ),
    );

    let _ = harness.background_rx.try_iter().count();
    assert!(
        actor.maybe_replay_known_block_commit_evidence(
            block_hash,
            2,
            view_idx,
            &snapshot_roster,
            "test_snapshot_roster",
        ),
        "expected cached commit QC replay to target snapshot roster"
    );

    let expected_set: BTreeSet<_> = snapshot_roster
        .iter()
        .filter(|peer| *peer != &local_peer)
        .cloned()
        .collect();

    let actual_targets: BTreeSet<_> = harness
        .background_rx
        .try_iter()
        .filter_map(|post| match post {
            BackgroundPost::Post { peer, msg, .. }
                if matches!(
                    msg.as_ref(),
                    BlockMessage::Qc(qc) if qc.subject_block_hash == block_hash
                ) =>
            {
                Some(peer)
            }
            _ => None,
        })
        .collect();

    assert_eq!(
        actual_targets, expected_set,
        "known-block commit QC replay should target the snapshot roster"
    );

    harness.shutdown.send();
}

#[test]
fn block_sync_update_targets_cover_full_roster_when_limit_allows() {
    let peers: Vec<_> = (0..4)
        .map(|_| {
            PeerId::new(
                KeyPair::random_with_algorithm(Algorithm::BlsNormal)
                    .public_key()
                    .clone(),
            )
        })
        .collect();
    let local_peer = peers[0].clone();
    let registered_peers = peers.clone();
    let online_peers = vec![peers[1].clone()];
    let gossip_limit = peers.len().saturating_sub(1);
    let seed = [7_u8; 32];

    let targets = Actor::block_sync_update_targets_for_peers(
        &local_peer,
        gossip_limit,
        &peers,
        &registered_peers,
        &[],
        &online_peers,
        &seed,
    );

    let expected: BTreeSet<_> = online_peers.into_iter().collect();
    let actual: BTreeSet<_> = targets.into_iter().collect();
    assert_eq!(
        actual, expected,
        "gossip targets should prefer online roster peers when available"
    );
}

#[tokio::test(flavor = "current_thread")]
async fn precommit_vote_targets_collectors_without_broadcast() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let height = 1;
    let block = sample_block(height, 0, None);
    let block_hash = block.hash();
    insert_validated_pending(actor, block.clone());
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let epoch = actor.epoch_for_height(height);

    let _ = harness.background_rx.try_iter().count();

    let emitted = actor.emit_precommit_vote(
        block_hash,
        1,
        0,
        epoch,
        ValidationStatus::Valid,
        &topology,
        block.header().prev_block_hash(),
        Some((Hash::new([]), Hash::new([]))),
    );
    assert!(emitted, "expected local precommit vote to be emitted");

    let signature_topology =
        super::topology_for_view(&topology, 1, 0, actor.mode_tag(), actor.npos_prf_seed());
    let (collectors_k, redundant_r) = on_chain_permissioned_collector_params(actor);
    let collectors = super::collectors::deterministic_collectors(
        &signature_topology,
        ConsensusMode::Permissioned,
        collectors_k,
        None,
        1,
        0,
    );
    let limit = usize::from(redundant_r.max(1));
    let mut expected_targets: Vec<_> = if collectors.is_empty() {
        signature_topology.as_ref().to_vec()
    } else {
        collectors.into_iter().take(limit).collect()
    };
    let local_peer_id = actor.common_config.peer.id().clone();
    expected_targets.retain(|peer| peer != &local_peer_id);
    let fallback_to_topology = expected_targets.is_empty();
    if fallback_to_topology {
        expected_targets = signature_topology.as_ref().to_vec();
        expected_targets.retain(|peer| peer != &local_peer_id);
    } else {
        let parallel = actor.config.collectors.parallel_topology_fanout;
        if parallel > 0 {
            let mut parallel_targets: Vec<_> = signature_topology
                .topology_fanout_from_tail(parallel)
                .into_iter()
                .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
                .collect();
            parallel_targets.retain(|peer| peer != &local_peer_id);
            for peer in parallel_targets {
                if !expected_targets.contains(&peer) {
                    expected_targets.push(peer);
                }
            }
        }
    }
    let expected_set: BTreeSet<_> = expected_targets.into_iter().collect();

    let mut actual_targets: Vec<_> = actor
        .subsystems
        .propose
        .collectors_contacted
        .iter()
        .cloned()
        .collect();
    actual_targets.retain(|peer| peer != &local_peer_id);
    let fallback_to_topology = actual_targets.is_empty();
    if fallback_to_topology {
        actual_targets = signature_topology.as_ref().to_vec();
        actual_targets.retain(|peer| peer != &local_peer_id);
    } else {
        let parallel = actor.config.collectors.parallel_topology_fanout;
        if parallel > 0 {
            let mut parallel_targets: Vec<_> = signature_topology
                .topology_fanout_from_tail(parallel)
                .into_iter()
                .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
                .collect();
            parallel_targets.retain(|peer| peer != &local_peer_id);
            for peer in parallel_targets {
                if !actual_targets.contains(&peer) {
                    actual_targets.push(peer);
                }
            }
        }
    }
    let actual_targets: BTreeSet<_> = actual_targets.into_iter().collect();

    assert_eq!(
        actual_targets, expected_set,
        "precommit votes should target deterministic collectors or topology fallback"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rebroadcast_precommit_votes_keep_collectors_when_below_quorum() {
    let _history_guard = crate::sumeragi::status::commit_history_test_guard();
    crate::sumeragi::status::reset_precommit_signer_history_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.relay_backpressure.disable_for_tests();
    let height = 1;
    // Keep the block hash unique per harness to avoid pulling roster artifacts from
    // concurrent tests that use deterministic sample hashes.
    let block = sample_block(
        height,
        0,
        Some(HashOf::from_untyped_unchecked(Hash::new(
            actor.common_config.peer.id().to_string().as_bytes(),
        ))),
    );
    let block_hash = block.hash();
    insert_validated_pending(actor, block.clone());
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let epoch = actor.epoch_for_height(height);

    assert!(actor.emit_precommit_vote(
        block_hash,
        1,
        0,
        epoch,
        ValidationStatus::Valid,
        &topology,
        block.header().prev_block_hash(),
        Some((Hash::new([]), Hash::new([]))),
    ));
    let _ = harness.background_rx.try_iter().count();

    let signature_topology =
        super::topology_for_view(&topology, 1, 0, actor.mode_tag(), actor.npos_prf_seed());
    let local_peer_id = actor.common_config.peer.id().clone();
    let planned_collectors: Vec<_> = signature_topology
        .as_ref()
        .iter()
        .filter(|peer| *peer != &local_peer_id)
        .take(2)
        .cloned()
        .collect();
    assert_eq!(
        planned_collectors.len(),
        2,
        "expected enough remote peers for below-quorum collectors"
    );
    actor.subsystems.propose.collector_plan = Some(super::collectors::CollectorPlan::new(
        planned_collectors.clone(),
    ));
    actor.subsystems.propose.collector_plan_subject = Some((1, 0));
    actor.subsystems.propose.collector_plan_targets = planned_collectors.clone();
    actor.subsystems.propose.collectors_contacted.clear();
    actor
        .subsystems
        .propose
        .collectors_contacted
        .extend(planned_collectors.iter().cloned());

    let _ = actor.rebroadcast_block_votes(Phase::Commit, block_hash, 1, 0, false);

    let mut expected_targets = planned_collectors;
    let parallel = actor.config.collectors.parallel_topology_fanout;
    if parallel > 0 {
        let mut parallel_targets: Vec<_> = signature_topology
            .topology_fanout_from_tail(parallel)
            .into_iter()
            .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
            .collect();
        parallel_targets.retain(|peer| peer != &local_peer_id);
        for peer in parallel_targets {
            if !expected_targets.contains(&peer) {
                expected_targets.push(peer);
            }
        }
    }
    let expected_set: BTreeSet<_> = expected_targets.into_iter().collect();

    let actual_targets: BTreeSet<_> = harness
        .background_rx
        .try_iter()
        .filter_map(|post| match post {
            BackgroundPost::Post { peer, msg, .. }
                if matches!(msg.as_ref(), BlockMessage::QcVote(_)) =>
            {
                Some(peer)
            }
            _ => None,
        })
        .collect();

    assert_eq!(
        actual_targets, expected_set,
        "precommit vote rebroadcasts should retain collector targets even when below quorum"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn exec_witness_targets_collectors_even_when_redundant_r_below_quorum() {
    use iroha_data_model::parameter::system::{Parameter, SumeragiParameter};

    let mut harness = test_actor_harness(7).await;
    let actor = &mut harness.actor;

    {
        let mut block = actor.state.world.block();
        let params = block.parameters.get_mut();
        params.set_parameter(Parameter::Sumeragi(SumeragiParameter::RedundantSendR(1)));
        block.commit();
    }

    let height = 1u64;
    let view = 0u64;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE3; Hash::LENGTH]));
    let witness = ExecWitness {
        reads: Vec::new(),
        writes: Vec::new(),
        fastpq_transcripts: Vec::new(),
        fastpq_batches: Vec::new(),
    };

    let _ = harness.background_rx.try_iter().count();
    actor.emit_exec_artifacts(block_hash, height, view, witness);

    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let topology_peers = actor.roster_for_vote_with_mode(block_hash, height, view, consensus_mode);
    let topology = super::network_topology::Topology::new(topology_peers);
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let (collectors_k, redundant_r) = actor.collector_plan_params_for_mode(consensus_mode);
    let mut expected_targets = if collectors_k == 0 {
        Vec::new()
    } else {
        super::collectors::deterministic_collectors(
            &signature_topology,
            consensus_mode,
            collectors_k,
            prf_seed,
            height,
            view,
        )
    };
    if !expected_targets.is_empty() {
        let limit = usize::from(
            signature_topology
                .redundant_send_r_floor(redundant_r)
                .max(1),
        );
        expected_targets.truncate(limit);
    }
    let local_peer_id = actor.common_config.peer.id().clone();
    expected_targets.retain(|peer| peer != &local_peer_id);
    if expected_targets.is_empty() {
        expected_targets = signature_topology.as_ref().to_vec();
        expected_targets.retain(|peer| peer != &local_peer_id);
    }
    let expected_set: BTreeSet<_> = expected_targets.into_iter().collect();

    let actual_targets: BTreeSet<_> = harness
        .background_rx
        .try_iter()
        .filter_map(|post| match post {
            BackgroundPost::Post { peer, msg, .. }
                if matches!(msg.as_ref(), BlockMessage::ExecWitness(_)) =>
            {
                Some(peer)
            }
            _ => None,
        })
        .collect();

    assert_eq!(
        actual_targets, expected_set,
        "exec witness should target deterministic collectors even when redundant_r is below quorum"
    );
    assert!(
        actual_targets.len() < signature_topology.as_ref().len().saturating_sub(1),
        "exec witness targets should not fall back to the full topology"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rebroadcast_block_votes_targets_snapshot_roster() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.relay_backpressure.disable_for_tests();
    let block = sample_block(1, 0, None);
    let block_hash = block.hash();
    let height = 1;
    let view = block.header().view_change_index();
    let epoch = 0;

    let mut snapshot_roster = actor.effective_commit_topology();
    let local_peer = actor.common_config.peer.id().clone();
    let removed_peer = snapshot_roster
        .iter()
        .find(|peer| *peer != &local_peer)
        .cloned()
        .expect("non-local roster entry");
    snapshot_roster.retain(|peer| peer != &removed_peer);

    let topology = super::network_topology::Topology::new(snapshot_roster.clone());
    let signers: BTreeSet<ValidatorIndex> = (0..snapshot_roster.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, snapshot_roster.len());
    let commit_qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        block_hash,
        height,
        view,
        epoch,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        snapshot_roster.clone(),
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let mut journal = actor.state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
    }

    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_canonical_signer(
        &mut vote,
        &actor.common_config.chain,
        &topology,
        &harness.key_pairs,
    );
    actor.vote_log.insert(
        (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
        vote,
    );

    let _ = harness.background_rx.try_iter().count();
    let _ = actor.rebroadcast_block_votes(Phase::Commit, block_hash, height, view, false);

    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let mut expected_targets: Vec<_> = actor
        .subsystems
        .propose
        .collectors_contacted
        .iter()
        .cloned()
        .collect();
    let mut fallback_to_topology = false;
    expected_targets.retain(|peer| peer != &local_peer);
    if expected_targets.is_empty() {
        fallback_to_topology = true;
        expected_targets = signature_topology.as_ref().to_vec();
        expected_targets.retain(|peer| peer != &local_peer);
    }
    if !fallback_to_topology {
        let parallel = actor.config.collectors.parallel_topology_fanout;
        if parallel > 0 {
            let mut parallel_targets: Vec<_> = signature_topology
                .topology_fanout_from_tail(parallel)
                .into_iter()
                .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
                .collect();
            parallel_targets.retain(|peer| peer != &local_peer);
            for peer in parallel_targets {
                if expected_targets.iter().all(|existing| existing != &peer) {
                    expected_targets.push(peer);
                }
            }
        }
        let remote_floor = usize::from(actor.subsystems.propose.collector_redundant_limit.max(1))
            .min(signature_topology.as_ref().len().saturating_sub(1));
        if expected_targets.len() < remote_floor {
            for peer in signature_topology.as_ref() {
                if peer == &local_peer || expected_targets.contains(peer) {
                    continue;
                }
                expected_targets.push(peer.clone());
                if expected_targets.len() >= remote_floor {
                    break;
                }
            }
        }
    }
    let expected_set: BTreeSet<_> = expected_targets.into_iter().collect();

    let actual_targets: BTreeSet<_> = harness
        .background_rx
        .try_iter()
        .filter_map(|post| match post {
            BackgroundPost::Post { peer, msg, .. }
                if matches!(msg.as_ref(), BlockMessage::QcVote(_)) =>
            {
                Some(peer)
            }
            _ => None,
        })
        .collect();

    assert_eq!(
        actual_targets, expected_set,
        "rebroadcasted votes should target the snapshot roster"
    );

    harness.shutdown.send();
}

