#[tokio::test(flavor = "current_thread")]
async fn rebuild_qcs_from_cached_votes_uses_snapshot_roster() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let parent = actor.state.view().latest_block_hash();
    let block = sample_block(2, 0, parent);
    let block_hash = block.hash();
    let height = 2;
    let view = block.header().view_change_index();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    let mut snapshot_roster = actor.effective_commit_topology();
    let local_peer = actor.common_config.peer.id().clone();
    let removed_peer = snapshot_roster
        .iter()
        .find(|peer| *peer != &local_peer)
        .cloned()
        .expect("non-local roster entry");
    snapshot_roster.retain(|peer| peer != &removed_peer);

    let topology = super::network_topology::Topology::new(snapshot_roster.clone());
    let signers: BTreeSet<ValidatorIndex> = (0..snapshot_roster.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, snapshot_roster.len());
    let epoch = actor.epoch_for_height(height);
    let commit_qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        block_hash,
        height,
        view,
        epoch,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        snapshot_roster.clone(),
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let mut journal = actor.state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
    }

    let commit_topology =
        actor.roster_for_vote_with_mode(block_hash, height, view, ConsensusMode::Permissioned);
    assert_eq!(
        commit_topology, snapshot_roster,
        "expected BlockCreated to rebuild QC using the snapshot roster"
    );

    for signer in 0..snapshot_roster.len() {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: None,
            signer: u32::try_from(signer).expect("signer fits u32"),
            bls_sig: Vec::new(),
        };
        sign_vote_for_canonical_signer(
            &mut vote,
            &actor.common_config.chain,
            &topology,
            &harness.key_pairs,
        );
        actor.vote_log.insert(
            (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
            vote,
        );
    }

    let signature_topology = super::topology_for_view(
        &super::network_topology::Topology::new(commit_topology.clone()),
        height,
        view,
        super::PERMISSIONED_TAG,
        Some(prf_seed_for_chain(&actor.common_config.chain)),
    );
    let valid_signers = actor.qc_signers_for_votes(
        Phase::Commit,
        block_hash,
        height,
        view,
        epoch,
        &signature_topology,
    );
    assert_eq!(
        valid_signers.len(),
        snapshot_roster.len(),
        "expected all cached votes to validate before QC rebuild"
    );

    actor.rebuild_qcs_from_cached_votes(&actor.effective_commit_topology());

    let key = (Phase::Commit, block_hash, height, view, epoch);
    let qc = actor
        .qc_cache
        .get(&key)
        .expect("QC rebuilt from cached votes");
    assert_eq!(
        qc.validator_set, snapshot_roster,
        "QC rebuild should honor the snapshot roster"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rebuild_qcs_from_cached_votes_does_not_quarantine_uncommitted_sidecar_mismatch() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let parent = actor.state.view().latest_block_hash();
    let block = sample_block(2, 0, parent);
    let block_hash = block.hash();
    let height = 2;
    let view = block.header().view_change_index();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    let sidecar_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x7E; Hash::LENGTH]));
    assert_ne!(
        sidecar_hash, block_hash,
        "test requires sidecar hash to differ from rebuild candidate hash"
    );
    actor
        .kura
        .write_roster_metadata(&crate::kura::RosterSidecar::new(
            height,
            sidecar_hash,
            None,
            None,
            None,
        ));

    let missing_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x7F; Hash::LENGTH]));
    assert!(
        !actor.block_payload_available_locally(missing_hash),
        "test requires unresolved missing payload hash"
    );
    let now = Instant::now();
    actor.pending.missing_block_requests.insert(
        missing_hash,
        super::MissingBlockRequest {
            height,
            view,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window: Duration::from_millis(1),
            view_change_window: Some(Duration::from_millis(2)),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let epoch = actor.epoch_for_height(height);
    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_canonical_signer(
        &mut vote,
        &actor.common_config.chain,
        &topology,
        &harness.key_pairs,
    );
    actor.vote_log.insert(
        (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
        vote,
    );

    actor.rebuild_qcs_from_cached_votes(&actor.effective_commit_topology());

    assert!(
        !actor.sidecar_quarantined_for_height(height),
        "qc rebuild replay must not quarantine uncommitted sidecar mismatch branches"
    );
    assert!(
        actor.sidecar_mismatch_recovery.get(&height).is_none(),
        "qc rebuild replay must not record fail-closed sidecar mismatch state"
    );

    harness.shutdown.send();
}

