#[tokio::test(flavor = "current_thread")]
async fn npos_qc_uses_active_validator_roster_for_stake_quorum() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let block_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let block = actor
        .kura
        .get_block(NonZeroUsize::new(1).expect("genesis height"))
        .expect("genesis block");
    let height = block.header().height().get();
    let view = block.header().view_change_index();
    let epoch = actor.epoch_for_height(height);

    let commit_topology = actor.effective_commit_topology();
    assert!(commit_topology.len() >= 4, "test requires 4 trusted peers");

    {
        let mut block = actor.state.world.public_lane_validators.block();
        let existing: Vec<_> = block.iter().map(|(key, _)| key.clone()).collect();
        for key in existing {
            block.remove(key);
        }
        for (idx, peer) in commit_topology.iter().take(2).enumerate() {
            let account_id = AccountId::new(peer.public_key().clone());
            let lane_id = LaneId::new(u32::try_from(idx + 1).expect("lane index fits u32"));
            let record = PublicLaneValidatorRecord {
                lane_id,
                validator: account_id.clone(),
                stake_account: account_id.clone(),
                total_stake: Numeric::new(1, 0),
                self_stake: Numeric::new(1, 0),
                metadata: iroha_data_model::metadata::Metadata::default(),
                status: PublicLaneValidatorStatus::Active,
                activation_epoch: None,
                activation_height: None,
                last_reward_epoch: None,
            };
            block.insert((record.lane_id, account_id), record);
        }
        block.commit();
    }

    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    assert!(
        matches!(consensus_mode, ConsensusMode::Npos),
        "test expects NPoS consensus"
    );
    let active_topology = actor.effective_commit_topology();
    assert_eq!(
        active_topology.len(),
        2,
        "active topology should be constrained to active validators"
    );
    let topology = super::network_topology::Topology::new(active_topology.clone());
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let mut signer_indices = Vec::new();
    for (idx, _) in signature_topology.as_ref().iter().enumerate() {
        signer_indices.push(u32::try_from(idx).expect("signer index fits u32"));
    }
    assert!(
        signer_indices.len() >= 2,
        "expected active validators in rotated topology"
    );

    let chain = actor.common_config.chain.clone();
    for signer in signer_indices.into_iter().take(2) {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: None,
            signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_view_with_seed(
            &mut vote,
            &chain,
            &topology,
            &harness.key_pairs,
            mode_tag,
            prf_seed,
        );
        actor
            .vote_log
            .insert((Phase::Commit, height, view, epoch, signer), vote);
    }

    let signers = actor.qc_signers_for_votes(
        Phase::Commit,
        block_hash,
        height,
        view,
        epoch,
        &signature_topology,
    );
    assert_eq!(signers.len(), 2, "expected exactly two active NPoS signers");
    let signer_peers = super::signer_peers_for_topology(&signers, &signature_topology)
        .expect("vote signers should map to peers");
    assert!(
        super::stake_snapshot::stake_quorum_reached_for_world(
            &actor.state.world_view(),
            &active_topology,
            &signer_peers,
        )
        .expect("stake quorum check should evaluate"),
        "active validators should satisfy NPoS stake quorum"
    );

    actor.try_form_qc_from_votes(Phase::Commit, block_hash, height, view, epoch, &topology);

    let key = (Phase::Commit, block_hash, height, view, epoch);
    assert!(
        actor.qc_cache.contains_key(&key) || actor.deferred_qcs.contains_key(&key),
        "QC should aggregate or defer using active validator roster for stake quorum"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn npos_qc_uses_pending_activation_roster_for_stake_quorum() {
    let phase = Phase::Prepare;
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let parent_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = u64::try_from(actor.state.committed_height())
        .unwrap_or(0)
        .saturating_add(1);
    let view = 0;
    let epoch = actor.epoch_for_height(height);
    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    assert!(
        matches!(consensus_mode, ConsensusMode::Npos),
        "test expects NPoS consensus"
    );
    let commit_topology = actor.effective_commit_topology();
    assert!(commit_topology.len() >= 4, "test requires 4 trusted peers");
    let topology = super::network_topology::Topology::new(commit_topology.clone());
    let pending_roster = super::roster::canonicalize_roster_for_mode(
        vec![commit_topology[0].clone(), commit_topology[1].clone()],
        consensus_mode,
    );
    actor.pending_roster_activation = Some((height, pending_roster.clone()));

    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let block_signer_peer = pending_roster
        .first()
        .expect("pending activation roster must have a signer");
    let block_signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == block_signer_peer.public_key())
        .expect("block signer keypair exists in harness");
    let block_signer_idx = signature_topology
        .position(block_signer_kp.public_key())
        .expect("block signer index in signature topology");
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.common_config.chain,
        height,
        view,
        Some(parent_hash),
        block_signer_kp,
        u64::try_from(block_signer_idx).expect("signer index fits u64"),
    );
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );
    assert_eq!(
        actor.roster_for_vote_with_mode(block_hash, height, view, consensus_mode),
        pending_roster,
        "commit vote roster should switch to pending activation at next height",
    );

    let pending_set: BTreeSet<_> = pending_roster.iter().cloned().collect();
    let mut signer_indices = Vec::new();
    for (idx, peer) in signature_topology.as_ref().iter().enumerate() {
        if pending_set.contains(peer) {
            signer_indices.push(u32::try_from(idx).expect("signer index fits u32"));
        }
    }
    assert_eq!(
        signer_indices.len(),
        2,
        "pending activation validators should map into signature topology"
    );

    let chain = actor.common_config.chain.clone();
    for signer in signer_indices {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: None,
            signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_view_with_seed(
            &mut vote,
            &chain,
            &topology,
            &harness.key_pairs,
            mode_tag,
            prf_seed,
        );
        actor
            .vote_log
            .insert((phase, height, view, epoch, signer), vote);
    }

    let signers =
        actor.qc_signers_for_votes(phase, block_hash, height, view, epoch, &signature_topology);
    let signer_peers = super::signer_peers_for_topology(&signers, &signature_topology)
        .expect("vote signers should map to peers");
    let pending_set: BTreeSet<_> = pending_roster.iter().cloned().collect();
    assert_eq!(
        signer_peers, pending_set,
        "cached votes should come from pending activation validators"
    );
    assert!(
        super::stake_snapshot::stake_quorum_reached_for_world(
            &actor.state.world_view(),
            &pending_roster,
            &signer_peers,
        )
        .expect("stake quorum check should evaluate"),
        "pending activation validators should satisfy NPoS stake quorum"
    );

    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let observed_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let observed_roster = super::roster::canonicalize_roster_for_mode(
        actor.roster_for_vote_with_mode(block_hash, height, view, consensus_mode),
        consensus_mode,
    );
    let observed_signer_peers = super::signer_peers_for_topology(&signers, &observed_topology)
        .expect("vote signers should map during post-vote check");
    assert!(
        super::stake_snapshot::stake_quorum_reached_for_world(
            &actor.state.world_view(),
            &observed_roster,
            &observed_signer_peers,
        )
        .expect("observed stake quorum should evaluate"),
        "stake quorum should hold for the roster used during QC aggregation",
    );

    actor.locked_qc = None;
    actor.try_form_qc_from_votes(phase, block_hash, height, view, epoch, &topology);

    let key = (phase, block_hash, height, view, epoch);
    let qc = actor.qc_cache.get(&key).expect(
        "QC should aggregate when signers satisfy stake quorum over pending activation roster",
    );
    assert_eq!(
        qc.validator_set, pending_roster,
        "aggregated QC must encode the pending activation roster used for voting"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn quorum_retransmit_targets_map_view_signers_to_canonical_peers() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let canonical_roster = actor.effective_commit_topology();
    assert_eq!(canonical_roster.len(), 4, "test requires a 4-peer topology");
    let topology = super::network_topology::Topology::new(canonical_roster.clone());
    let local_peer = actor.common_config.peer.id().clone();
    let height = u64::try_from(actor.state.committed_height())
        .unwrap_or(0)
        .saturating_add(1);
    let epoch = actor.epoch_for_height(height);
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA5; Hash::LENGTH]));
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);

    let mut selected = None;
    for view in 0..64_u64 {
        let signature_topology =
            super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
        for (canonical_idx, peer) in canonical_roster.iter().enumerate() {
            if peer == &local_peer {
                continue;
            }
            let signer_idx = signature_topology
                .as_ref()
                .iter()
                .position(|candidate| candidate == peer)
                .expect("canonical peer must exist in view-aligned topology");
            if signer_idx != canonical_idx {
                selected = Some((view, peer.clone(), signer_idx, signature_topology));
                break;
            }
        }
        if selected.is_some() {
            break;
        }
    }
    let (view, missing_peer, missing_signer_idx, signature_topology) = selected
        .expect("test requires a view where signer indices differ from canonical roster indices");

    for (signer_idx, _) in signature_topology.as_ref().iter().enumerate() {
        if signer_idx == missing_signer_idx {
            continue;
        }
        let signer = u32::try_from(signer_idx).expect("signer index fits u32");
        actor.vote_log.insert(
            (Phase::Commit, height, view, epoch, signer),
            crate::sumeragi::consensus::Vote {
                phase: Phase::Commit,
                block_hash,
                parent_state_root: zero_state_root(),
                post_state_root: zero_state_root(),
                height,
                view,
                epoch,
                highest_qc: None,
                signer,
                bls_sig: Vec::new(),
            },
        );
    }

    let vote_count = signature_topology.as_ref().len().saturating_sub(1);
    let min_votes_for_commit = topology.min_votes_for_commit();
    assert!(
        vote_count >= min_votes_for_commit,
        "test expects numeric commit quorum without stake quorum"
    );

    let targets = actor.quorum_retransmit_targets_for_missing_votes(
        block_hash,
        height,
        view,
        &canonical_roster,
        min_votes_for_commit,
        vote_count,
    );
    assert_eq!(
        targets,
        vec![missing_peer.clone()],
        "retransmit targets must include the canonical peer missing from the view-aligned signer set"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_vote_defers_until_roster_available() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(0);
    let height = committed_height.saturating_add(2);
    let view = 0;
    let parent_hash = HashOf::from_untyped_unchecked(Hash::prehashed([0x44; 32]));
    let block = sample_block(height, view, Some(parent_hash));
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let chain = actor.common_config.chain.clone();
    let epoch = actor.epoch_for_height(height);
    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(&mut vote, &chain, &topology, &harness.key_pairs);

    let before = actor.vote_log.len();
    actor.handle_vote(vote);
    assert_eq!(
        actor.vote_log.len(),
        before,
        "vote should be deferred until roster is available"
    );
    assert!(
        actor.deferred_votes.contains_key(&block_hash),
        "vote should be retained for roster resolution"
    );

    actor.cache_vote_roster(block_hash, height, view, topology.as_ref().to_vec());

    assert!(
        actor
            .vote_log
            .contains_key(&(Phase::Commit, height, view, epoch, 0)),
        "deferred vote should be replayed once roster is cached"
    );
    assert!(
        !actor.deferred_votes.contains_key(&block_hash),
        "deferred votes should be cleared after replay"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn deferred_votes_replay_after_commit_roster_history_arrives() {
    use crate::sumeragi::status;

    let _history_guard = status::commit_history_test_guard();
    status::reset_commit_certs_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let hash_height1 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x21; Hash::LENGTH]));
    let hash_height2 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x22; Hash::LENGTH]));
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(hash_height1);
        hashes.push(hash_height2);
        hashes.commit_for_tests();
    }

    let active_roster = actor.effective_commit_topology();
    assert!(
        active_roster.len() >= 2,
        "test needs at least two validators"
    );
    let history_roster = active_roster.clone();

    let block_height3 = sample_block(3, 0, Some(hash_height2));
    let hash_height3 = block_height3.hash();
    let block_height4 = sample_block(4, 0, Some(hash_height3));
    let hash_height4 = block_height4.hash();
    let block_height5 = sample_block(5, 0, Some(hash_height4));
    let hash_height5 = block_height5.hash();

    let payload_hash = Hash::prehashed([0xA5; 32]);
    actor.pending.pending_blocks.insert(
        hash_height3,
        PendingBlock::new(block_height3, payload_hash, 3, 0),
    );
    actor.pending.pending_blocks.insert(
        hash_height4,
        PendingBlock::new(block_height4, payload_hash, 4, 0),
    );
    actor.pending.pending_blocks.insert(
        hash_height5,
        PendingBlock::new(block_height5, payload_hash, 5, 0),
    );

    let expected_roster = {
        let mut topo = super::network_topology::Topology::new(history_roster.clone());
        topo.block_committed(history_roster.clone(), hash_height2);
        let roster_height3 = topo.as_ref().to_vec();
        let mut topo = super::network_topology::Topology::new(roster_height3.clone());
        topo.block_committed(roster_height3.clone(), hash_height3);
        let roster_height4 = topo.as_ref().to_vec();
        let mut topo = super::network_topology::Topology::new(roster_height4.clone());
        topo.block_committed(roster_height4, hash_height4);
        topo.as_ref().to_vec()
    };
    assert!(
        !expected_roster.is_empty(),
        "derived roster should be non-empty"
    );

    let topology = super::network_topology::Topology::new(expected_roster.clone());
    let chain = actor.common_config.chain.clone();
    let height = 5u64;
    let view = 0u64;
    let epoch = actor.epoch_for_height(height);
    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: hash_height5,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(&mut vote, &chain, &topology, &harness.key_pairs);

    let before = actor.vote_log.len();
    actor.handle_vote(vote);
    assert_eq!(
        actor.vote_log.len(),
        before,
        "vote should be deferred until roster history is available"
    );
    assert!(
        actor.deferred_votes.contains_key(&hash_height5),
        "deferred vote should be buffered"
    );

    let mut signers = BTreeSet::new();
    for idx in 0..history_roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, history_roster.len());
    let history_topology = super::network_topology::Topology::new(history_roster.clone());
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        hash_height2,
        2,
        0,
        0,
        &signers_bitmap,
        &history_topology,
        &harness.key_pairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: hash_height2,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 2,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&history_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: history_roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };
    status::record_commit_qc(commit_qc);

    let replayed = actor.try_replay_deferred_votes();
    assert!(replayed, "expected deferred votes to replay");
    assert!(
        actor
            .vote_log
            .contains_key(&(Phase::Commit, height, view, epoch, 0)),
        "deferred vote should be recorded after roster resolution"
    );
    assert!(
        !actor.deferred_votes.contains_key(&hash_height5),
        "deferred vote should be cleared after replay"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn deferred_qcs_replay_after_commit_roster_history_arrives() {
    use crate::sumeragi::status;

    let _history_guard = status::commit_history_test_guard();
    status::reset_commit_certs_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let hash_height1 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x41; Hash::LENGTH]));
    let hash_height2 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x42; Hash::LENGTH]));
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(hash_height1);
        hashes.push(hash_height2);
        hashes.commit_for_tests();
    }

    let active_roster = actor.effective_commit_topology();
    assert!(
        active_roster.len() >= 2,
        "test needs at least two validators"
    );
    let mut history_roster = active_roster.clone();
    let rotate_at = super::network_topology::commit_quorum_from_len(history_roster.len())
        .min(history_roster.len());
    if rotate_at > 1 {
        history_roster[..rotate_at].rotate_right(1);
    }

    let block_height3 = sample_block(3, 0, Some(hash_height2));
    let hash_height3 = block_height3.hash();
    let block_height4 = sample_block(4, 0, Some(hash_height3));
    let hash_height4 = block_height4.hash();
    let block_height5 = sample_block(5, 0, Some(hash_height4));
    let hash_height5 = block_height5.hash();

    let payload_hash = Hash::prehashed([0xB5; 32]);
    actor.pending.pending_blocks.insert(
        hash_height3,
        PendingBlock::new(block_height3, payload_hash, 3, 0),
    );
    actor.pending.pending_blocks.insert(
        hash_height4,
        PendingBlock::new(block_height4, payload_hash, 4, 0),
    );
    actor.pending.pending_blocks.insert(
        hash_height5,
        PendingBlock::new(block_height5, payload_hash, 5, 0),
    );

    let expected_roster = {
        let roster = actor.roster_for_vote(hash_height5, 5, 0);
        if roster.is_empty() {
            actor.effective_commit_topology()
        } else {
            roster
        }
    };
    assert!(
        !expected_roster.is_empty(),
        "derived roster should be non-empty"
    );

    let mut signers = BTreeSet::new();
    for idx in 0..expected_roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, expected_roster.len());
    let topology = super::network_topology::Topology::new(expected_roster.clone());
    let expected_epoch = actor.epoch_for_height(5);
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        hash_height5,
        5,
        0,
        expected_epoch,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: hash_height5,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 5,
        view: 0,
        epoch: expected_epoch,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&expected_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: expected_roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };

    actor.handle_qc(qc.clone()).expect("qc handled");
    assert!(
        actor
            .deferred_qcs
            .contains_key(&(Phase::Commit, hash_height5, 5, 0, expected_epoch)),
        "QC should be deferred until roster history is available"
    );
    assert!(
        !actor
            .qc_cache
            .contains_key(&(Phase::Commit, hash_height5, 5, 0, expected_epoch)),
        "deferred QC should not be cached yet"
    );

    let history_epoch = actor.epoch_for_height(2);
    let mut history_signers = BTreeSet::new();
    for idx in 0..history_roster.len() {
        history_signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let history_bitmap = super::build_signers_bitmap(&history_signers, history_roster.len());
    let history_topology = super::network_topology::Topology::new(history_roster.clone());
    let history_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        hash_height2,
        2,
        0,
        history_epoch,
        &history_bitmap,
        &history_topology,
        &harness.key_pairs,
    );
    let history_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: hash_height2,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 2,
        view: 0,
        epoch: history_epoch,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&history_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: history_roster,
        aggregate: QcAggregate {
            signers_bitmap: history_bitmap,
            bls_aggregate_signature: history_signature,
        },
    };
    status::record_commit_qc(history_qc);

    let height = 5u64;
    let view = 0u64;
    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(0);
    assert!(
        committed_height >= 2,
        "committed height should reflect seeded hashes"
    );
    let derived_roster = actor.roster_for_vote(hash_height5, height, view);
    let derived_set: BTreeSet<_> = derived_roster.iter().cloned().collect();
    let expected_set: BTreeSet<_> = expected_roster.iter().cloned().collect();
    assert_eq!(
        derived_set, expected_set,
        "roster roll-forward should preserve expected membership"
    );
    let deferred_key = (Phase::Commit, hash_height5, 5, 0, expected_epoch);
    if let Some(deferred_qc) = actor.deferred_qcs.get_mut(&deferred_key) {
        if deferred_qc.validator_set != derived_roster {
            let mut replay_signers = BTreeSet::new();
            for idx in 0..derived_roster.len() {
                replay_signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
            }
            let replay_bitmap = super::build_signers_bitmap(&replay_signers, derived_roster.len());
            let replay_topology = super::network_topology::Topology::new(derived_roster.clone());
            let replay_signature = aggregate_signature_for_bitmap(
                &actor.common_config.chain,
                PERMISSIONED_TAG,
                Phase::Commit,
                hash_height5,
                5,
                0,
                expected_epoch,
                &replay_bitmap,
                &replay_topology,
                &harness.key_pairs,
            );
            deferred_qc.validator_set_hash = HashOf::new(&derived_roster);
            deferred_qc.validator_set = derived_roster.clone();
            deferred_qc.aggregate.signers_bitmap = replay_bitmap;
            deferred_qc.aggregate.bls_aggregate_signature = replay_signature;
        }
    }
    let replayed = actor.try_replay_deferred_qcs();
    assert!(replayed, "expected deferred QCs to replay");
    let qc_key = (Phase::Commit, hash_height5, 5, 0, expected_epoch);
    let qc_cached = actor.qc_cache.contains_key(&qc_key);
    let pending_snapshot = actor.pending.pending_blocks.get(&hash_height5);
    let pending_commit_seen = pending_snapshot.is_some_and(|pending| pending.commit_qc_observed());
    let pending_aborted = pending_snapshot.is_some_and(|pending| pending.aborted);
    let pending_status = pending_snapshot.map(|pending| pending.validation_status);
    let pending_present = pending_snapshot.is_some();
    let kura_committed = actor.kura.get_block_height_by_hash(hash_height5).is_some();
    assert!(
        qc_cached,
        "replayed QC should be cached; cached={:?} deferred={:?} commit_seen={} pending_present={} pending_aborted={} pending_status={:?} kura_committed={} locked={:?}",
        actor.qc_cache.keys().collect::<Vec<_>>(),
        actor.deferred_qcs.keys().collect::<Vec<_>>(),
        pending_commit_seen,
        pending_present,
        pending_aborted,
        pending_status,
        kura_committed,
        actor.locked_qc,
    );
    assert!(
        pending_present && !kura_committed,
        "pending block should remain queued until tip advances; commit_seen={} pending_present={} pending_aborted={} pending_status={:?} kura_committed={} locked={:?}",
        pending_commit_seen,
        pending_present,
        pending_aborted,
        pending_status,
        kura_committed,
        actor.locked_qc,
    );
    assert!(
        actor.deferred_qcs.is_empty(),
        "deferred QCs should be cleared after replay"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn deferred_missing_payload_qc_expiry_is_bounded() {
    let _worker_guard = status::worker_queue_test_guard();
    status::reset_worker_loop_snapshot_for_tests();
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;
    status::reset_missing_block_fetch_counters_for_tests();
    status::reset_view_change_cause_counters_for_tests();

    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([37; Hash::LENGTH]));
    let qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 2,
        view: 0,
        epoch: actor.epoch_for_height(2),
        mode_tag: "permissioned".to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&Vec::<PeerId>::new()),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: Vec::new(),
        aggregate: QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };
    let key = super::Actor::qc_tally_key(&qc);
    let now = Instant::now();
    actor.deferred_missing_payload_qcs.insert(
        key,
        super::DeferredQcEntry {
            qc,
            first_seen: now
                .checked_sub(actor.recovery_deferred_qc_ttl() + Duration::from_millis(1))
                .expect("time subtraction should be valid"),
            last_attempt: now,
            attempts: super::DEFERRED_MISSING_PAYLOAD_QC_MAX_ATTEMPTS,
            escalated_fetch: true,
            reason: "test_expiry",
        },
    );

    let progressed = actor.try_replay_deferred_missing_payload_qcs(now);
    assert!(progressed, "deferred QC expiry should make progress");
    assert!(
        actor.deferred_missing_payload_qcs.is_empty(),
        "expired deferred QCs should be removed"
    );

    let snapshot = status::snapshot();
    assert!(
        snapshot.qc_deferred_expired_total >= 1,
        "deferred QC expiry should be observable in status counters"
    );
    assert!(
        snapshot.view_change_causes.missing_payload_total >= 1,
        "deferred QC expiry should record MissingPayload view-change cause"
    );

    harness.shutdown.send();
}

