#[tokio::test(flavor = "current_thread")]
async fn handle_qc_drops_empty_block_payload() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    {
        let _guard = super::status::message_handling_test_guard();
        super::status::reset_message_handling_for_tests();
    }
    let height = 1_u64;
    let view = 0_u64;
    let block = empty_block(height, view, None);
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    let epoch = actor.epoch_for_height(height);
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        vec![0x01],
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_qc(qc).expect("handle qc");

    let key = (Phase::Commit, block_hash, height, view, epoch);
    assert!(
        !actor.qc_cache.contains_key(&key),
        "empty-block QC should be dropped before caching"
    );
    assert!(
        actor.locked_qc.is_none(),
        "empty-block QC must not update locks"
    );

    let entries = super::status::snapshot().consensus_message_handling.entries;
    let entry = entries
        .iter()
        .find(|entry| {
            entry.kind == super::status::ConsensusMessageKind::Qc
                && entry.outcome == super::status::ConsensusMessageOutcome::Dropped
                && entry.reason == super::status::ConsensusMessageReason::InvalidPayload
        })
        .expect("empty QC drop should be recorded");
    assert_eq!(entry.total, 1);

    super::status::reset_message_handling_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_qc_marks_pending_with_commit_qc() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config_and_height(4, consensus_cfg, None, 0).await;
    let actor = &mut harness.actor;

    seed_genesis_block_for_state(actor.state.as_ref());
    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1);
    let view = 0_u64;
    let view_index = view;
    let block = nonempty_block_for_actor(actor, &harness.key_pairs, height, view_index, None);
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    let inflight_block = nonempty_block_for_actor(
        actor,
        &harness.key_pairs,
        height + 1,
        view_index,
        Some(block_hash),
    );
    let inflight_hash = inflight_block.hash();
    let inflight_payload_hash = Hash::new(super::proposals::block_payload_bytes(&inflight_block));
    let inflight_pending =
        PendingBlock::new(inflight_block, inflight_payload_hash, height + 1, view);
    let inflight_lock = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: inflight_hash,
        height: height + 1,
        view,
        epoch: 0,
    };
    let commit_topology = actor.effective_commit_topology();
    let inflight = CommitInFlight {
        id: 1,
        lock: inflight_lock,
        block_hash: inflight_hash,
        pending: inflight_pending,
        commit_topology: commit_topology.clone(),
        signature_topology: commit_topology.clone(),
        qc_signers: None,
        commit_qc: None,
        allow_quorum_bypass: false,
        post_commit_qc: None,
        enqueue_time: Instant::now(),
    };
    actor.subsystems.commit.inflight = Some(inflight);

    let topology = super::network_topology::Topology::new(commit_topology);
    let mut signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx"))
                .expect("signer idx fits"),
        );
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        0,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_qc(qc.clone()).expect("handle qc");

    let pending = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending block retained");
    assert!(
        pending.commit_qc_observed(),
        "pending block should mark commit certificate seen"
    );
    assert_eq!(pending.commit_qc_epoch, Some(qc.epoch));

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_qc_validates_pending_block_on_commit_qc() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config_and_height(4, consensus_cfg, None, 0).await;
    let actor = &mut harness.actor;

    let parent = seed_genesis_block_for_state(actor.state.as_ref());
    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1);
    let view = 0_u64;
    let commit_topology = actor.effective_commit_topology();
    let mut leader_topology = super::network_topology::Topology::new(commit_topology.clone());
    let leader_idx = actor
        .leader_index_for(&mut leader_topology, height, view)
        .expect("leader index available for tests");
    let leader_peer = leader_topology
        .as_ref()
        .get(leader_idx)
        .expect("leader exists in topology");
    let leader_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == leader_peer.public_key())
        .expect("leader keypair available in harness");
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.chain_id,
        height,
        view,
        Some(parent),
        leader_kp,
        u64::try_from(leader_idx).expect("leader index fits u64"),
    );
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );

    assert!(
        !actor.block_known_for_lock(block_hash),
        "pending block should start unvalidated"
    );

    let topology = super::network_topology::Topology::new(commit_topology);
    let signers: BTreeSet<ValidatorIndex> = (0..topology.as_ref().len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        0,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_qc(qc).expect("handle qc");

    assert!(
        actor.block_known_for_lock(block_hash),
        "commit QC should validate pending block when payload is present"
    );

    harness.shutdown.send();
}

