#[tokio::test(flavor = "current_thread")]
async fn request_missing_block_for_pending_rbc_holds_initial_frontier_fetch_within_ingress_grace() {
    let _guard = super::status::missing_block_fetch_test_guard();
    super::status::reset_missing_block_fetch_counters_for_tests();

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let background_log = attach_background_log(actor);

    let height = actor.committed_height_snapshot().saturating_add(1);
    let view = 0u64;
    let roster = actor.effective_commit_topology();
    let (block, init, _payload_hash) =
        rbc_init_with_block(actor, &roster, height, view, &harness.key_pairs);
    let key = Actor::session_key(&block.hash(), height, view);
    actor.handle_rbc_init(init, None).expect("rbc init");
    actor.pending.missing_block_requests.remove(&key.0);
    let _ = take_background_log(&background_log);

    actor.request_missing_block_for_pending_rbc(key, "test_ingress_grace", None);

    let snapshot = super::status::snapshot();
    assert_eq!(
        snapshot.missing_block_fetch_total, 0,
        "committed + 1 RBC recovery must not emit generic missing-block fetches"
    );
    assert!(
        actor.pending.missing_block_requests.is_empty(),
        "committed + 1 RBC recovery must stay out of the generic missing-block tracker"
    );
    let frontier_slot = actor.frontier_slot.as_ref().expect("frontier slot");
    assert_eq!(frontier_slot.block_hash, key.0);
    assert_eq!(frontier_slot.height, height);
    assert_eq!(frontier_slot.view, view);
    assert!(
        !frontier_slot.block_created_seen,
        "RBC metadata alone must not become authoritative frontier identity"
    );
    assert!(
        take_background_log(&background_log)
            .into_iter()
            .all(|entry| entry.msg_kind != Some("FetchPendingBlock")),
        "committed + 1 RBC recovery must not emit FetchPendingBlock traffic"
    );

    let grace = actor.authoritative_body_ingress_fetch_grace();
    let slot = actor
        .frontier_slot
        .as_mut()
        .expect("frontier slot retained");
    slot.last_updated_at = Instant::now()
        .checked_sub(grace.saturating_add(Duration::from_millis(1)))
        .unwrap_or_else(Instant::now);
    let _ = take_background_log(&background_log);

    actor.request_missing_block_for_pending_rbc(key, "test_ingress_grace", None);

    let snapshot_after_grace = super::status::snapshot();
    assert_eq!(
        snapshot_after_grace.missing_block_fetch_total, 0,
        "the second invocation should not add generic missing-block fetches either"
    );
    assert!(
        actor.pending.missing_block_requests.is_empty(),
        "committed + 1 RBC recovery must stay out of the generic missing-block tracker after grace too"
    );
    assert!(
        take_background_log(&background_log)
            .into_iter()
            .all(|entry| entry.msg_kind != Some("FetchPendingBlock")),
        "post-grace committed + 1 RBC recovery must still avoid FetchPendingBlock traffic"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn request_missing_block_for_pending_rbc_far_future_under_lock_lag_reanchors_frontier() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let locked_hash = seed_genesis_block_for_state(&actor.state);
    let local_height = actor.committed_height_snapshot();
    let frontier_height = local_height.saturating_add(1);
    let far_height = local_height.saturating_add(5);
    let far_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xBC; Hash::LENGTH]));
    actor.locked_qc = Some(QcHeaderRef {
        height: local_height,
        view: 0,
        epoch: actor.epoch_for_height(local_height),
        subject_block_hash: locked_hash,
        phase: Phase::Commit,
    });
    actor.highest_qc = Some(QcHeaderRef {
        height: far_height,
        view: 0,
        epoch: actor.epoch_for_height(far_height),
        subject_block_hash: HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed(
            [0xBD; Hash::LENGTH],
        )),
        phase: Phase::Commit,
    });

    let now = Instant::now();
    actor.pending.missing_block_requests.insert(
        far_hash,
        MissingBlockRequest {
            height: far_height,
            view: 0,
            phase: Phase::Commit,
            priority: MissingBlockPriority::Consensus,
            retry_window: Duration::from_millis(25),
            view_change_window: Some(Duration::from_millis(25)),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 1,
        },
    );
    actor.range_pull_escalation_cooldowns.clear();

    actor.request_missing_block_for_pending_rbc(
        (far_hash, far_height, 0),
        "test_lock_lag_far_future_rbc",
        None,
    );

    assert!(
        !actor.pending.missing_block_requests.contains_key(&far_hash),
        "far-future RBC dependency under lock lag should be treated as obsolete"
    );
    assert!(
        actor
            .range_pull_escalation_cooldowns
            .keys()
            .any(|(_, _, canonical_height, _)| *canonical_height == frontier_height),
        "far-future RBC dependency under lock lag should reanchor canonical frontier recovery"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn request_missing_block_for_pending_rbc_far_future_reanchors_contiguous_frontier() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let _ = seed_genesis_block_for_state(&actor.state);

    let local_height = actor.committed_height_snapshot();
    let frontier_height = local_height.saturating_add(1);
    let far_height = frontier_height.saturating_add(3);
    let far_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xBE; Hash::LENGTH]));
    let key = (far_hash, far_height, 0);
    let now = Instant::now();
    actor.pending.missing_block_requests.insert(
        far_hash,
        MissingBlockRequest {
            height: far_height,
            view: 0,
            phase: Phase::Commit,
            priority: MissingBlockPriority::Consensus,
            retry_window: Duration::from_millis(25),
            view_change_window: Some(Duration::from_millis(25)),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 1,
        },
    );
    actor
        .subsystems
        .da_rbc
        .rbc
        .pending
        .insert(key, super::pending_rbc::PendingRbcMessages::new(now));
    actor.record_rbc_session_roster(
        key,
        actor.effective_commit_topology(),
        super::RbcRosterSource::Init,
    );
    actor.range_pull_escalation_cooldowns.clear();

    actor.request_missing_block_for_pending_rbc(key, "test_far_future_rbc", None);

    assert!(
        !actor.pending.missing_block_requests.contains_key(&far_hash),
        "far-future RBC dependency should not stay tracked as a missing-block request"
    );
    assert!(
        !actor.subsystems.da_rbc.rbc.pending.contains_key(&key),
        "far-future RBC stash should be purged instead of surviving as active recovery state"
    );
    assert!(
        actor.rbc_session_roster(key).is_empty(),
        "far-future RBC roster state should be cleared with the suppressed session"
    );
    assert!(
        actor
            .range_pull_escalation_cooldowns
            .keys()
            .any(|(_, _, canonical_height, reason)| {
                *canonical_height == frontier_height && *reason == "rbc_far_future_missing_block"
            }),
        "far-future RBC dependency should reanchor the contiguous frontier"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_qc_accepts_stale_precommit_qc_for_unknown_block() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config_and_height(1, consensus_cfg, None, 2).await;
    let actor = &mut harness.actor;

    let height = 3u64;
    let stale_view = 0u64;
    let local_view = 1u64;
    let block = sample_block(height, stale_view, None);
    let block_hash = block.hash();

    let now = Instant::now();
    actor.phase_tracker.start_new_round(height, now);
    actor.phase_tracker.on_view_change(height, local_view, now);

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signature_topology = super::topology_for_view(
        &topology,
        height,
        stale_view,
        actor.mode_tag(),
        actor.npos_prf_seed(),
    );
    let required = signature_topology.min_votes_for_commit().max(1);
    let signers: BTreeSet<ValidatorIndex> = (0..required)
        .map(|idx| ValidatorIndex::try_from(idx).expect("index"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, signature_topology.as_ref().len());
    let qc = qc_with_view_bitmap(
        &actor.chain_id,
        block_hash,
        height,
        stale_view,
        0,
        &signers_bitmap,
        Phase::Commit,
        &signature_topology,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_qc(qc).expect("precommit qc");
    assert!(
        actor
            .qc_cache
            .contains_key(&(Phase::Commit, block_hash, height, stale_view, 0)),
        "precommit QC should be cached for stale view"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn block_created_applies_cached_precommit_qc() {
    let _commit_history_guard = super::status::commit_history_test_guard();
    let _local_removed_guard = LocalRemovedGuard::new(false);

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let genesis_hash = seed_genesis_block_for_state(&actor.state);
    let height = 2u64;
    let view = 0u64;
    let block =
        nonempty_block_for_actor(actor, &harness.key_pairs, height, view, Some(genesis_hash));
    let block_hash = block.hash();

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit().max(1);
    let mut signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        if signers.len() >= required {
            break;
        }
        signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx"))
                .expect("signer idx fits"),
        );
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let epoch = actor.epoch_for_height(height);
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    actor.handle_qc(qc).expect("handle qc");
    assert!(
        actor
            .qc_cache
            .contains_key(&(Phase::Commit, block_hash, height, view, epoch)),
        "precommit QC should be cached for unknown block"
    );
    assert!(
        actor.locked_qc.is_none(),
        "lock must remain unset for unknown blocks"
    );

    actor
        .handle_block_created(
            super::message::BlockCreated {
                block,
                frontier: None,
            },
            None,
        )
        .expect("block created");

    let locked = actor.locked_qc.expect("locked QC should be updated");
    assert_eq!(locked.subject_block_hash, block_hash);
    assert_eq!(locked.height, height);
    assert_eq!(locked.view, view);
    let highest = actor.highest_qc.expect("highest QC should be updated");
    assert_eq!(highest.subject_block_hash, block_hash);
    assert_eq!(highest.height, height);
    assert_eq!(highest.view, view);

    harness.shutdown.send();
}

