#[tokio::test(flavor = "current_thread")]
async fn handle_qc_missing_block_fetch_uses_aggressive_topology_for_commit_qc() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg
        .recovery
        .missing_block_signer_fallback_attempts = 1;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    seed_genesis_block_for_state(&actor.state);

    let height = 2u64;
    let view = 0u64;
    let block = nonempty_block_for_actor(actor, &harness.key_pairs, height, view, None);
    let block_hash = block.hash();

    let now = Instant::now();
    actor.phase_tracker.start_new_round(height, now);

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signature_topology = super::topology_for_view(
        &topology,
        height,
        view,
        actor.mode_tag(),
        actor.npos_prf_seed(),
    );
    let signers: BTreeSet<ValidatorIndex> = (0..signature_topology.as_ref().len())
        .map(|idx| {
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer index fits u32"))
                .expect("validator index fits")
        })
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, signature_topology.as_ref().len());
    let qc = qc_with_view_bitmap(
        &actor.chain_id,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        Phase::Commit,
        &signature_topology,
        &topology,
        &harness.key_pairs,
    );

    #[cfg(feature = "telemetry")]
    let telemetry = actor.telemetry_handle().expect("telemetry enabled").clone();
    #[cfg(feature = "telemetry")]
    let metrics = telemetry.metrics().await;
    #[cfg(feature = "telemetry")]
    let signers_before = metrics
        .sumeragi_missing_block_fetch_target_total
        .with_label_values(&["signers"])
        .get();
    #[cfg(feature = "telemetry")]
    let topology_before = metrics
        .sumeragi_missing_block_fetch_target_total
        .with_label_values(&["topology"])
        .get();

    actor.handle_qc(qc).expect("handle precommit QC");
    let stats = actor
        .pending
        .missing_block_requests
        .get(&block_hash)
        .expect("missing-block request recorded");
    assert_eq!(
        stats.retry_window,
        super::REBROADCAST_COOLDOWN_FLOOR,
        "commit QC should use aggressive retry window"
    );
    assert_eq!(
        stats.view_change_window,
        Some(actor.quorum_timeout(actor.runtime_da_enabled())),
        "view-change deadline should still follow quorum timeout"
    );
    #[cfg(feature = "telemetry")]
    {
        let signers_after = metrics
            .sumeragi_missing_block_fetch_target_total
            .with_label_values(&["signers"])
            .get();
        let topology_after = metrics
            .sumeragi_missing_block_fetch_target_total
            .with_label_values(&["topology"])
            .get();
        assert_eq!(
            signers_after, signers_before,
            "aggressive commit QC fetch should skip signer-only targets"
        );
        assert_eq!(
            topology_after,
            topology_before + 1,
            "aggressive commit QC fetch should target full topology immediately"
        );
    }

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn defer_qc_if_block_missing_uses_rebroadcast_cooldown() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    super::status::reset_worker_loop_snapshot_for_tests();
    super::status::reset_view_change_cause_counters_for_tests();
    let mut harness = test_actor_harness_with_config(2, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let mut block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x93; Hash::LENGTH]));
    if actor.block_known_locally(block_hash) {
        block_hash =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x94; Hash::LENGTH]));
    }
    let height = 2u64;
    let view = 0u64;
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signers = BTreeSet::new();

    let deferred = actor.defer_qc_if_block_missing(
        Phase::Commit,
        block_hash,
        height,
        view,
        &signers,
        &topology,
    );
    assert!(deferred, "missing payload should defer QC aggregation");

    let stats = actor
        .pending
        .missing_block_requests
        .get(&block_hash)
        .expect("missing-block request recorded");
    assert_eq!(stats.retry_window, actor.rebroadcast_cooldown());
    if let Some(window) = stats.view_change_window {
        assert_eq!(window, actor.quorum_timeout(actor.runtime_da_enabled()));
    }

    harness.shutdown.send();
}

