#[tokio::test(flavor = "current_thread")]
async fn qc_missing_block_defer_fast_recovery_is_single_shot_per_cooldown() {
    let _missing_block_guard = super::status::missing_block_fetch_test_guard();
    super::status::reset_missing_block_fetch_counters_for_tests();
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    actor.relay_backpressure.disable_for_tests();
    let _ = seed_genesis_block_for_state(&actor.state);

    let mut block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x89; Hash::LENGTH]));
    if actor.block_known_locally(block_hash) {
        block_hash =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x8A; Hash::LENGTH]));
    }
    let height = actor.state.view().height() as u64 + 1;
    let view = 0u64;
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit().max(1);
    let signers: BTreeSet<ValidatorIndex> = (0..required)
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();

    let before = super::status::snapshot();
    assert!(
        actor.qc_missing_block_defer(
            Phase::Commit,
            block_hash,
            height,
            view,
            &signers,
            &topology,
            ConsensusMode::Permissioned,
            /*quorum_met*/ true,
            required,
            /*block_known*/ false,
            required,
            required,
        ),
        "missing payload should stay deferred"
    );
    let first_fetch_at = actor
        .block_sync_fetch_log
        .last_sent
        .get(&block_hash)
        .copied()
        .expect("fast recovery should record cooldown state");
    let after_first = super::status::snapshot();
    assert!(
        after_first.blocksync_range_pull_escalation_total
            >= before.blocksync_range_pull_escalation_total,
        "fast recovery should not regress block-sync escalation tracking"
    );

    assert!(
        actor.qc_missing_block_defer(
            Phase::Commit,
            block_hash,
            height,
            view,
            &signers,
            &topology,
            ConsensusMode::Permissioned,
            /*quorum_met*/ true,
            required,
            /*block_known*/ false,
            required,
            required,
        ),
        "missing payload should remain deferred"
    );
    let second_fetch_at = actor
        .block_sync_fetch_log
        .last_sent
        .get(&block_hash)
        .copied()
        .expect("cooldown record should remain present");
    assert_eq!(
        second_fetch_at, first_fetch_at,
        "fast recovery should not re-fire inside rebroadcast cooldown"
    );
    let after_second = super::status::snapshot();
    assert_eq!(
        after_second.blocksync_range_pull_escalation_total,
        after_first.blocksync_range_pull_escalation_total,
        "second defer in cooldown should not emit an extra range pull escalation"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn qc_missing_block_defer_inflight_fetch_suppresses_range_pull_escalation() {
    let _missing_block_guard = super::status::missing_block_fetch_test_guard();
    super::status::reset_missing_block_fetch_counters_for_tests();
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let _ = seed_genesis_block_for_state(&actor.state);

    let mut block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x8B; Hash::LENGTH]));
    if actor.block_known_locally(block_hash) {
        block_hash =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x8C; Hash::LENGTH]));
    }
    let height = actor.state.view().height() as u64 + 1;
    let view = 0_u64;
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit().max(1);
    let signers: BTreeSet<ValidatorIndex> = (0..required)
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();

    let now = Instant::now();
    let retry_window = actor
        .rebroadcast_cooldown()
        .saturating_mul(8)
        .max(Duration::from_secs(1));
    actor.pending.missing_block_requests.insert(
        block_hash,
        super::MissingBlockRequest {
            height,
            view,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window,
            view_change_window: Some(retry_window),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 1,
        },
    );
    let vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: actor.epoch_for_height(height),
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    actor.vote_log.insert(
        (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
        vote,
    );
    let _ = harness.background_rx.try_iter().count();

    let before = super::status::snapshot();
    assert!(
        actor.qc_missing_block_defer(
            Phase::Commit,
            block_hash,
            height,
            view,
            &signers,
            &topology,
            ConsensusMode::Permissioned,
            /*quorum_met*/ true,
            required,
            /*block_known*/ false,
            required,
            required,
        ),
        "missing payload should remain deferred while equivalent fetch is in-flight",
    );
    let after = super::status::snapshot();
    assert_eq!(
        after.blocksync_range_pull_escalation_total, before.blocksync_range_pull_escalation_total,
        "duplicate defer with in-flight fetch should suppress range-pull escalation churn",
    );
    let vote_posts = harness
        .background_rx
        .try_iter()
        .filter(|post| {
            matches!(
                post,
                BackgroundPost::Post { msg, .. }
                    if matches!(
                        msg.as_ref(),
                        BlockMessage::QcVote(vote)
                            if vote.phase == Phase::Commit
                                && vote.block_hash == block_hash
                                && vote.height == height
                                && vote.view == view
                    )
            )
        })
        .count();
    assert_eq!(
        vote_posts, 0,
        "duplicate defer with in-flight fetch should suppress vote rebroadcast churn",
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn defer_qc_if_block_missing_widens_retry_window_when_rbc_progresses() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(2, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let mut block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x97; Hash::LENGTH]));
    if actor.block_known_locally(block_hash) {
        block_hash =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x98; Hash::LENGTH]));
    }
    let height = 2u64;
    let view = 0u64;
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signers = BTreeSet::new();
    let base_retry_window = actor.rebroadcast_cooldown();
    let availability_timeout =
        actor.availability_timeout(actor.quorum_timeout(actor.runtime_da_enabled()), true);
    let expected_retry_window = base_retry_window
        .saturating_mul(2)
        .min(availability_timeout.max(base_retry_window));

    let mut session = RbcSession::test_new(
        2,
        Some(Hash::new(b"missing-block-rbc-progress")),
        None,
        actor.epoch_for_height(height),
    );
    session.test_note_chunk(0, vec![0xAB], 0);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert((block_hash, height, view), session);

    let deferred = actor.defer_qc_if_block_missing(
        Phase::Commit,
        block_hash,
        height,
        view,
        &signers,
        &topology,
    );
    assert!(
        deferred,
        "missing payload should still defer QC aggregation"
    );

    let stats = actor
        .pending
        .missing_block_requests
        .get(&block_hash)
        .expect("missing-block request recorded");
    assert!(
        stats.retry_window > base_retry_window,
        "RBC progress should widen missing-block retry window"
    );
    assert_eq!(
        stats.retry_window, expected_retry_window,
        "retry window should follow RBC-aware widening policy"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn qc_missing_block_defer_recovers_authoritative_rbc_session_before_fetch() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.rbc.chunk_max_bytes = 1024 * 1024;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let parent = seed_genesis_block_for_state(&actor.state);
    let height = actor.state.view().height() as u64 + 1;
    let view = 0u64;
    let block = nonempty_block_for_actor(actor, &harness.key_pairs, height, view, Some(parent));
    let block_hash = block.hash();
    let payload = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload);
    let key = (block_hash, height, view);
    let mut session = Actor::build_rbc_session_from_payload(
        &payload,
        payload_hash,
        actor.config.rbc.chunk_max_bytes,
        actor.epoch_for_height(height),
    )
    .expect("build RBC session");
    session.test_set_block_header_and_signature(&block);
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);
    actor.record_rbc_session_roster(
        key,
        actor.effective_commit_topology(),
        super::RbcRosterSource::Derived,
    );

    assert!(
        !actor.block_known_locally(block_hash),
        "seeded RBC payload should not count as a known block before recovery"
    );

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit().max(1);
    let signers: BTreeSet<ValidatorIndex> = (0..required)
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();

    let deferred = actor.qc_missing_block_defer(
        Phase::Commit,
        block_hash,
        height,
        view,
        &signers,
        &topology,
        ConsensusMode::Permissioned,
        /*quorum_met*/ true,
        required,
        /*block_known*/ false,
        required,
        required,
    );
    assert!(
        !deferred,
        "locally authoritative RBC payload should materialize the block before missing-block deferral"
    );
    assert!(
        actor.block_known_locally(block_hash),
        "QC recovery should materialize the block locally"
    );
    assert!(
        actor.pending.pending_blocks.contains_key(&block_hash),
        "recovered BlockCreated should populate pending block state"
    );
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&block_hash),
        "QC recovery should avoid scheduling a missing-block fetch"
    );

    harness.shutdown.send();
}

