#[tokio::test(flavor = "current_thread")]
async fn rbc_chunk_commit_pipeline_runs_on_completion() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.rbc.chunk_max_bytes = 1024 * 1024;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;

    let view = 0u64;
    let (height, parent_hash) = {
        let state_view = harness.actor.state.view();
        let tip_height = u64::try_from(state_view.height()).unwrap_or(u64::MAX);
        let tip_hash = state_view.latest_block_hash();
        drop(state_view);
        (tip_height.saturating_add(1), tip_hash)
    };
    let block = sample_block(height, view, parent_hash);
    let block_hash = block.hash();
    let key = (block_hash, height, view);

    let payload = vec![0xAB; 2048];
    let payload_hash = Hash::new(&payload);
    let chunks = super::rbc::chunk_payload_bytes(&payload, 1024);
    assert_eq!(chunks.len(), 2);

    let full_session =
        Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, 0).expect("session");
    let chunk_root = full_session.chunk_root().expect("chunk root");
    let session = RbcSession::new(
        u32::try_from(chunks.len()).expect("chunk count fits u32"),
        Some(payload_hash),
        Some(chunk_root),
        Some(
            full_session
                .expected_chunk_digests
                .clone()
                .expect("chunk digests"),
        ),
        0,
    )
    .expect("session");
    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session);
    harness.actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );
    harness.actor.note_proposal_seen(height, view, payload_hash);
    assert!(
        harness.actor.active_pending_blocks_len() > 0,
        "test requires an active pending block"
    );

    let block_time = {
        let view = harness.actor.state.view();
        harness
            .actor
            .block_time_for_mode(&view, harness.actor.consensus_mode)
    };
    let cooldown = block_time.max(super::REBROADCAST_COOLDOWN_FLOOR);
    let now = Instant::now();
    let last_qc_rebuild = now - cooldown - Duration::from_millis(1);
    harness.actor.last_qc_rebuild = last_qc_rebuild;
    harness.actor.pending.last_commit_pipeline_run = last_qc_rebuild;
    harness.actor.pending.commit_pipeline_wakeup = false;

    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height,
        view,
        epoch: 0,
        idx: 0,
        bytes: chunks[0].clone(),
    };
    harness
        .actor
        .handle_rbc_chunk(chunk, None)
        .expect("first chunk");
    assert_eq!(harness.actor.last_qc_rebuild, last_qc_rebuild);
    assert!(
        !harness.actor.pending.commit_pipeline_wakeup,
        "commit pipeline should not be requested before payload completion"
    );

    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height,
        view,
        epoch: 0,
        idx: 1,
        bytes: chunks[1].clone(),
    };
    harness
        .actor
        .handle_rbc_chunk(chunk, None)
        .expect("second chunk");
    assert!(
        harness.actor.pending.commit_pipeline_wakeup,
        "commit pipeline should be requested once payload completes"
    );
    harness.actor.tick();
    assert!(harness.actor.last_qc_rebuild > last_qc_rebuild);

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rbc_pending_caps_respect_minimum_chunk_size() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.rbc.chunk_max_bytes = 1;
    let hard_chunk_cap = usize::try_from(super::RBC_MAX_TOTAL_CHUNKS).unwrap_or(usize::MAX);
    let chunk_max_bytes = consensus_cfg.rbc.chunk_max_bytes.max(1);
    let hard_byte_cap = chunk_max_bytes.saturating_mul(hard_chunk_cap);
    let expected_max_bytes = consensus_cfg
        .rbc
        .pending_max_bytes
        .min(hard_byte_cap)
        .max(chunk_max_bytes);
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;

    let (_max_chunks, max_bytes) = harness.actor.pending_rbc_caps();
    assert_eq!(max_bytes, expected_max_bytes);

    let height = 4;
    let view = 0u64;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA5; Hash::LENGTH]));
    let key = (block_hash, height, view);

    let payload = vec![0xAB];
    let payload_hash = Hash::new(&payload);
    let seeded =
        Actor::build_rbc_session_from_payload(&payload, payload_hash, 1, 0).expect("session");
    let chunk_root = seeded.chunk_root().expect("chunk root");
    let session = RbcSession::new(
        1,
        Some(payload_hash),
        Some(chunk_root),
        Some(
            seeded
                .expected_chunk_digests
                .clone()
                .expect("chunk digests"),
        ),
        0,
    )
    .expect("session");
    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session);

    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height,
        view,
        epoch: 0,
        idx: 0,
        bytes: payload,
    };
    harness
        .actor
        .handle_rbc_chunk(chunk, None)
        .expect("chunk handled");

    let session = harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    assert_eq!(session.received_chunks(), 1);

    harness.shutdown.send();
}

