#[test]
fn membership_view_hash_changes_with_context() {
    let chain_id = ChainId::from("iroha:test:membership");
    let peers: Vec<PeerId> = (0..3)
        .map(|_| PeerId::from(KeyPair::random().public_key().clone()))
        .collect();
    let hash_a = super::compute_membership_view_hash(&chain_id, 5, 2, 1, &peers);
    let hash_b = super::compute_membership_view_hash(&chain_id, 5, 2, 1, &peers);
    assert_eq!(
        hash_a, hash_b,
        "hash must be deterministic for same context"
    );
    let mut peers_reordered = peers.clone();
    peers_reordered.reverse();
    let hash_c = super::compute_membership_view_hash(&chain_id, 5, 2, 1, &peers_reordered);
    assert_ne!(hash_a, hash_c, "hash must differ when roster order changes");
    let hash_d = super::compute_membership_view_hash(&chain_id, 5, 3, 1, &peers);
    assert_ne!(hash_a, hash_d, "hash must differ when view index changes");
}

#[tokio::test(flavor = "current_thread")]
async fn init_collector_plan_broadcasts_membership_advert() {
    let mut harness = test_actor_harness(3).await;
    harness.actor.config.collectors.k = 1;
    harness.actor.config.collectors.redundant_send_r = 1;
    {
        let state = Arc::get_mut(&mut harness.actor.state).expect("state uniquely held");
        let mut block = state.world.block();
        let params = block.parameters.get_mut();
        params.sumeragi.collectors_k = 2;
        params.sumeragi.collectors_redundant_send_r = 3;
        block.commit();
    }
    let height = 5;
    let view = 2;
    let epoch = harness.actor.epoch_for_height(height);
    let topology =
        super::network_topology::Topology::new(harness.actor.effective_commit_topology());

    let _ = harness.background_rx.try_iter().count();
    harness.actor.init_collector_plan(&topology, height, view);

    let advert = harness
        .background_rx
        .try_iter()
        .find_map(|post| match post {
            BackgroundPost::Broadcast { msg, .. } => match msg.as_ref() {
                BlockMessage::ConsensusParams(advert) => Some(*advert),
                _ => None,
            },
            _ => None,
        })
        .expect("consensus params broadcast");
    let (on_chain_k, on_chain_r) = on_chain_permissioned_collector_params(&harness.actor);
    let expected_k = u16::try_from(on_chain_k).unwrap_or(u16::MAX);
    assert_eq!(advert.collectors_k, expected_k);
    assert_eq!(advert.redundant_send_r, on_chain_r);
    let membership = advert.membership.expect("membership payload");
    assert_eq!(membership.height, height);
    assert_eq!(membership.view, view);
    assert_eq!(membership.epoch, epoch);
    let expected_hash = super::compute_membership_view_hash(
        &harness.actor.chain_id,
        height,
        view,
        epoch,
        topology.as_ref(),
    );
    assert_eq!(membership.view_hash, Some(expected_hash));

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn init_collector_plan_uses_epoch_for_height() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;
    consensus_cfg.npos.epoch_length_blocks = 2;

    let mut harness = test_actor_harness_with_config(3, consensus_cfg, None).await;

    let height = 2;
    let view = 1;
    let manager = harness.actor.epoch_manager.as_mut().expect("epoch manager");
    manager.on_block_commit(2);
    assert_eq!(manager.epoch(), 1);

    let expected_epoch = harness.actor.epoch_for_height(height);
    assert_eq!(expected_epoch, 0);
    let topology =
        super::network_topology::Topology::new(harness.actor.effective_commit_topology());

    let _ = harness.background_rx.try_iter().count();
    harness.actor.init_collector_plan(&topology, height, view);

    let advert = harness
        .background_rx
        .try_iter()
        .find_map(|post| match post {
            BackgroundPost::Broadcast { msg, .. } => match msg.as_ref() {
                BlockMessage::ConsensusParams(advert) => Some(*advert),
                _ => None,
            },
            _ => None,
        })
        .expect("consensus params broadcast");
    let membership = advert.membership.expect("membership payload");
    assert_eq!(membership.height, height);
    assert_eq!(membership.view, view);
    assert_eq!(membership.epoch, expected_epoch);
    let expected_hash = super::compute_membership_view_hash(
        &harness.actor.chain_id,
        height,
        view,
        expected_epoch,
        topology.as_ref(),
    );
    assert_eq!(membership.view_hash, Some(expected_hash));

    harness.shutdown.send();
}

