#[tokio::test(flavor = "current_thread")]
async fn commit_qc_rehydrates_pending_from_kura() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    actor
        .kura
        .store_block(block.clone())
        .expect("block stored in kura");

    let commit_topology = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(commit_topology.clone());
    let epoch = actor.epoch_for_height(height);
    let signers: BTreeSet<ValidatorIndex> = (0..commit_topology.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, commit_topology.len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        0,
        epoch,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );

    assert!(
        !actor.pending.pending_blocks.contains_key(&block_hash),
        "pending should start empty"
    );
    assert!(
        actor.rehydrate_pending_from_kura_for_qc(&qc),
        "commit QC should rehydrate pending from kura"
    );
    let pending = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending rehydrated");
    assert_eq!(pending.height, height);
    assert_eq!(pending.view, 0);
    assert!(
        pending.kura_persisted,
        "rehydrated pending is already persisted"
    );
    assert!(
        pending.commit_qc_observed(),
        "rehydrated pending should mark commit certificate seen"
    );
    assert_eq!(
        pending.commit_qc_epoch,
        Some(epoch),
        "rehydrated pending should record commit epoch"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_qc_revives_aborted_pending_block() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    drop(view);

    let parent =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x77; Hash::LENGTH]));
    let block = sample_block(height, 0, Some(parent));
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block, payload_hash, height, 0);
    pending.mark_aborted();
    actor.pending.pending_blocks.insert(block_hash, pending);

    assert!(
        !actor.block_known_locally(block_hash),
        "aborted pending block should not be known before commit QC"
    );

    let commit_topology = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(commit_topology.clone());
    let epoch = actor.epoch_for_height(height);
    let signers: BTreeSet<ValidatorIndex> = (0..commit_topology.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, commit_topology.len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        0,
        epoch,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_qc(qc).expect("commit QC should be handled");

    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending retained");
    assert!(
        !pending_after.aborted,
        "commit QC should revive aborted pending payload"
    );
    assert!(
        pending_after.commit_qc_observed(),
        "commit QC should be recorded on aborted pending payload"
    );
    assert_eq!(
        pending_after.commit_qc_epoch,
        Some(epoch),
        "commit QC epoch should be tracked for aborted pending payload"
    );
    assert!(
        actor.block_known_locally(block_hash),
        "revived pending payload should become known for consensus after commit QC"
    );
    assert!(
        actor.block_payload_available_locally(block_hash),
        "revived pending payload should remain locally available after commit QC"
    );

    harness.shutdown.send();
}

#[test]
fn non_rbc_payload_budget_respects_frame_cap_when_unset() {
    let frame_cap: usize = 1024 * 1024;
    let expected = frame_cap.saturating_sub(super::NON_RBC_FRAME_HEADROOM_BYTES);
    assert_eq!(
        super::non_rbc_payload_budget(None, frame_cap),
        expected,
        "default budget should honor the consensus frame cap headroom"
    );
}

#[test]
fn non_rbc_payload_budget_clamps_to_lower_of_config_and_cap() {
    let frame_cap: usize = 256 * 1024;
    let config_budget = nonzero_ext::nonzero!(64_000usize);
    assert_eq!(
        super::non_rbc_payload_budget(Some(config_budget), frame_cap),
        config_budget.get(),
        "explicit config below cap should be preserved"
    );

    let config_above_cap = nonzero_ext::nonzero!(512 * 1024usize);
    let expected = frame_cap.saturating_sub(super::NON_RBC_FRAME_HEADROOM_BYTES);
    assert_eq!(
        super::non_rbc_payload_budget(Some(config_above_cap), frame_cap),
        expected,
        "config above cap should be clamped to frame limit"
    );
}

#[tokio::test(flavor = "current_thread")]
async fn consensus_frame_caps_are_plaintext_and_rbc_chunk_is_clamped() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.rbc.chunk_max_bytes = 1024 * 1024;
    let configured_chunk_max_bytes = consensus_cfg.rbc.chunk_max_bytes;
    let mut harness = test_actor_harness_with_config(1, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let encrypted_cap =
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_CONSENSUS.get();
    let expected_cap = iroha_p2p::frame_plaintext_cap(encrypted_cap);
    assert_eq!(
        actor.consensus_frame_cap, expected_cap,
        "consensus frame cap should use plaintext bytes"
    );
    let encrypted_payload_cap =
        iroha_config::parameters::defaults::network::MAX_FRAME_BYTES_BLOCK_SYNC.get();
    let expected_payload_cap = iroha_p2p::frame_plaintext_cap(encrypted_payload_cap);
    assert_eq!(
        actor.consensus_payload_frame_cap, expected_payload_cap,
        "consensus payload frame cap should use plaintext bytes"
    );
    let expected_chunk_cap =
        super::rbc_chunk_payload_cap(actor.common_config.peer.id(), expected_payload_cap);
    let expected_chunk_max_bytes = configured_chunk_max_bytes.min(expected_chunk_cap);
    assert_eq!(
        actor.config.rbc.chunk_max_bytes, expected_chunk_max_bytes,
        "RBC chunk size should honor the consensus payload cap"
    );
    let chunk = sample_chunk_with_len(0, actor.config.rbc.chunk_max_bytes);
    assert!(
        super::consensus_block_wire_len(
            actor.common_config.peer.id(),
            &BlockMessage::RbcChunk(chunk)
        ) <= actor.consensus_payload_frame_cap,
        "RBC chunk should fit within consensus payload cap"
    );

    harness.shutdown.send();
}

