#[tokio::test(flavor = "current_thread")]
async fn sidecar_noncanonical_mismatch_retargets_missing_request_to_canonical_hash() {
    let (kura, _kura_dir) = persistent_kura_for_tests();
    let mut harness = test_actor_harness_with_config_and_height_and_kura(
        4,
        test_sumeragi_config(),
        None,
        0,
        Arc::clone(&kura),
    )
    .await;
    let actor = &mut harness.actor;
    let committed_height = u64::try_from(actor.state.committed_height()).unwrap_or(u64::MAX);
    let height = committed_height.saturating_add(1).max(1);
    let parent_hash = actor.state.view().latest_block_hash();
    let canonical_block =
        nonempty_block_for_actor(actor, &harness.key_pairs, height, 0, parent_hash);
    let canonical_hash = canonical_block.hash();
    actor
        .kura
        .store_block(canonical_block.clone())
        .expect("store canonical block");
    actor
        .kura
        .write_roster_metadata(&crate::kura::RosterSidecar::new(
            height,
            canonical_hash,
            None,
            None,
            None,
        ));

    let pending_hash = insert_validated_pending(actor, canonical_block);
    let expected_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE3; Hash::LENGTH]));
    assert_ne!(
        expected_hash, canonical_hash,
        "test requires distinct non-canonical and canonical hashes"
    );
    let now = Instant::now();
    actor.pending.missing_block_requests.insert(
        expected_hash,
        super::MissingBlockRequest {
            height,
            view: 0,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window: Duration::from_millis(1),
            view_change_window: Some(Duration::from_millis(2)),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );
    assert!(
        actor
            .pending
            .missing_block_requests
            .iter()
            .any(|(hash, request)| {
                request.height == height && !actor.block_payload_available_locally(*hash)
            }),
        "test setup should track an unresolved frontier missing-block request"
    );
    actor.sidecar_mismatch_recovery.remove(&height);
    actor.frontier_catchup_stall = None;
    actor.canonical_frontier_reanchor_window_gates.clear();
    actor.sidecar_observation_suppression_depth = 0;
    let local_height = actor.committed_height_snapshot();
    let allow_frontier_sidecar_retarget = actor
        .should_retarget_contiguous_frontier_missing_request_to_sidecar_hint(height, local_height);
    assert!(
        allow_frontier_sidecar_retarget,
        "baseline frontier sidecar retarget test requires retarget gate to be open"
    );
    assert!(
        !actor.sidecar_quarantined_for_height(height),
        "baseline frontier sidecar retarget test requires non-quarantined height state"
    );

    actor.observe_sidecar_mismatch_for_height(
        height,
        expected_hash,
        "test_sidecar_noncanonical_retarget",
    );

    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&expected_hash),
        "non-canonical missing request must be removed once canonical sidecar hash is known"
    );
    let request = actor
        .pending
        .missing_block_requests
        .get(&canonical_hash)
        .expect("canonical missing request should be scheduled");
    assert_eq!(request.height, height);
    assert!(
        !actor.pending.pending_blocks.contains_key(&pending_hash),
        "stale pending blocks at the retargeted height must be pruned"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn sidecar_mismatch_final_drop_trips_after_retry_cap() {
    let mut harness = test_actor_harness_with_config(1, test_sumeragi_config(), None).await;
    let actor = &mut harness.actor;
    let height = u64::try_from(actor.state.committed_height())
        .unwrap_or(u64::MAX)
        .saturating_add(3);
    let stored_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA2; Hash::LENGTH]));
    let expected_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA3; Hash::LENGTH]));
    let before = status::snapshot();

    let retry_cap = actor.recovery_sidecar_mismatch_retry_cap();
    for attempt in 0..retry_cap {
        actor.note_sidecar_mismatch(
            height,
            expected_hash,
            stored_hash,
            if attempt + 1 == retry_cap {
                "test_sidecar_mismatch_last"
            } else {
                "test_sidecar_mismatch"
            },
        );
    }

    let entry = actor
        .sidecar_mismatch_recovery
        .get(&height)
        .copied()
        .expect("sidecar mismatch entry should be tracked");
    assert!(entry.quarantined, "mismatch should quarantine sidecar");
    assert!(
        entry.final_dropped,
        "retry cap should trigger deterministic sidecar final-drop state"
    );
    assert!(
        !entry.canonical_rebuild_inflight,
        "final-drop should complete canonical rebuild scheduling for this sidecar"
    );
    let after = status::snapshot();
    assert!(
        after.consensus_sidecar_quarantine_total
            >= before.consensus_sidecar_quarantine_total.saturating_add(1)
    );
    assert!(
        after.consensus_sidecar_final_drop_total
            >= before.consensus_sidecar_final_drop_total.saturating_add(1)
    );

    harness.shutdown.send();
}

