#[test]
fn block_sync_update_certified_builder_skips_uncertified_roster_fallback() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();
    let kura = Arc::new(Kura::blank_kura_for_testing());

    let (me_peer, me_pop, kp) = bls_peer("127.0.0.1:7097");
    let mut pops = BTreeMap::new();
    pops.insert(me_peer.id().public_key().clone(), me_pop);
    let trusted = trusted_with_pops(me_peer.clone(), Vec::new(), pops);
    let state = state_with_peers_and_keys(
        std::slice::from_ref(me_peer.id()),
        std::slice::from_ref(&kp),
    );

    let header = BlockHeader::new(nonzero!(9_u64), None, None, None, 0, 0);
    let block_hash = header.hash();
    let block = SignedBlock::presigned(
        BlockSignature::new(0, SignatureOf::from_hash(kp.private_key(), block_hash)),
        header,
        Vec::new(),
    );

    let roster_cache = roster_cache_for_state(&state, EPOCH_LENGTH_BLOCKS);
    let permissive = super::block_sync_update_with_roster(
        &block,
        &state,
        &kura,
        ConsensusMode::Npos,
        &trusted,
        me_peer.id(),
        &roster_cache,
    );
    let certified_only = super::block_sync_update_with_certified_roster(
        &block,
        &state,
        &kura,
        ConsensusMode::Npos,
        &roster_cache,
    );

    assert!(permissive.commit_qc.is_none());
    assert!(permissive.validator_checkpoint.is_none());
    assert!(
        permissive.stake_snapshot.is_some(),
        "permissive builder may carry uncertified stake snapshot fallback"
    );

    assert!(certified_only.commit_qc.is_none());
    assert!(certified_only.validator_checkpoint.is_none());
    assert!(
        certified_only.stake_snapshot.is_none(),
        "certified builder must not synthesize uncertified roster hints"
    );
}

#[test]
fn roster_validation_inputs_from_state_collects_pops_for_roster() {
    let kp1 = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp2 = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let peer1 = PeerId::new(kp1.public_key().clone());
    let peer2 = PeerId::new(kp2.public_key().clone());
    let peers = vec![peer1.clone(), peer2.clone()];
    let keys = vec![kp1, kp2];
    let state = state_with_peers_and_keys(&peers, &keys);
    let view = state.view();

    let inputs =
        roster_validation_inputs_for_view(view.world(), &peers, ConsensusMode::Permissioned, None);

    assert!(inputs.stake_snapshot.is_none());
    assert_eq!(inputs.pops.len(), peers.len());
    assert!(inputs.pops.contains_key(peer1.public_key()));
    assert!(inputs.pops.contains_key(peer2.public_key()));
}

#[test]
fn roster_validation_cache_merges_fallback_pops() {
    let (peer, pop, _kp) = bls_peer("127.0.0.1:7099");
    let state = State::new_for_testing(
        World::default(),
        Kura::blank_kura_for_testing(),
        LiveQueryStore::start_test(),
    );
    let view = state.world.view();
    let mut fallback_pops = BTreeMap::new();
    fallback_pops.insert(peer.id().public_key().clone(), pop.clone());
    let cache =
        super::RosterValidationCache::from_world(&view, EPOCH_LENGTH_BLOCKS, Some(&fallback_pops));
    assert_eq!(cache.pops.get(peer.id().public_key()), Some(&pop));
}

#[test]
fn validate_commit_qc_roster_accepts_valid_cert() {
    let kp = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let peer = PeerId::new(kp.public_key().clone());
    let chain: ChainId = "commit-cert-valid".parse().expect("chain id parses");
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xC2; Hash::LENGTH]));
    let topology = super::network_topology::Topology::new(vec![peer.clone()]);
    let keypairs = vec![kp.clone()];
    let world = world_with_consensus_keys(topology.as_ref(), &keypairs);
    let world_view = world.view();
    let signers_bitmap = vec![0b0000_0001];
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        1,
        0,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let cert = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 1,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&vec![peer.clone()]),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: vec![peer.clone()],
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };

    let inputs = roster_validation_inputs_for_view(
        &world_view,
        &cert.validator_set,
        ConsensusMode::Permissioned,
        None,
    );
    let roster = super::validate_commit_qc_roster(
        &cert,
        block_hash,
        cert.height,
        Some(cert.view),
        iroha_config::parameters::actual::ConsensusMode::Permissioned,
        cert.epoch,
        &chain,
        PERMISSIONED_TAG,
        false,
        &inputs,
    )
    .expect("valid cert roster");
    assert_eq!(roster, vec![peer]);
}

