#[test]
fn selection_from_roster_artifacts_uses_commit_cert_epoch_for_checkpoint() {
    use iroha_data_model::parameter::system::SumeragiNposParameters;

    let keypairs = [
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
    ];
    let roster: Vec<PeerId> = keypairs
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect();
    let state = state_with_peers(roster.clone());

    {
        let mut block = state.world.block();
        let params = block.parameters.get_mut();
        let npos_params = SumeragiNposParameters {
            epoch_length_blocks: 4,
            ..SumeragiNposParameters::default()
        };
        params.custom.insert(
            SumeragiNposParameters::parameter_id(),
            npos_params.into_custom_parameter(),
        );
        block.commit();
    }

    let height = 12_u64;
    let view = 0_u64;
    let roster_cache = roster_cache_for_state(&state, EPOCH_LENGTH_BLOCKS);
    let epoch = roster_cache.expected_epoch(height, ConsensusMode::Npos);
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE1; Hash::LENGTH]));
    let topology = super::network_topology::Topology::new(roster.clone());
    let signers: BTreeSet<ValidatorIndex> = [0_usize, 1]
        .into_iter()
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, roster.len());
    let aggregate_signature = aggregate_signature_for_bitmap(
        &state.chain_id,
        super::NPOS_TAG,
        Phase::Commit,
        block_hash,
        height,
        view,
        epoch,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &state.chain_id,
        super::NPOS_TAG,
        block_hash,
        height,
        view,
        epoch,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        mode_tag: super::NPOS_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature: aggregate_signature.clone(),
        },
    };
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        roster.clone(),
        signers_bitmap.clone(),
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    let stake_snapshot =
        super::stake_snapshot::CommitStakeSnapshot::from_roster(state.view().world(), &roster)
            .expect("stake snapshot");

    let selection = super::selection_from_roster_artifacts(
        Some(&commit_qc),
        Some(&checkpoint),
        Some(&stake_snapshot),
        block_hash,
        height,
        Some(view),
        super::BlockSyncRosterSource::CommitCheckpointPairHint,
        ConsensusMode::Npos,
        &state.chain_id,
        super::NPOS_TAG,
        &roster_cache,
    )
    .expect("selection should succeed");

    assert_eq!(selection.roster, roster);
    assert!(
        selection.checkpoint.is_some(),
        "checkpoint should validate using commit certificate epoch"
    );
}

#[test]
fn synthesize_commit_qc_accepts_valid_roster() {
    let _guard = status::commit_history_test_guard();
    status::reset_commit_certs_for_tests();
    status::reset_precommit_signer_history_for_tests();

    let (peer, _pop, kp) = bls_peer("127.0.0.1:7090");
    let roster = vec![peer.id().clone()];
    let block: SignedBlock = ValidBlock::new_dummy_and_modify_header(kp.private_key(), |header| {
        header.set_height(nonzero!(1_u64));
    })
    .into();
    let state = state_with_peers(roster.clone());
    let height = block.header().height().get();
    let view = block.header().view_change_index();
    let signers = BTreeSet::from([0]);
    let cert = super::derive_block_sync_qc_from_signers(
        block.hash(),
        height,
        view,
        0,
        zero_state_root(),
        zero_state_root(),
        &roster,
        ConsensusMode::Permissioned,
        None,
        PERMISSIONED_TAG,
        &signers,
        vec![0xAB; 96],
    )
    .expect("qc derived");
    status::record_commit_qc(cert);

    let (cert, _stake_snapshot) = super::Actor::synthesize_commit_qc(
        &state,
        &block,
        &roster,
        PERMISSIONED_TAG,
        0,
        iroha_config::parameters::actual::ConsensusMode::Permissioned,
    )
    .expect("certificate should be synthesized");

    assert_eq!(cert.validator_set, roster);
    assert_eq!(cert.subject_block_hash, block.hash());

    status::reset_precommit_signer_history_for_tests();
    status::reset_commit_certs_for_tests();
}

