#[test]
fn touch_missing_block_request_retries_after_window() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAB; 32]));
    let height = 7;
    let window = Duration::from_millis(50);
    let now = Instant::now();

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        now,
        window,
        Some(window)
    ));
    assert_eq!(requests.len(), 1);
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        now,
        window,
        Some(window)
    ));

    let entry = requests.get_mut(&hash).expect("entry exists");
    let earlier = now
        .checked_sub(window + window)
        .expect("instant can move backwards for test");
    entry.last_requested = earlier;
    let later = now + window + window;

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        later,
        window,
        Some(window)
    ));
    let updated = requests.get(&hash).expect("entry exists");
    assert_eq!(updated.last_requested, later);
}

#[test]
fn touch_missing_block_request_preserves_first_seen_and_last_requested_on_backoff() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCD; 32]));
    let height = 4;
    let window = Duration::from_millis(25);
    let start = Instant::now();

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        start,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    let first_seen = stats.first_seen;
    let last_requested = stats.last_requested;

    // Retry before the window elapses should not mutate timestamps or trigger a request.
    let mid = start + Duration::from_millis(10);
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        mid,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.first_seen, first_seen);
    assert_eq!(stats.last_requested, last_requested);

    // After the window, the retry should update last_requested while keeping first_seen.
    let retry = start + window + Duration::from_millis(1);
    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        retry,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.first_seen, first_seen);
    assert_eq!(stats.last_requested, retry);
}

#[test]
fn touch_missing_block_request_ignores_conflicting_height_for_same_hash() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCC; 32]));
    let window = Duration::from_millis(30);
    let start = Instant::now();

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        2,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        start,
        window,
        Some(window)
    ));
    let conflicting_update = start + Duration::from_millis(5);
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        9,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        conflicting_update,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.height, 2);
    assert_eq!(stats.first_seen, start);
    assert_eq!(stats.last_requested, start);

    let retry_at = start + window + Duration::from_millis(1);
    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        9,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        retry_at,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.height, 2);
    assert_eq!(stats.first_seen, start);
    assert_eq!(stats.last_requested, retry_at);
}

#[test]
fn touch_missing_block_request_control_activity_updates_only_last_requested() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCB; 32]));
    let now = Instant::now();
    let stale = now
        .checked_sub(Duration::from_secs(1))
        .expect("instant can move backwards for test");
    requests.insert(
        hash,
        super::MissingBlockRequest {
            height: 3,
            view: 0,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window: Duration::from_millis(5),
            view_change_window: Some(Duration::from_millis(10)),
            first_seen: stale,
            last_requested: stale,
            last_dependency_progress: stale,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 1,
        },
    );

    assert!(super::touch_missing_block_request_control_activity(
        &mut requests,
        hash,
        3,
        now
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(
        stats.last_requested, now,
        "control activity should refresh the last-requested timestamp"
    );
    assert_eq!(
        stats.last_dependency_progress, stale,
        "control activity should not mutate dependency-progress timestamps"
    );

    assert!(!super::touch_missing_block_request_control_activity(
        &mut requests,
        hash,
        4,
        now + Duration::from_millis(1)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(
        stats.last_requested, now,
        "conflicting height should not mutate last-requested timestamps"
    );
}

#[test]
fn touch_missing_block_request_prefers_consensus_priority_windows() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCE; 32]));
    let now = Instant::now();
    let background_retry = Duration::from_millis(10);
    let consensus_retry = Duration::from_millis(40);
    let background_view_change = Duration::from_millis(20);
    let consensus_view_change = Duration::from_millis(60);

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        4,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Background,
        now,
        background_retry,
        Some(background_view_change)
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.priority, super::MissingBlockPriority::Background);

    let upgraded = now + Duration::from_millis(1);
    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        4,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        upgraded,
        consensus_retry,
        Some(consensus_view_change),
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.priority, super::MissingBlockPriority::Consensus);
    assert_eq!(stats.retry_window, consensus_retry);
    assert_eq!(stats.view_change_window, Some(consensus_view_change));

    let lower = upgraded + Duration::from_millis(1);
    super::touch_missing_block_request(
        &mut requests,
        hash,
        4,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Background,
        lower,
        Duration::from_millis(5),
        Some(Duration::from_millis(5)),
    );
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.priority, super::MissingBlockPriority::Consensus);
    assert_eq!(stats.retry_window, consensus_retry);
    assert_eq!(stats.view_change_window, Some(consensus_view_change));
}

#[test]
fn touch_missing_block_request_keeps_widened_retry_window_after_attempts() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCF; 32]));
    let now = Instant::now();
    let aggressive_retry = Duration::from_millis(25);
    let widened_retry = Duration::from_millis(100);

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        5,
        1,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        now,
        aggressive_retry,
        Some(aggressive_retry),
    ));
    {
        let stats = requests.get_mut(&hash).expect("entry exists");
        stats.attempts = 1;
    }

    // Once requests are in flight, equal-priority touches should be able to relax the retry
    // window instead of collapsing back to the aggressive floor.
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        5,
        1,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        now + Duration::from_millis(1),
        widened_retry,
        Some(widened_retry),
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.retry_window, widened_retry);

    // Subsequent equal-priority touches must not shrink a widened retry window.
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        5,
        1,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        now + Duration::from_millis(2),
        aggressive_retry,
        Some(aggressive_retry),
    ));
    let stats = requests.get(&hash).expect("entry exists");
    assert_eq!(stats.retry_window, widened_retry);
}

#[test]
fn clear_missing_block_request_resets_retry_window() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xDA; 32]));
    let height = 9;
    let window = Duration::from_millis(100);
    let start = Instant::now();

    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        start,
        window,
        Some(window)
    ));
    assert!(!super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        start + Duration::from_millis(10),
        window,
        Some(window)
    ));

    super::clear_missing_block_request(&mut requests, &hash);
    assert!(requests.is_empty(), "clearing must drop the request entry");

    let retry_instant = start + Duration::from_millis(20);
    assert!(super::touch_missing_block_request(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        retry_instant,
        window,
        Some(window)
    ));
    let stats = requests.get(&hash).expect("entry exists after re-insert");
    assert_eq!(stats.first_seen, retry_instant);
    assert_eq!(stats.last_requested, retry_instant);
}

