#[tokio::test(flavor = "current_thread")]
async fn retry_missing_block_requests_uses_commit_roster_snapshot_without_validation() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let height = 12_u64;
    let view = 0_u64;
    let epoch = actor.epoch_for_height(height);
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty(), "test requires commit roster");
    let topology = super::network_topology::Topology::new(roster.clone());
    let required = topology.min_votes_for_commit().max(1);
    let mut signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        if signers.len() >= required {
            break;
        }
        signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx fits"))
                .expect("signer idx fits"),
        );
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xD3; Hash::LENGTH]));
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        qc.parent_state_root,
        qc.post_state_root,
        roster,
        signers_bitmap,
        qc.aggregate.bls_aggregate_signature.clone(),
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut journal = state.commit_roster_journal.write();
        journal.upsert(qc, checkpoint, None);
    }

    actor.roster_validation_cache.pops.clear();

    let retry_window = Duration::from_millis(10);
    let now = Instant::now();
    let last_requested = now - retry_window - Duration::from_millis(1);
    actor.pending.missing_block_requests.insert(
        block_hash,
        super::MissingBlockRequest {
            height,
            view,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window,
            view_change_window: Some(retry_window),
            first_seen: last_requested,
            last_requested,
            last_dependency_progress: last_requested,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );

    let progress = actor.retry_missing_block_requests(now, None);
    assert!(
        progress,
        "retry should proceed using local commit roster snapshot"
    );
    let stats = actor
        .pending
        .missing_block_requests
        .get(&block_hash)
        .expect("request entry retained");
    assert!(stats.attempts > 0, "retry should record an attempt");

    harness.shutdown.send();
}

#[test]
fn plan_missing_block_fetch_respects_backoff_window() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xF1; 32]));
    let height = 8;
    let window = Duration::from_millis(20);
    let now = Instant::now();

    let peer = PeerId::new(KeyPair::random().public_key().clone());
    let topology = super::network_topology::Topology::new(vec![peer]);
    let signers = BTreeSet::new();

    let first = super::plan_missing_block_fetch(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        &signers,
        &topology,
        now,
        window,
        Some(window),
        default_missing_block_signer_fallback_attempts(),
    );
    assert!(
        matches!(first, super::MissingBlockFetchDecision::Requested { .. }),
        "first request should be issued immediately"
    );
    let last_requested = requests.get(&hash).expect("entry present").last_requested;
    let attempts = requests.get(&hash).expect("entry present").attempts;

    let decision = super::plan_missing_block_fetch(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        &signers,
        &topology,
        now + Duration::from_millis(5),
        window,
        Some(window),
        default_missing_block_signer_fallback_attempts(),
    );
    assert_eq!(decision, super::MissingBlockFetchDecision::Backoff);
    let updated = requests
        .get(&hash)
        .expect("entry still present")
        .last_requested;
    assert_eq!(
        updated, last_requested,
        "backoff should not refresh last_requested timestamp"
    );
    assert_eq!(
        requests.get(&hash).expect("entry still present").attempts,
        attempts,
        "backoff should not increment attempts while retry window is active"
    );
}

#[test]
fn plan_missing_block_fetch_falls_back_to_commit_topology() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xF3; 32]));
    let height = 4;
    let window = Duration::from_millis(10);
    let now = Instant::now();

    let peers = vec![
        PeerId::new(KeyPair::random().public_key().clone()),
        PeerId::new(KeyPair::random().public_key().clone()),
    ];
    let topology = super::network_topology::Topology::new(peers.clone());
    let signers = BTreeSet::new();

    match super::plan_missing_block_fetch(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        &signers,
        &topology,
        now,
        window,
        Some(window),
        default_missing_block_signer_fallback_attempts(),
    ) {
        super::MissingBlockFetchDecision::Requested {
            targets,
            target_kind,
        } => {
            assert_eq!(
                targets, peers,
                "missing-block fetch should fall back to the full commit topology when no signer targets are available"
            );
            assert_eq!(
                target_kind,
                crate::telemetry::MissingBlockFetchTargetKind::Topology
            );
        }
        other => panic!("expected fetch request using commit topology, got {other:?}"),
    }
}

#[test]
fn plan_missing_block_fetch_falls_back_after_signer_attempts() {
    let mut requests = BTreeMap::new();
    let hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xF4; 32]));
    let height = 6;
    let window = Duration::from_millis(10);
    let now = Instant::now();

    let peers = vec![
        PeerId::new(KeyPair::random().public_key().clone()),
        PeerId::new(KeyPair::random().public_key().clone()),
    ];
    let topology = super::network_topology::Topology::new(peers.clone());
    let mut signers = BTreeSet::new();
    signers.insert(ValidatorIndex::from(0u16));

    let fallback_after = 1;
    requests.insert(
        hash,
        super::MissingBlockRequest {
            height,
            view: 0,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window: window,
            view_change_window: Some(window),
            first_seen: now - window,
            last_requested: now - window,
            last_dependency_progress: now - window,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: fallback_after,
        },
    );

    match super::plan_missing_block_fetch(
        &mut requests,
        hash,
        height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        &signers,
        &topology,
        now,
        window,
        Some(window),
        fallback_after,
    ) {
        super::MissingBlockFetchDecision::Requested {
            targets,
            target_kind,
        } => {
            assert_eq!(
                targets, peers,
                "missing-block fetch should fall back to full topology after signer attempts"
            );
            assert_eq!(
                target_kind,
                crate::telemetry::MissingBlockFetchTargetKind::Topology
            );
        }
        other => panic!("expected fetch request using commit topology, got {other:?}"),
    }

    let stats = requests.get(&hash).expect("request entry recorded");
    assert_eq!(
        stats.attempts,
        fallback_after.saturating_add(1),
        "fallback request should bump attempt counter"
    );
}

