async fn trigger_view_change_realigns_conflicting_committed_edge_qcs_before_new_view_vote() {
    let mut harness =
        test_actor_harness_with_config_and_height(4, test_sumeragi_config(), None, 2).await;
    let _guard = super::status::view_change_proof_test_guard();
    let actor = &mut harness.actor;

    let committed_height = actor.committed_height_snapshot();
    let committed_qc = actor
        .latest_committed_qc()
        .expect("test setup should have committed QC at the tip");
    let committed_hash = actor
        .committed_block_hash_for_height(committed_height)
        .expect("committed tip hash should be available");
    let conflicting_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE3; Hash::LENGTH]));
    assert_ne!(
        conflicting_hash, committed_hash,
        "test setup requires a conflicting committed-edge subject hash"
    );

    actor.highest_qc = Some(QcHeaderRef {
        height: committed_height,
        view: committed_qc.view.saturating_add(7),
        epoch: committed_qc.epoch,
        subject_block_hash: conflicting_hash,
        phase: Phase::Commit,
    });
    actor.locked_qc = Some(QcHeaderRef {
        height: committed_height,
        view: committed_qc.view.saturating_add(3),
        epoch: committed_qc.epoch,
        subject_block_hash: conflicting_hash,
        phase: Phase::Commit,
    });

    let height = committed_height.saturating_add(1);
    let current_view = 2u64;
    actor
        .phase_tracker
        .on_view_change(height, current_view, Instant::now());

    actor.trigger_view_change_with_cause(
        height,
        current_view,
        super::ViewChangeCause::QuorumTimeout,
    );

    let highest_after = actor
        .highest_qc
        .expect("highest QC should remain available after realignment");
    assert_eq!(
        highest_after.subject_block_hash, committed_hash,
        "view-change trigger should realign conflicting highest QC to committed edge"
    );
    assert_eq!(
        highest_after.height, committed_qc.height,
        "realigned highest QC should match committed height"
    );

    let locked_after = actor
        .locked_qc
        .expect("locked QC should remain available after realignment");
    assert_eq!(
        locked_after.subject_block_hash, committed_hash,
        "view-change trigger should realign conflicting locked QC to committed edge"
    );
    assert_eq!(
        locked_after.height, committed_qc.height,
        "realigned locked QC should match committed height"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn trigger_view_change_retains_aborted_pending_payloads_with_da() {
    let mut harness = test_actor_harness(4).await;
    let _guard = super::status::view_change_proof_test_guard();
    let actor = &mut harness.actor;

    let height = 3u64;
    let current_view = 2u64;
    actor
        .phase_tracker
        .on_view_change(height, current_view, Instant::now());

    let leader_kp = &harness.key_pairs[0];
    let make_block = |view| -> SignedBlock {
        super::ValidBlock::new_dummy_and_modify_header(leader_kp.private_key(), |header| {
            header.set_height(NonZeroU64::new(height).expect("height nonzero"));
            header.set_view_change_index(view);
        })
        .into()
    };

    let stale_block_0 = make_block(0);
    let stale_block_1 = make_block(1);
    let keep_block = make_block(current_view.saturating_add(1));

    let payload_hash_0 = Hash::prehashed([0x10; Hash::LENGTH]);
    let payload_hash_1 = Hash::prehashed([0x11; Hash::LENGTH]);
    let payload_hash_keep = Hash::prehashed([0x12; Hash::LENGTH]);

    actor.pending.pending_blocks.insert(
        stale_block_0.hash(),
        PendingBlock::new(stale_block_0.clone(), payload_hash_0, height, 0),
    );
    actor.pending.pending_blocks.insert(
        stale_block_1.hash(),
        PendingBlock::new(stale_block_1.clone(), payload_hash_1, height, 1),
    );
    actor.pending.pending_blocks.insert(
        keep_block.hash(),
        PendingBlock::new(
            keep_block.clone(),
            payload_hash_keep,
            height,
            current_view.saturating_add(1),
        ),
    );

    let chunk_root_0 = Hash::prehashed([0x21; Hash::LENGTH]);
    let chunk_root_1 = Hash::prehashed([0x22; Hash::LENGTH]);
    let chunk_root_keep = Hash::prehashed([0x23; Hash::LENGTH]);
    let session_0 = RbcSession::test_new(1, Some(payload_hash_0), Some(chunk_root_0), 0);
    let session_1 = RbcSession::test_new(1, Some(payload_hash_1), Some(chunk_root_1), 0);
    let session_keep = RbcSession::test_new(1, Some(payload_hash_keep), Some(chunk_root_keep), 0);
    let key_0 = (stale_block_0.hash(), height, 0);
    let key_1 = (stale_block_1.hash(), height, 1);
    let key_keep = (keep_block.hash(), height, current_view.saturating_add(1));
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key_0, session_0);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key_1, session_1);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key_keep, session_keep);

    let now = Instant::now();
    let retry_window = Duration::from_secs(1);
    let request = |view| MissingBlockRequest {
        height,
        view,
        phase: Phase::Commit,
        priority: MissingBlockPriority::Consensus,
        retry_window,
        view_change_window: Some(retry_window),
        first_seen: now,
        last_requested: now,
        last_dependency_progress: now,
        last_rbc_observed: None,
        last_view_change_triggered: None,
        view_change_triggered_view: None,
        attempts: 0,
    };
    actor
        .pending
        .missing_block_requests
        .insert(stale_block_0.hash(), request(0));
    actor
        .pending
        .missing_block_requests
        .insert(stale_block_1.hash(), request(1));
    actor
        .pending
        .missing_block_requests
        .insert(keep_block.hash(), request(current_view.saturating_add(1)));

    actor.trigger_view_change_with_cause(
        height,
        current_view,
        super::ViewChangeCause::QuorumTimeout,
    );

    let stale_pending_0 = actor
        .pending
        .pending_blocks
        .get(&stale_block_0.hash())
        .expect("stale pending block should be retained");
    assert!(
        stale_pending_0.aborted,
        "stale pending block should be aborted"
    );
    let stale_pending_1 = actor
        .pending
        .pending_blocks
        .get(&stale_block_1.hash())
        .expect("stale pending block should be retained");
    assert!(
        stale_pending_1.aborted,
        "stale pending block should be aborted"
    );
    assert!(
        actor
            .pending
            .pending_blocks
            .contains_key(&keep_block.hash()),
        "pending block for the new view should remain"
    );
    let keep_pending = actor
        .pending
        .pending_blocks
        .get(&keep_block.hash())
        .expect("pending block for the new view should remain");
    assert!(
        !keep_pending.aborted,
        "pending block for the new view should not be aborted"
    );
    assert!(
        actor.subsystems.da_rbc.rbc.sessions.contains_key(&key_0),
        "stale RBC session should remain until availability delivers"
    );
    assert!(
        actor.subsystems.da_rbc.rbc.sessions.contains_key(&key_1),
        "stale RBC session should remain until availability delivers"
    );
    assert!(
        actor.subsystems.da_rbc.rbc.sessions.contains_key(&key_keep),
        "RBC session for the new view should remain"
    );
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&stale_block_0.hash()),
        "stale missing-block request should be pruned once payload is retained locally"
    );
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&stale_block_1.hash()),
        "stale missing-block request should be pruned once payload is retained locally"
    );
    assert!(
        actor
            .pending
            .missing_block_requests
            .contains_key(&keep_block.hash()),
        "missing-block request for the new view should remain"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn prune_stale_view_state_prunes_delivered_rbc_when_payload_available() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = 3u64;
    let current_view = 2u64;
    actor
        .phase_tracker
        .on_view_change(height, current_view, Instant::now());

    let parent = actor.state.view().latest_block_hash();
    let stale_block = sample_block(height, 0, parent);
    actor
        .kura
        .store_block(stale_block.clone())
        .expect("store block");
    let payload_hash = Hash::prehashed([0x30; Hash::LENGTH]);
    let chunk_root = Hash::prehashed([0x31; Hash::LENGTH]);
    let mut session = RbcSession::test_new(1, Some(payload_hash), Some(chunk_root), 0);
    session.delivered = true;
    let key = (stale_block.hash(), height, 0);
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);

    let now = Instant::now();
    let retry_window = Duration::from_secs(1);
    actor.pending.missing_block_requests.insert(
        stale_block.hash(),
        MissingBlockRequest {
            height,
            view: 0,
            phase: Phase::Commit,
            priority: MissingBlockPriority::Consensus,
            retry_window,
            view_change_window: Some(retry_window),
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );

    actor
        .pending
        .pending_processing
        .set(Some(stale_block.hash()));

    actor.prune_stale_view_state(height, current_view.saturating_add(1));

    assert!(
        !actor.subsystems.da_rbc.rbc.sessions.contains_key(&key),
        "stale delivered RBC session should be pruned once payload is available"
    );
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&stale_block.hash()),
        "stale missing-block request should be pruned once payload is available"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn retain_rbc_sessions_after_commit_when_undelivered() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = actor
        .state
        .view()
        .height()
        .saturating_add(1)
        .try_into()
        .unwrap_or(u64::MAX);
    let view = 0_u64;
    let parent = actor.state.view().latest_block_hash();
    let block = sample_block(height, view, parent);
    let block_hash = block.hash();
    let key = Actor::session_key(&block_hash, height, view);

    let payload_hash = Hash::prehashed([0x55; Hash::LENGTH]);
    let chunk_root = Hash::prehashed([0x56; Hash::LENGTH]);
    let session = RbcSession::test_new(1, Some(payload_hash), Some(chunk_root), 0);
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);

    assert!(
        actor.should_retain_rbc_sessions_after_commit(block_hash, height),
        "undelivered RBC sessions should be retained after commit under DA"
    );

    if let Some(session) = actor.subsystems.da_rbc.rbc.sessions.get_mut(&key) {
        session.delivered = true;
    }

    assert!(
        !actor.should_retain_rbc_sessions_after_commit(block_hash, height),
        "delivered RBC sessions should not be retained after commit under DA"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn committed_rbc_cleanup_waits_for_local_delivery() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = actor
        .state
        .view()
        .height()
        .saturating_add(1)
        .try_into()
        .unwrap_or(u64::MAX);
    let view = 0_u64;
    let parent = actor.state.view().latest_block_hash();
    let block = sample_block(height, view, parent);
    let block_hash = block.hash();
    let key = Actor::session_key(&block_hash, height, view);

    let payload_hash = Hash::prehashed([0x61; Hash::LENGTH]);
    let chunk_root = Hash::prehashed([0x62; Hash::LENGTH]);
    let mut session = RbcSession::test_new(1, Some(payload_hash), Some(chunk_root), 0);
    session.test_note_chunk(0, vec![0xAB; 8], 0);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session.clone());

    assert!(
        !actor.clean_rbc_sessions_for_committed_block_if_settled(block_hash, height),
        "undelivered committed RBC sessions should be retained until delivery converges"
    );
    assert!(
        actor.subsystems.da_rbc.rbc.sessions.contains_key(&key),
        "undelivered RBC session should remain cached after committed cleanup"
    );

    session.delivered = true;
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session.clone());

    assert!(
        actor.clean_rbc_sessions_for_committed_block_if_settled(block_hash, height),
        "delivered committed RBC sessions should be purged once settled"
    );
    assert!(
        !actor.subsystems.da_rbc.rbc.sessions.contains_key(&key),
        "delivered RBC session should be removed after committed cleanup"
    );
    let summary = actor
        .subsystems
        .da_rbc
        .rbc
        .status_handle
        .get(&key)
        .expect("cleanup should retain the final RBC summary");
    assert!(
        summary.delivered,
        "retained summary should preserve delivery"
    );
    assert_eq!(
        summary.received_chunks, summary.total_chunks,
        "retained summary should preserve complete chunk accounting"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn proposals_seen_prunes_far_future_heights() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let committed_height = actor.state.view().height() as u64;
    let anchor_height = committed_height.saturating_add(1);
    let far_height = anchor_height
        .saturating_add(super::PROPOSALS_SEEN_HEIGHT_WINDOW)
        .saturating_add(1);

    actor
        .subsystems
        .propose
        .proposals_seen
        .insert((anchor_height, 0));
    actor
        .subsystems
        .propose
        .proposals_seen
        .insert((far_height, 0));

    actor.prune_proposals_seen_horizon(committed_height);

    assert!(
        actor
            .subsystems
            .propose
            .proposals_seen
            .contains(&(anchor_height, 0)),
        "entries near the active height should be retained"
    );
    assert!(
        !actor
            .subsystems
            .propose
            .proposals_seen
            .contains(&(far_height, 0)),
        "entries far above the active height should be pruned"
    );

    harness.shutdown.send();
}

