#[test]
fn idle_view_timeout_caps_no_proposal_grace() {
    let commit = Duration::from_millis(1_000);
    let propose = Duration::from_millis(750);
    assert_eq!(
        super::idle_view_timeout(false, commit, propose, false),
        commit
    );
    assert_eq!(
        super::idle_view_timeout(true, commit, propose, false),
        commit
    );
    assert_eq!(
        super::idle_view_timeout(false, commit, propose, true),
        commit.saturating_add(propose)
    );

    let commit = Duration::from_millis(5_000);
    let propose = Duration::from_millis(1_000);
    assert_eq!(
        super::idle_view_timeout(false, commit, propose, false),
        propose.saturating_mul(4)
    );
    assert_eq!(
        super::idle_view_timeout(false, commit, propose, true),
        commit.saturating_add(propose)
    );
}

#[tokio::test(flavor = "current_thread")]
async fn active_pending_blocks_len_ignores_aborted_and_nonextending() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config_and_height(4, consensus_cfg, None, 1).await;
    let actor = &mut harness.actor;

    let (tip_height, tip_hash) = {
        let view = actor.state.view();
        (
            view.height(),
            view.latest_block_hash().expect("tip hash available"),
        )
    };

    let aborted_block = sample_block(2, 1, Some(tip_hash));
    let aborted_payload = Hash::new(super::proposals::block_payload_bytes(&aborted_block));
    let mut aborted_pending = PendingBlock::new(aborted_block, aborted_payload, 2, 1);
    aborted_pending.mark_aborted();
    actor
        .pending
        .pending_blocks
        .insert(aborted_pending.block.hash(), aborted_pending);

    let nonextending_block = sample_block(3, 0, Some(tip_hash));
    let nonextending_payload =
        Hash::new(super::proposals::block_payload_bytes(&nonextending_block));
    actor.pending.pending_blocks.insert(
        nonextending_block.hash(),
        PendingBlock::new(nonextending_block, nonextending_payload, 3, 0),
    );

    let extending_block = sample_block(2, 0, Some(tip_hash));
    let extending_payload = Hash::new(super::proposals::block_payload_bytes(&extending_block));
    let extending_hash = extending_block.hash();
    actor.pending.pending_blocks.insert(
        extending_hash,
        PendingBlock::new(extending_block, extending_payload, 2, 0),
    );
    actor.note_proposal_seen(2, 0, extending_payload);

    assert_eq!(
        actor.active_pending_blocks_len_for_tip(tip_height, Some(tip_hash)),
        1
    );
    assert_eq!(actor.active_pending_blocks_len(), 1);
    assert!(actor.has_active_pending_blocks());

    actor.pending.pending_blocks.remove(&extending_hash);
    assert_eq!(
        actor.active_pending_blocks_len_for_tip(tip_height, Some(tip_hash)),
        0
    );
    assert_eq!(actor.active_pending_blocks_len(), 0);
    assert!(!actor.has_active_pending_blocks());

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn force_view_change_if_idle_records_missing_qc_and_advances_view() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.config.recovery.max_forced_proposal_attempts_per_view = 0;
    let _guard = super::status::view_change_cause_test_guard();

    super::status::reset_view_change_cause_counters_for_tests();
    super::status::reset_worker_loop_snapshot_for_tests();
    super::status::reset_worker_loop_snapshot_for_tests();

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let committed_height = actor.state.view().height() as u64;
    let highest_qc = sample_qc_ref(committed_height, 0);
    actor.highest_qc = Some(highest_qc);
    let height = super::active_round_height(
        actor.highest_qc,
        actor.latest_committed_qc(),
        committed_height,
    );
    let current_view = 0u64;
    let now = Instant::now();
    actor.subsystems.propose.last_pacemaker_attempt = Some(now);
    let timeout = super::idle_view_timeout(
        false,
        actor.commit_quorum_timeout(),
        actor.subsystems.propose.pacemaker.propose_interval,
        actor.runtime_da_enabled(),
    );
    let availability_timeout =
        actor.availability_timeout(actor.commit_quorum_timeout(), actor.runtime_da_enabled());
    let start = now
        .checked_sub(timeout + availability_timeout + Duration::from_millis(1))
        .unwrap_or(now);
    actor
        .phase_tracker
        .on_view_change(height, current_view, start);
    actor.queue_ready_since = Some(super::QueueReadySince {
        height,
        view: current_view,
        since: start,
    });
    actor
        .subsystems
        .propose
        .proposals_seen
        .insert((height, current_view));
    actor
        .subsystems
        .propose
        .proposals_seen
        .insert((height, current_view));
    actor.queue_ready_since = Some(super::QueueReadySince {
        height,
        view: current_view,
        since: start,
    });
    actor.queue_ready_since = Some(super::QueueReadySince {
        height,
        view: current_view,
        since: start,
    });
    actor.queue_ready_since = Some(super::QueueReadySince {
        height,
        view: current_view,
        since: start,
    });
    actor.subsystems.propose.proposals_seen.clear();
    actor.subsystems.propose.last_pacemaker_attempt = Some(now);

    assert!(
        actor.force_view_change_if_idle(now),
        "idle timeout should trigger a view change"
    );
    assert_eq!(
        actor.phase_tracker.current_view(height),
        Some(current_view.saturating_add(1))
    );
    assert_eq!(
        actor.subsystems.propose.forced_view_after_timeout,
        Some((height, current_view.saturating_add(1)))
    );

    let snapshot = super::status::snapshot().view_change_causes;
    assert_eq!(snapshot.missing_qc_total, 1);
    assert_eq!(snapshot.last_cause.as_deref(), Some("missing_qc"));

    super::status::reset_view_change_cause_counters_for_tests();
    super::status::reset_worker_loop_snapshot_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn force_view_change_if_idle_suppresses_missing_qc_when_matching_frontier_pending_exists() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.config.recovery.max_forced_proposal_attempts_per_view = 0;
    let _guard = super::status::view_change_cause_test_guard();

    super::status::reset_view_change_cause_counters_for_tests();

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let committed_height = actor.state.view().height() as u64;
    actor.highest_qc = Some(sample_qc_ref(committed_height, 0));
    let height = super::active_round_height(
        actor.highest_qc,
        actor.latest_committed_qc(),
        committed_height,
    );
    let current_view = 0u64;
    let now = Instant::now();
    actor.subsystems.propose.last_pacemaker_attempt = Some(now);
    let timeout = super::idle_view_timeout(
        false,
        actor.commit_quorum_timeout(),
        actor.subsystems.propose.pacemaker.propose_interval,
        actor.runtime_da_enabled(),
    );
    let initial_frontier_proposal_grace =
        super::saturating_mul_duration(actor.rebroadcast_cooldown(), 4)
            .max(Duration::from_millis(500));
    let start = now
        .checked_sub(
            timeout
                .saturating_add(initial_frontier_proposal_grace)
                .saturating_add(Duration::from_millis(1)),
        )
        .unwrap_or(now);
    actor
        .phase_tracker
        .on_view_change(height, current_view, start);
    actor.queue_ready_since = Some(super::QueueReadySince {
        height,
        view: current_view,
        since: start,
    });

    let block = sample_block(height, current_view, actor.state.view().latest_block_hash());
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block.hash(),
        PendingBlock::new(block, payload_hash, height, current_view),
    );

    let before = super::status::snapshot();
    assert!(
        !actor.force_view_change_if_idle(now),
        "idle missing_qc should stay suppressed while a matching contiguous-frontier pending block exists for the current view"
    );
    let after = super::status::snapshot();
    assert_eq!(
        actor.phase_tracker.current_view(height),
        Some(current_view),
        "suppression should keep the current view"
    );
    assert!(
        actor.subsystems.propose.forced_view_after_timeout.is_none(),
        "suppression should not install a forced-view marker"
    );
    assert_eq!(
        after.view_change_causes.missing_qc_total, before.view_change_causes.missing_qc_total,
        "suppression should not count a MissingQc rotation"
    );

    super::status::reset_view_change_cause_counters_for_tests();
    harness.shutdown.send();
}

