#[tokio::test(flavor = "current_thread")]
async fn qc_signers_for_votes_keeps_lower_view_vote_after_higher_view_vote() {
    let mut harness = test_actor_harness(3).await;
    let actor = &mut harness.actor;
    let chain = actor.common_config.chain.clone();
    let height = 1u64;
    let epoch = actor.epoch_for_height(height);
    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    assert_eq!(
        consensus_mode,
        ConsensusMode::Permissioned,
        "test assumes permissioned consensus"
    );

    let roster: Vec<PeerId> = harness
        .key_pairs
        .iter()
        .map(|keypair| PeerId::new(keypair.public_key().clone()))
        .collect();
    let topology = super::network_topology::Topology::new(roster);
    let block_hash_low =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x19; Hash::LENGTH]));
    let block_hash_high =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x1A; Hash::LENGTH]));

    let canonical_roster = super::roster::canonicalize_roster_for_mode(
        topology.as_ref().to_vec(),
        ConsensusMode::Permissioned,
    );
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let canonical_signer = ValidatorIndex::try_from(0_u32).expect("signer fits u32");

    let mut vote_low = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: block_hash_low,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: 0,
        epoch,
        highest_qc: None,
        signer: 0, // canonical signer index (mapped below)
        bls_sig: Vec::new(),
    };
    let canonical_signature_topology_low = super::topology_for_view(
        &canonical_topology,
        height,
        vote_low.view,
        mode_tag,
        prf_seed,
    );
    let view_idx_low = super::view_index_for_canonical_signer(
        canonical_signer,
        &canonical_signature_topology_low,
        &canonical_topology,
    )
    .expect("canonical signer maps to view index");
    vote_low.signer = u32::try_from(view_idx_low).expect("view index fits u32");
    sign_vote_for_view_with_seed(
        &mut vote_low,
        &chain,
        &canonical_topology,
        &harness.key_pairs,
        mode_tag,
        prf_seed,
    );

    let mut vote_high = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: block_hash_high,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: 1,
        epoch,
        highest_qc: None,
        signer: 0, // canonical signer index (mapped below)
        bls_sig: Vec::new(),
    };
    let canonical_signature_topology_high = super::topology_for_view(
        &canonical_topology,
        height,
        vote_high.view,
        mode_tag,
        prf_seed,
    );
    let view_idx_high = super::view_index_for_canonical_signer(
        canonical_signer,
        &canonical_signature_topology_high,
        &canonical_topology,
    )
    .expect("canonical signer maps to view index");
    vote_high.signer = u32::try_from(view_idx_high).expect("view index fits u32");
    sign_vote_for_view_with_seed(
        &mut vote_high,
        &chain,
        &canonical_topology,
        &harness.key_pairs,
        mode_tag,
        prf_seed,
    );

    for vote in [&vote_low, &vote_high] {
        let key = (vote.phase, vote.height, vote.view, vote.epoch, vote.signer);
        let signature_topology =
            super::topology_for_view(&topology, height, vote.view, mode_tag, prf_seed);
        let roster_hash = HashOf::new(&signature_topology.as_ref().to_vec());
        let membership_hash = HashOf::new(&super::roster::canonicalize_roster_for_mode(
            signature_topology.as_ref().to_vec(),
            consensus_mode,
        ));
        actor.vote_log.insert(key, vote.clone());
        actor.vote_validation_cache.insert(
            key,
            super::VoteValidationCacheEntry {
                roster_hash,
                membership_hash,
            },
        );
    }

    let signature_topology_low =
        super::topology_for_view(&topology, height, vote_low.view, mode_tag, prf_seed);
    let signers_low = actor.qc_signers_for_votes(
        Phase::Commit,
        block_hash_low,
        height,
        vote_low.view,
        epoch,
        &signature_topology_low,
    );
    assert!(
        signers_low.contains(&vote_low.signer),
        "lower-view vote should remain eligible for QC once validated"
    );

    let signature_topology_high =
        super::topology_for_view(&topology, height, vote_high.view, mode_tag, prf_seed);
    let signers_high = actor.qc_signers_for_votes(
        Phase::Commit,
        block_hash_high,
        height,
        vote_high.view,
        epoch,
        &signature_topology_high,
    );
    assert!(
        signers_high.contains(&vote_high.signer),
        "highest-view vote should still be counted"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn qc_signers_for_votes_does_not_ignore_lower_view_vote_from_other_peer() {
    let mut harness = test_actor_harness(3).await;
    let actor = &mut harness.actor;
    let chain = actor.common_config.chain.clone();
    let height = 1u64;
    let epoch = actor.epoch_for_height(height);
    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    assert_eq!(
        consensus_mode,
        ConsensusMode::Permissioned,
        "test assumes permissioned consensus"
    );

    let roster: Vec<PeerId> = harness
        .key_pairs
        .iter()
        .map(|keypair| PeerId::new(keypair.public_key().clone()))
        .collect();
    let topology = super::network_topology::Topology::new(roster);
    let block_hash_low =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x1B; Hash::LENGTH]));
    let block_hash_high =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x1C; Hash::LENGTH]));

    // Use the same view-specific signer index across views (leader slot). This index maps to a
    // different peer after topology rotation, so higher-view votes must not suppress lower-view
    // votes from a different validator.
    let mut vote_low = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: block_hash_low,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: 0,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view_with_seed(
        &mut vote_low,
        &chain,
        &topology,
        &harness.key_pairs,
        mode_tag,
        prf_seed,
    );

    let mut vote_high = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: block_hash_high,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: 1,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view_with_seed(
        &mut vote_high,
        &chain,
        &topology,
        &harness.key_pairs,
        mode_tag,
        prf_seed,
    );

    let signature_topology_low =
        super::topology_for_view(&topology, height, vote_low.view, mode_tag, prf_seed);
    let signature_topology_high =
        super::topology_for_view(&topology, height, vote_high.view, mode_tag, prf_seed);
    let idx = usize::try_from(vote_low.signer).expect("signer fits usize");
    let peer_low = signature_topology_low
        .as_ref()
        .get(idx)
        .cloned()
        .expect("signer present in topology");
    let peer_high = signature_topology_high
        .as_ref()
        .get(idx)
        .cloned()
        .expect("signer present in topology");
    assert_ne!(
        peer_low, peer_high,
        "test setup expects view rotation to move peers between indices"
    );

    for vote in [&vote_low, &vote_high] {
        let key = (vote.phase, vote.height, vote.view, vote.epoch, vote.signer);
        let signature_topology =
            super::topology_for_view(&topology, height, vote.view, mode_tag, prf_seed);
        let roster_hash = HashOf::new(&signature_topology.as_ref().to_vec());
        let membership_hash = HashOf::new(&super::roster::canonicalize_roster_for_mode(
            signature_topology.as_ref().to_vec(),
            consensus_mode,
        ));
        actor.vote_log.insert(key, vote.clone());
        actor.vote_validation_cache.insert(
            key,
            super::VoteValidationCacheEntry {
                roster_hash,
                membership_hash,
            },
        );
    }

    let signers_low = actor.qc_signers_for_votes(
        Phase::Commit,
        block_hash_low,
        height,
        vote_low.view,
        epoch,
        &signature_topology_low,
    );
    assert!(
        signers_low.contains(&vote_low.signer),
        "lower-view vote must not be suppressed by a higher-view vote from a different peer"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn try_form_qc_from_votes_keeps_lower_view_quorum_after_higher_view_votes() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.locked_qc = None;

    let view_state = actor.state.view();
    let height = view_state.height() as u64 + 1;
    let parent = view_state.latest_block_hash();
    drop(view_state);
    let view_low = 0u64;
    let view_high = 1u64;

    let block_low = sample_block(height, view_low, parent);
    actor
        .kura
        .store_block(block_low.clone())
        .expect("store block");
    let block_hash_low = block_low.hash();
    let block_hash_high =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x9A; Hash::LENGTH]));

    let epoch = actor.epoch_for_height(height);
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let required = topology.min_votes_for_commit();
    let chain = actor.common_config.chain.clone();
    let (consensus_mode, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    assert_eq!(
        consensus_mode,
        ConsensusMode::Permissioned,
        "test assumes permissioned consensus"
    );

    for signer in 0..required {
        let canonical_signer = u32::try_from(signer).expect("signer index fits u32");

        let mut vote_high = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash: block_hash_high,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view: view_high,
            epoch,
            highest_qc: None,
            signer: canonical_signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_canonical_signer(&mut vote_high, &chain, &topology, &harness.key_pairs);
        let signature_topology_high =
            super::topology_for_view(&topology, height, view_high, mode_tag, prf_seed);
        let roster_hash_high = HashOf::new(&signature_topology_high.as_ref().to_vec());
        let membership_hash_high = HashOf::new(&super::roster::canonicalize_roster_for_mode(
            signature_topology_high.as_ref().to_vec(),
            consensus_mode,
        ));
        let key_high = (
            vote_high.phase,
            vote_high.height,
            vote_high.view,
            vote_high.epoch,
            vote_high.signer,
        );
        actor.vote_log.insert(key_high, vote_high);
        actor.vote_validation_cache.insert(
            key_high,
            super::VoteValidationCacheEntry {
                roster_hash: roster_hash_high,
                membership_hash: membership_hash_high,
            },
        );

        let mut vote_low = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash: block_hash_low,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view: view_low,
            epoch,
            highest_qc: None,
            signer: canonical_signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_canonical_signer(&mut vote_low, &chain, &topology, &harness.key_pairs);
        let signature_topology_low =
            super::topology_for_view(&topology, height, view_low, mode_tag, prf_seed);
        let roster_hash_low = HashOf::new(&signature_topology_low.as_ref().to_vec());
        let membership_hash_low = HashOf::new(&super::roster::canonicalize_roster_for_mode(
            signature_topology_low.as_ref().to_vec(),
            consensus_mode,
        ));
        let key_low = (
            vote_low.phase,
            vote_low.height,
            vote_low.view,
            vote_low.epoch,
            vote_low.signer,
        );
        actor.vote_log.insert(key_low, vote_low);
        actor.vote_validation_cache.insert(
            key_low,
            super::VoteValidationCacheEntry {
                roster_hash: roster_hash_low,
                membership_hash: membership_hash_low,
            },
        );
    }

    actor.try_form_qc_from_votes(
        Phase::Commit,
        block_hash_low,
        height,
        view_low,
        epoch,
        &topology,
    );

    assert!(
        actor
            .qc_cache
            .contains_key(&(Phase::Commit, block_hash_low, height, view_low, epoch)),
        "lower-view commit quorum should still aggregate after higher-view votes"
    );

    harness.shutdown.send();
}

