#[tokio::test(flavor = "current_thread")]
async fn new_view_gossip_targets_excludes_sender_and_local() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    actor.block_sync_gossip_limit = 1;

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signature_topology = super::network_topology::Topology::new(topology.clone());
    let local_idx = actor
        .local_validator_index_for_topology(&signature_topology)
        .expect("local peer in topology");
    let sender = (0..topology.as_ref().len())
        .filter_map(|idx| ValidatorIndex::try_from(idx).ok())
        .find(|idx| *idx != local_idx)
        .expect("remote sender available");

    let targets = actor.new_view_gossip_targets(topology.as_ref(), Some(sender));
    assert_eq!(targets.len(), 1);
    assert!(
        !targets.contains(actor.common_config.peer.id()),
        "gossip targets should exclude the local peer"
    );
    let sender_peer = topology
        .as_ref()
        .get(usize::try_from(sender).expect("sender index fits usize"))
        .expect("sender present in topology");
    assert!(
        !targets.contains(sender_peer),
        "gossip targets should exclude the sender peer"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn new_view_votes_target_collectors_even_when_below_quorum() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let background_log: Arc<Mutex<Vec<super::BackgroundRequestLogEntry>>> =
        Arc::new(Mutex::new(Vec::new()));
    actor.background_request_log = Some(Arc::clone(&background_log));

    seed_genesis_block_for_state(&actor.state);
    while harness.background_rx.try_recv().is_ok() {}

    let committed_qc = actor.latest_committed_qc().expect("committed qc");
    let height = committed_qc.height.saturating_add(1);
    let view = 1;

    let roster = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(roster);
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let local_peer = actor.common_config.peer.id().clone();

    assert!(
        actor.emit_new_view_vote(height, view, committed_qc, &topology),
        "new view vote should be emitted"
    );

    let targets: Vec<_> = background_log
        .lock()
        .expect("background request log mutex poisoned")
        .iter()
        .filter_map(|entry| {
            if entry.kind == super::BackgroundRequestLogKind::Post
                && entry.msg_kind == Some("QcVote")
            {
                entry.peer.clone()
            } else {
                None
            }
        })
        .collect();

    let leader = signature_topology.leader().clone();
    let mut expected: Vec<_> = actor
        .subsystems
        .propose
        .collectors_contacted
        .iter()
        .cloned()
        .collect();
    let mut fallback_to_topology = false;
    expected.retain(|peer| peer != &local_peer);
    if expected.is_empty() {
        fallback_to_topology = true;
        expected = signature_topology.as_ref().to_vec();
        expected.retain(|peer| peer != &local_peer);
    }
    if expected.is_empty() {
        fallback_to_topology = true;
        expected = signature_topology.as_ref().to_vec();
        expected.retain(|peer| peer != &local_peer);
    }
    if !fallback_to_topology {
        let parallel = actor.config.collectors.parallel_topology_fanout;
        if parallel > 0 {
            let mut parallel_targets: Vec<_> = signature_topology
                .topology_fanout_from_tail(parallel)
                .into_iter()
                .filter_map(|idx| signature_topology.as_ref().get(idx).cloned())
                .collect();
            parallel_targets.retain(|peer| peer != &local_peer);
            for peer in parallel_targets {
                if !expected.contains(&peer) {
                    expected.push(peer);
                }
            }
        }
        let remote_floor = usize::from(actor.subsystems.propose.collector_redundant_limit.max(1))
            .min(signature_topology.as_ref().len().saturating_sub(1));
        if expected.len() < remote_floor {
            for peer in signature_topology.as_ref() {
                if peer == &local_peer || expected.contains(peer) {
                    continue;
                }
                expected.push(peer.clone());
                if expected.len() >= remote_floor {
                    break;
                }
            }
        }
    }
    if leader != local_peer && !expected.contains(&leader) {
        expected.push(leader);
    }
    assert_eq!(targets, expected);

    harness.shutdown.send();
}

