#[tokio::test(flavor = "current_thread")]
async fn pacemaker_keeps_new_view_entries_with_pending_txs() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let view = 1;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x27; Hash::LENGTH]));
    let highest_qc = QcHeaderRef {
        subject_block_hash: block_hash,
        height: committed_height,
        view: 0,
        epoch: 0,
        phase: Phase::Commit,
    };

    let roster = actor.effective_commit_topology();
    let peer_a = roster.get(1).cloned().expect("validator 1");
    let peer_b = roster.get(2).cloned().expect("validator 2");
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, peer_a, highest_qc);
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, peer_b, highest_qc);

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor.phase_tracker.start_new_round(tracked_height, start);
    actor
        .phase_tracker
        .on_view_change(tracked_height, view, start);

    let count_before = actor
        .subsystems
        .propose
        .new_view_tracker
        .count(tracked_height, view);
    assert_eq!(count_before, 2);

    // Use view 1 so the local node is not the leader after rotation.
    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(!proposed, "local node should not lead this view");

    let count_after = actor
        .subsystems
        .propose
        .new_view_tracker
        .count(tracked_height, view);
    assert!(
        count_after >= count_before,
        "NEW_VIEW tracker entries should survive pending tx proposals"
    );
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_requires_commit_quorum_for_new_view() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let block1 = sample_block(1, 0, None);
    actor.kura.store_block(block1.clone()).expect("store block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(block1.hash());

    let local = actor.common_config.peer.id().clone();
    let mut roster = actor.effective_commit_topology();
    assert!(roster.len() >= 3, "test requires at least three validators");
    let local_pos = roster
        .iter()
        .position(|peer| peer == &local)
        .expect("local peer in topology");
    let rotate_by = (local_pos + roster.len() - 1) % roster.len();
    roster.rotate_left(rotate_by);
    assert_eq!(
        roster.get(1),
        Some(&local),
        "local peer should occupy index 1 for view=1 leadership"
    );
    {
        let mut topo_block = actor.state.commit_topology.block();
        topo_block.mutate_vec(|vec| *vec = roster.clone());
        topo_block.commit();
    }

    actor.subsystems.propose.new_view_tracker = NewViewTracker::default();
    actor.subsystems.propose.forced_view_after_timeout = None;

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let highest_qc = QcHeaderRef {
        subject_block_hash: block1.hash(),
        height: committed_height,
        view: 0,
        epoch: 0,
        phase: Phase::Commit,
    };
    let view = 1;
    let sender = roster.get(2).cloned().expect("sender peer");
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, sender, highest_qc);

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor
        .phase_tracker
        .on_view_change(tracked_height, view, start);

    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(
        !proposed,
        "pacemaker should wait for commit quorum NEW_VIEW votes"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(tracked_height, view)
            .is_none(),
        "proposal should not be assembled without commit quorum"
    );
    assert_eq!(
        actor
            .subsystems
            .propose
            .new_view_tracker
            .count(tracked_height, view),
        1,
        "NEW_VIEW entry should remain until quorum is reached"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_rebroadcasts_new_view_votes_when_quorum_missing() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let block1 = sample_block(1, 0, None);
    actor.kura.store_block(block1.clone()).expect("store block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(block1.hash());

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let view = 1;
    let highest_qc = QcHeaderRef {
        subject_block_hash: block1.hash(),
        height: committed_height,
        view: 0,
        epoch: 0,
        phase: Phase::Commit,
    };
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let sent = actor.emit_new_view_vote(tracked_height, view, highest_qc, &topology);
    assert!(sent, "local NEW_VIEW vote should be emitted");

    let _ = harness.background_rx.try_iter().count();

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor
        .phase_tracker
        .on_view_change(tracked_height, view, start);

    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(
        !proposed,
        "pacemaker should defer when NEW_VIEW quorum is missing"
    );

    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    let new_view_posts = posts
        .iter()
        .filter(|post| match post {
            BackgroundPost::Post { msg, .. } => matches!(
                msg.as_ref(),
                BlockMessage::QcVote(vote)
                    if vote.phase == Phase::NewView
                        && vote.height == tracked_height
                        && vote.view == view
            ),
            _ => false,
        })
        .count();
    assert!(
        new_view_posts > 0,
        "expected NEW_VIEW vote rebroadcasts when quorum is missing"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_defers_proposal_when_precommit_votes_present() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let block1 = sample_block(1, 0, None);
    actor.kura.store_block(block1.clone()).expect("store block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(block1.hash());

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let mut highest_qc = actor.latest_committed_qc().unwrap_or_else(|| {
        let mut qc = sample_qc_ref(committed_height, 0);
        qc.phase = Phase::Commit;
        qc
    });
    highest_qc.phase = Phase::Commit;
    let topology_peers = actor.effective_commit_topology();
    let local_pos = topology_peers
        .iter()
        .position(|peer| peer == actor.common_config.peer.id())
        .expect("local peer in topology");
    let view = u64::try_from(local_pos).unwrap_or_default();
    let sender_a_pos = (local_pos + 1) % topology_peers.len();
    let sender_b_pos = (local_pos + 2) % topology_peers.len();
    let sender_a = topology_peers
        .get(sender_a_pos)
        .cloned()
        .expect("sender peer");
    let sender_b = topology_peers
        .get(sender_b_pos)
        .cloned()
        .expect("sender peer");
    let sender_a_idx = ValidatorIndex::try_from(sender_a_pos).expect("sender index");

    actor.subsystems.propose.new_view_tracker.record(
        tracked_height,
        view,
        sender_a.clone(),
        highest_qc,
    );
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, sender_b, highest_qc);

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor.phase_tracker.start_new_round(tracked_height, start);

    let pending_block = sample_block(tracked_height, view, Some(block1.hash()));
    let payload_bytes = super::proposals::block_payload_bytes(&pending_block);
    let payload_hash = Hash::new(&payload_bytes);
    actor.pending.pending_blocks.insert(
        pending_block.hash(),
        PendingBlock::new(pending_block.clone(), payload_hash, tracked_height, view),
    );

    let epoch = actor.current_epoch();
    let vote_hash = pending_block.hash();
    actor.vote_log.insert(
        (Phase::Commit, tracked_height, view, epoch, sender_a_idx),
        crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash: vote_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height: tracked_height,
            view,
            epoch,
            highest_qc: None,
            signer: sender_a_idx,
            bls_sig: Vec::new(),
        },
    );

    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(
        !proposed,
        "pacemaker should defer when precommit votes already exist"
    );
    assert!(
        actor.highest_qc.is_none(),
        "highest QC should remain unset when precommit votes block proposal"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(tracked_height, view)
            .is_none(),
        "proposal should not be assembled when precommit votes exist"
    );

    harness.shutdown.send();
}

