#[tokio::test(flavor = "current_thread")]
async fn pacemaker_clamps_live_height_to_local_commit_horizon() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    actor.subsystems.propose.new_view_tracker = NewViewTracker::default();
    actor.subsystems.propose.forced_view_after_timeout = None;

    let committed_height = actor.state.view().height() as u64;
    let mut ahead_qc = sample_qc_ref(committed_height.saturating_add(1), 0);
    ahead_qc.phase = Phase::Commit;
    actor.highest_qc = Some(ahead_qc);

    let desired_height = super::active_round_height(
        actor.highest_qc,
        actor.latest_committed_qc(),
        committed_height,
    );
    assert_eq!(
        desired_height,
        committed_height.saturating_add(2),
        "test setup should place pacemaker one height beyond the local commit horizon"
    );

    let (consensus_mode, _, _) = actor.consensus_context_for_height(desired_height);
    assert!(
        actor
            .roster_for_live_vote_with_mode(desired_height, consensus_mode)
            .is_empty(),
        "live roster should be unavailable beyond the local commit horizon"
    );

    let expected_height = committed_height.saturating_add(1);
    assert!(
        actor.phase_tracker.current_view(expected_height).is_none(),
        "round should not be initialized before pacemaker runs"
    );

    let now = Instant::now();
    let _ = actor.on_pacemaker_propose_ready(now);
    assert!(
        actor.phase_tracker.current_view(expected_height).is_some(),
        "pacemaker should initialize the next local height when highest QC is ahead"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_allows_proposal_with_stale_precommit_votes() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let block1 = sample_block(1, 0, None);
    actor.kura.store_block(block1.clone()).expect("store block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(block1.hash());

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let mut highest_qc = actor.latest_committed_qc().unwrap_or_else(|| {
        let mut qc = sample_qc_ref(committed_height, 0);
        qc.phase = Phase::Commit;
        qc
    });
    highest_qc.phase = Phase::Commit;
    let topology = actor.effective_commit_topology();
    let local_pos = topology
        .iter()
        .position(|peer| peer == actor.common_config.peer.id())
        .expect("local peer in topology");
    let local_idx = ValidatorIndex::try_from(local_pos).expect("local idx fits");
    let view = u64::from(local_idx);
    let sender_a_pos = (local_pos + 1) % topology.len();
    let sender_b_pos = (local_pos + 2) % topology.len();
    let sender_a = topology.get(sender_a_pos).cloned().expect("sender peer");
    let sender_b = topology.get(sender_b_pos).cloned().expect("sender peer");
    let sender_a_idx = ValidatorIndex::try_from(sender_a_pos).expect("sender index");

    actor.subsystems.propose.new_view_tracker.record(
        tracked_height,
        view,
        sender_a.clone(),
        highest_qc,
    );
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, sender_b, highest_qc);

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor.phase_tracker.start_new_round(tracked_height, start);

    let epoch = actor.current_epoch();
    let vote_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x46; Hash::LENGTH]));
    let stale_view = u64::from(view == 0);
    actor.vote_log.insert(
        (
            Phase::Commit,
            tracked_height,
            stale_view,
            epoch,
            sender_a_idx,
        ),
        crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash: vote_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height: tracked_height,
            view: stale_view,
            epoch,
            highest_qc: None,
            signer: sender_a_idx,
            bls_sig: Vec::new(),
        },
    );

    let _ = actor.on_pacemaker_propose_ready(now);
    assert!(
        actor.highest_qc == Some(highest_qc),
        "highest QC should be recorded when only stale precommit votes exist"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_does_not_fallback_to_view_zero_after_view_change() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    actor.subsystems.propose.new_view_tracker = NewViewTracker::default();
    actor.subsystems.propose.forced_view_after_timeout = None;

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = super::active_round_height(
        actor.highest_qc,
        actor.latest_committed_qc(),
        committed_height,
    );
    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    actor.phase_tracker.on_view_change(tracked_height, 2, start);

    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(tracked_height, 0)
            .is_none(),
        "proposal cache should start empty for view 0"
    );

    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(
        !proposed,
        "pacemaker should not fall back to view 0 after a view change"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(tracked_height, 0)
            .is_none(),
        "view 0 proposal must not be assembled after the view advances"
    );
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn pacemaker_ignores_stale_new_view_entries() {
    use std::borrow::Cow;

    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    actor.subsystems.propose.new_view_tracker = NewViewTracker::default();
    actor.subsystems.propose.forced_view_after_timeout = None;

    let committed_height = actor.state.view().height() as u64;
    let tracked_height = committed_height.saturating_add(1);
    let mut highest_qc = actor.latest_committed_qc().unwrap_or_else(|| {
        let mut qc = sample_qc_ref(committed_height, 0);
        qc.phase = Phase::Commit;
        qc
    });
    highest_qc.phase = Phase::Commit;
    let topology = actor.effective_commit_topology();
    let local_pos = topology
        .iter()
        .position(|peer| peer == actor.common_config.peer.id())
        .expect("local peer in topology");
    let view = u64::try_from(local_pos).unwrap_or_default();
    let sender_a = topology
        .get((local_pos + 1) % topology.len())
        .cloned()
        .expect("sender peer");
    let sender_b = topology
        .get((local_pos + 2) % topology.len())
        .cloned()
        .expect("sender peer");

    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, sender_a, highest_qc);
    actor
        .subsystems
        .propose
        .new_view_tracker
        .record(tracked_height, view, sender_b, highest_qc);

    let offline_grace = actor.commit_quorum_timeout();
    let now = Instant::now();
    let start = now
        .checked_sub(offline_grace + Duration::from_millis(1))
        .unwrap_or(now);
    let current_view = view.saturating_add(1);
    actor
        .phase_tracker
        .on_view_change(tracked_height, current_view, start);

    let proposed = actor.on_pacemaker_propose_ready(now);
    assert!(
        !proposed,
        "pacemaker should ignore NEW_VIEW entries below the current view"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(tracked_height, view)
            .is_none(),
        "stale NEW_VIEW entries must not assemble proposals"
    );
    assert_eq!(
        actor
            .subsystems
            .propose
            .new_view_tracker
            .count(tracked_height, view),
        0,
        "stale NEW_VIEW entries should be pruned"
    );
    harness.shutdown.send();
}

