#[tokio::test(flavor = "current_thread")]
async fn drop_missing_lock_if_unknown_requests_payload_and_retains_lock() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let locked_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAD; Hash::LENGTH]));
    assert!(
        !actor.block_known_locally(locked_hash),
        "test lock should be missing locally"
    );
    let lock = QcHeaderRef {
        height: 5,
        view: 0,
        epoch: 0,
        subject_block_hash: locked_hash,
        phase: Phase::Commit,
    };
    actor.locked_qc = Some(lock);
    super::status::set_locked_qc(lock.height, lock.view, Some(locked_hash));

    let roster = actor.effective_commit_topology();
    let qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed(
            [0xAE; Hash::LENGTH],
        )),
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: lock.height.saturating_add(1),
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster,
        aggregate: QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };

    actor.drop_missing_lock_if_unknown(&qc);

    let locked_after = actor.locked_qc.expect("locked qc retained");
    assert_eq!(locked_after.subject_block_hash, locked_hash);
    assert!(
        actor
            .pending
            .missing_block_requests
            .contains_key(&locked_hash),
        "missing locked payload should trigger fetch request"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn drop_missing_lock_if_unknown_suppresses_stale_frontier_conflict_as_obsolete() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_height = u64::try_from(actor.state.committed_height()).unwrap_or(u64::MAX);
    let frontier_height = committed_height.saturating_add(1);
    let locked_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAF; Hash::LENGTH]));
    let lock = QcHeaderRef {
        height: frontier_height,
        view: 0,
        epoch: actor.epoch_for_height(frontier_height),
        subject_block_hash: locked_hash,
        phase: Phase::Commit,
    };
    actor.locked_qc = Some(lock);
    super::status::set_locked_qc(lock.height, lock.view, Some(locked_hash));

    let stale_window = actor
        .recovery_missing_block_height_ttl()
        .max(actor.recovery_missing_qc_reacquire_window())
        .max(actor.rebroadcast_cooldown())
        .max(Duration::from_millis(1));
    let now = Instant::now();
    let stale_first_seen = now
        .checked_sub(stale_window.saturating_add(Duration::from_millis(25)))
        .unwrap_or(now);
    let inserted = super::touch_missing_block_request(
        &mut actor.pending.missing_block_requests,
        locked_hash,
        frontier_height,
        0,
        Phase::Commit,
        super::MissingBlockPriority::Consensus,
        stale_first_seen,
        Duration::from_millis(1),
        None,
    );
    assert!(
        inserted,
        "test setup should seed stale missing request for locked hash"
    );

    let roster = actor.effective_commit_topology();
    let incoming_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xB0; Hash::LENGTH]));
    let incoming_height = frontier_height.saturating_add(2);
    let qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: incoming_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: incoming_height,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster,
        aggregate: QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };

    let expected_reanchor = actor.state.latest_block_hash_fast().is_some()
        && !actor
            .range_pull_targets_for_height(frontier_height)
            .is_empty();

    actor.drop_missing_lock_if_unknown(&qc);

    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&locked_hash),
        "stale missing lock dependency should be cleared as obsolete"
    );
    let latest_committed_qc = actor.latest_committed_qc();
    assert_eq!(
        actor.locked_qc, latest_committed_qc,
        "stale frontier lock should realign to latest committed QC"
    );
    assert!(
        !expected_reanchor
            || actor
                .range_pull_escalation_cooldowns
                .keys()
                .any(|(_, _, height, reason)| {
                    *height == frontier_height && *reason == "round_liveness_catchup_isolated"
                }),
        "stale lock suppression should request canonical range-pull reanchor when eligible"
    );

    harness.shutdown.send();
}

#[test]
fn qc_extends_locked_if_present_rejects_conflicting_child_when_parent_known() {
    let locked = sample_qc_ref(8, 3);
    let other_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xEE; 32]));
    let highest = QcHeaderRef {
        subject_block_hash: other_hash,
        ..sample_qc_ref(9, 4)
    };
    let extends = super::qc_extends_locked_if_present(
        Some(locked),
        highest,
        |hash, _height| {
            if hash == highest.subject_block_hash {
                // Parent known but diverges.
                Some(HashOf::<BlockHeader>::from_untyped_unchecked(
                    Hash::prehashed([0xFF; 32]),
                ))
            } else {
                None
            }
        },
        |hash| hash == locked.subject_block_hash,
    );
    assert!(
        !extends,
        "divergent parent should fail extends_locked when parent known"
    );
}

#[test]
fn qc_extends_locked_if_present_rejects_non_extending_qc() {
    let locked = sample_qc_ref(5, 1);
    let highest = sample_qc_ref(7, 3);
    let mut parent_lookup_calls = 0;
    let extends = super::qc_extends_locked_if_present(
        Some(locked),
        highest,
        |_hash, _height| {
            parent_lookup_calls += 1;
            // Return unrelated parent hashes so the chain never reaches the lock.
            Some(HashOf::<BlockHeader>::from_untyped_unchecked(
                Hash::prehashed([0xBA; 32]),
            ))
        },
        |_hash| true,
    );
    assert!(!extends, "non-extending QC must be rejected");
    assert!(parent_lookup_calls > 0, "parent lookup should be attempted");
}

#[test]
fn validate_qc_against_votes_rejects_old_epoch_after_roster_change() {
    // QC built for epoch 0 with bitmap len 2, but current roster len is 3 → bitmap length mismatch.
    let chain: ChainId = "qc-roster-change".parse().expect("chain id parses");
    let peer_keys: Vec<_> = (0..3)
        .map(|_| KeyPair::random_with_algorithm(Algorithm::BlsNormal))
        .collect();
    let peers_new: Vec<PeerId> = peer_keys
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect();
    let mut topology_new = super::network_topology::Topology::new(peers_new);
    topology_new.canonicalize_order();
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x63; Hash::LENGTH]));
    let validator_set = topology_new.as_ref().to_vec();
    let qc = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 5,
        view: 2,
        epoch: 0,
        mode_tag: super::PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: vec![0b0000_0011], // valid for 2-signers roster
            bls_aggregate_signature: aggregate_signature_for_bitmap(
                &chain,
                super::PERMISSIONED_TAG,
                crate::sumeragi::consensus::Phase::Commit,
                block_hash,
                5,
                2,
                0,
                &[0b0000_0011],
                &topology_new,
                &peer_keys,
            ),
        },
    };

    // Build vote_log for the old roster.
    let mut vote_log = BTreeMap::new();
    for signer in [0u32, 1u32] {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: crate::sumeragi::consensus::Phase::Commit,
            block_hash,
            parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            height: qc.height,
            view: qc.view,
            epoch: qc.epoch,
            highest_qc: None,
            signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_canonical_signer(&mut vote, &chain, &topology_new, &peer_keys);
        vote_log.insert(
            (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
            vote,
        );
    }

    let result = validate_qc_against_votes_with_keys(
        &vote_log,
        &qc,
        &topology_new, // new roster length should invalidate bitmap length
        &peer_keys,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        None,
    );
    // New roster requires 3 votes; QC from the old roster only has 2 signers.
    assert!(matches!(
        result,
        Err(super::QcValidationError::InsufficientSigners { .. })
    ));
}

#[test]
fn validate_qc_against_votes_rejects_sparse_high_bit() {
    // Roster len 4 → expected bitmap len 1. Bit 4 is out of range.
    let chain: ChainId = "qc-sparse-high-bit".parse().expect("chain id parses");
    let keypairs: Vec<_> = (0..4)
        .map(|_| KeyPair::random_with_algorithm(Algorithm::BlsNormal))
        .collect();
    let peers: Vec<PeerId> = keypairs
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect();
    let mut topology = super::network_topology::Topology::new(peers);
    topology.canonicalize_order();
    let world = world_with_consensus_keys(topology.as_ref(), &keypairs);
    let world_view = world.view();
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x5D; Hash::LENGTH]));
    let validator_set = topology.as_ref().to_vec();
    let qc = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 4,
        view: 1,
        epoch: 0,
        mode_tag: super::PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: vec![0b0001_0000], // bit 4 set, exceeds roster len 4 (indices 0-3)
            bls_aggregate_signature: Vec::new(),
        },
    };
    let vote_log = BTreeMap::new();
    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    let result = super::validate_qc_against_votes(
        &vote_log,
        &qc,
        &topology,
        &world_view,
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        None,
        None,
    );
    assert!(
        matches!(
            result,
            Err(super::QcValidationError::SignerOutOfBounds { .. })
        ),
        "unexpected sparse-bitmap validation result: {result:?}"
    );
}

