#[test]
fn block_sync_quorum_accepts_only_explicit_contiguous_frontier_sparse_recovery() {
    let block_height = 5;
    let local_height = 4;
    assert!(
        super::block_sync_quorum_available(
            1,
            3,
            false,
            false,
            false,
            false,
            true,
            block_height,
            local_height
        ),
        "explicit contiguous-frontier sparse recovery should be accepted"
    );
    assert!(
        !super::block_sync_quorum_available(
            1,
            3,
            false,
            false,
            false,
            false,
            false,
            block_height,
            local_height
        ),
        "unsolicited sparse signatures should be rejected"
    );
    assert!(
        !super::block_sync_quorum_available(
            1,
            3,
            false,
            false,
            false,
            false,
            false,
            block_height.saturating_add(32),
            local_height
        ),
        "unsolicited far-ahead sparse signatures should be rejected"
    );
    assert!(
        !super::block_sync_quorum_available(
            1,
            3,
            false,
            false,
            false,
            false,
            true,
            block_height.saturating_add(1),
            local_height
        ),
        "explicit missing-block requests must not accept far-ahead sparse payloads"
    );
    assert!(
        !super::block_sync_quorum_available(
            0,
            3,
            false,
            false,
            false,
            false,
            true,
            block_height,
            local_height
        ),
        "explicit missing-block requests must not accept unsigned block sync updates"
    );
    assert!(
        super::block_sync_quorum_available(
            0,
            3,
            false,
            true,
            false,
            false,
            false,
            block_height,
            local_height
        ),
        "validated QC evidence should satisfy quorum even with no block signatures"
    );
    assert!(
        super::block_sync_quorum_available(
            0,
            3,
            false,
            false,
            true,
            false,
            false,
            block_height,
            local_height
        ),
        "commit certificate should satisfy quorum even with no block signatures"
    );
    assert!(
        super::block_sync_quorum_available(
            0,
            3,
            false,
            false,
            false,
            true,
            false,
            block_height,
            local_height
        ),
        "validator checkpoint should satisfy quorum even with no block signatures"
    );
    assert!(
        super::block_sync_quorum_available(
            3,
            3,
            true,
            false,
            false,
            false,
            false,
            block_height,
            local_height
        ),
        "quorum signatures should satisfy block sync requirements"
    );
}

#[test]
fn block_sync_commit_cert_present_rejects_locked_conflicts() {
    assert!(
        super::block_sync_commit_cert_present(true, true, false),
        "validated QC with commit-cert hint should be accepted when lock-compatible"
    );
    assert!(
        !super::block_sync_commit_cert_present(true, true, true),
        "locked-chain conflicts must prevent commit-cert quorum hints from being treated as evidence"
    );
    assert!(
        !super::block_sync_commit_cert_present(true, false, false),
        "an unvalidated QC cannot satisfy commit-cert evidence"
    );
    assert!(
        !super::block_sync_commit_cert_present(false, true, false),
        "without a commit-cert hint the QC path must not synthesize commit evidence"
    );
}

