#[test]
fn signer_index_normalization_round_trips_across_view_rotation() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let signature_topology =
        super::topology_for_view(&canonical_topology, 1, 1, super::PERMISSIONED_TAG, None);

    let canonical_signers: BTreeSet<ValidatorIndex> = [0_u32, 2_u32]
        .into_iter()
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index parses"))
        .collect();
    let view_signers = super::normalize_signer_indices_to_view(
        &canonical_signers,
        &signature_topology,
        &canonical_topology,
    );
    assert_eq!(view_signers.len(), canonical_signers.len());

    let roundtrip = super::normalize_signer_indices_to_canonical(
        &view_signers,
        &signature_topology,
        &canonical_topology,
    );
    assert_eq!(roundtrip, canonical_signers);

    for signer in &canonical_signers {
        let view_idx = super::view_index_for_canonical_signer(
            *signer,
            &signature_topology,
            &canonical_topology,
        )
        .expect("canonical signer should map to view index");
        assert!(view_signers.contains(&view_idx));
    }
}

#[test]
fn view_index_for_canonical_signer_accounts_for_rotation_offset() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let mut rotated = canonical_topology.clone();
    rotated.nth_rotation(1);

    let canonical0 = ValidatorIndex::try_from(0_u32).expect("validator index parses");
    let canonical1 = ValidatorIndex::try_from(1_u32).expect("validator index parses");
    let canonical2 = ValidatorIndex::try_from(2_u32).expect("validator index parses");

    let view0 = super::view_index_for_canonical_signer(canonical0, &rotated, &canonical_topology)
        .expect("maps");
    let view1 = super::view_index_for_canonical_signer(canonical1, &rotated, &canonical_topology)
        .expect("maps");
    let view2 = super::view_index_for_canonical_signer(canonical2, &rotated, &canonical_topology)
        .expect("maps");

    assert_eq!(
        view0,
        ValidatorIndex::try_from(2_u32).expect("validator index parses")
    );
    assert_eq!(
        view1,
        ValidatorIndex::try_from(0_u32).expect("validator index parses")
    );
    assert_eq!(
        view2,
        ValidatorIndex::try_from(1_u32).expect("validator index parses")
    );
}

#[test]
fn topology_for_view_rotates_npos_prf_leader() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);

    let seed = [0x22_u8; 32];
    let mut height = 1u64;
    let mut view = 0u64;
    let mut leader = canonical_topology.leader_index_prf(seed, height, view);
    if leader == 0 {
        'search: for h in 1u64..=64 {
            for v in 0u64..=8 {
                let candidate = canonical_topology.leader_index_prf(seed, h, v);
                if candidate != 0 {
                    height = h;
                    view = v;
                    leader = candidate;
                    break 'search;
                }
            }
        }
    }
    assert_ne!(leader, 0, "test requires non-zero PRF leader index");

    let rotated = super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed));
    let expected = canonical_topology
        .as_ref()
        .get(leader)
        .expect("leader peer exists");
    assert_eq!(rotated.as_ref().first(), Some(expected));
}

#[test]
fn topology_for_view_canonicalizes_npos_roster_order() {
    let kp_a = KeyPair::from_seed(vec![0xA1; 32], Algorithm::BlsNormal);
    let kp_b = KeyPair::from_seed(vec![0xB2; 32], Algorithm::BlsNormal);
    let kp_c = KeyPair::from_seed(vec![0xC3; 32], Algorithm::BlsNormal);
    let kp_d = KeyPair::from_seed(vec![0xD4; 32], Algorithm::BlsNormal);
    let mut canonical = vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
        PeerId::new(kp_d.public_key().clone()),
    ];
    canonical.sort();
    let topology = super::network_topology::Topology::new(canonical.clone());
    let mut scrambled = canonical.clone();
    scrambled.rotate_left(1);
    let scrambled_topology = super::network_topology::Topology::new(scrambled);

    let seed = [0x44_u8; 32];
    let mut height = 1u64;
    let mut view = 0u64;
    let mut leader = topology.leader_index_prf(seed, height, view);
    if leader == 0 {
        'search: for h in 1u64..=64 {
            for v in 0u64..=8 {
                let candidate = topology.leader_index_prf(seed, h, v);
                if candidate != 0 {
                    height = h;
                    view = v;
                    leader = candidate;
                    break 'search;
                }
            }
        }
    }
    assert_ne!(leader, 0, "test requires non-zero PRF leader index");

    let rotated = super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed));
    let rotated_scrambled = super::topology_for_view(
        &scrambled_topology,
        height,
        view,
        super::NPOS_TAG,
        Some(seed),
    );
    assert_eq!(rotated.as_ref(), rotated_scrambled.as_ref());
}

#[test]
fn validated_block_signers_accepts_npos_prf_rotation() {
    let keypairs = vec![
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
    ];
    let peers = keypairs
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect::<Vec<_>>();
    let topology = super::network_topology::Topology::new(peers);

    let seed = [0x33_u8; 32];
    let mut height = 1u64;
    let mut view = 0u64;
    let mut canonical = topology.clone();
    canonical.canonicalize_order();
    let mut leader = canonical.leader_index_prf(seed, height, view);
    if leader == 0 {
        'search: for h in 1u64..=64 {
            for v in 0u64..=8 {
                let candidate = canonical.leader_index_prf(seed, h, v);
                if candidate != 0 {
                    height = h;
                    view = v;
                    leader = candidate;
                    break 'search;
                }
            }
        }
    }
    assert_ne!(leader, 0, "test requires non-zero PRF leader index");
    let signature_topology =
        super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed));
    let leader_peer = signature_topology
        .as_ref()
        .first()
        .expect("leader present after rotation");
    let leader_kp = keypair_for_peer(&keypairs, leader_peer);

    let block = super::ValidBlock::new_dummy_and_modify_header(leader_kp.private_key(), |header| {
        header.set_height(NonZeroU64::new(height).expect("height"));
        header.set_view_change_index(view);
    });
    let block: SignedBlock = block.into();
    let state = State::new_for_testing(
        World::new(),
        Kura::blank_kura_for_testing(),
        LiveQueryStore::start_test(),
    );

    let signers = super::validated_block_signers(
        &block,
        &topology,
        &state.view(),
        super::NPOS_TAG,
        Some(seed),
    )
    .expect("block signatures should validate under NPoS rotation");
    assert_eq!(signers.len(), 1);
    assert!(signers.contains(&ValidatorIndex::from(0u16)));
}

#[test]
fn qc_validation_remaps_signers_across_block_and_qc_views() {
    let chain: ChainId = "qc-remap".parse().expect("chain id parses");
    let keypairs = vec![
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
        KeyPair::random_with_algorithm(Algorithm::BlsNormal),
    ];
    let peers = keypairs
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect::<Vec<_>>();
    let topology = super::network_topology::Topology::new(peers);

    // Block built in view 1 and signed against the rotated topology.
    let signature_topology =
        super::topology_for_view(&topology, 2, 1, super::PERMISSIONED_TAG, None);
    let leader_kp = keypair_at_index(&keypairs, &signature_topology, 0);
    let signer_kp_1 = keypair_at_index(&keypairs, &signature_topology, 1);
    let signer_kp_2 = keypair_at_index(&keypairs, &signature_topology, 2);
    let mut block =
        super::ValidBlock::new_dummy_and_modify_header(leader_kp.private_key(), |header| {
            header.set_view_change_index(1);
        });
    block.sign(signer_kp_1, &signature_topology);
    block.sign(signer_kp_2, &signature_topology);
    let block: SignedBlock = block.into();
    let state = State::new_for_testing(
        World::new(),
        Kura::blank_kura_for_testing(),
        LiveQueryStore::start_test(),
    );
    let block_signers = super::validated_block_signers(
        &block,
        &topology,
        &state.view(),
        super::PERMISSIONED_TAG,
        None,
    )
    .expect("block signatures should validate");

    // QC aggregated in a later view; bitmap is expressed in that rotated index space.
    let signers_bitmap = vec![0b0000_0111];
    let block_hash = block.hash();
    let qc = qc_with_bitmap(
        &chain,
        block_hash,
        block.header().height().get(),
        2,
        0,
        signers_bitmap,
        crate::sumeragi::consensus::Phase::Commit,
        &topology,
        &keypairs,
    );
    let world = world_with_consensus_keys(topology.as_ref(), &keypairs);
    let world_view = world.view();

    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    let (voting_signers, present) = super::validate_block_sync_qc(
        &qc,
        &topology,
        &world_view,
        &block_signers,
        block.header().view_change_index(),
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        None,
        None,
    )
    .expect("qc validation should succeed after remapping signers");

    let expected_signers =
        super::qc_signer_indices(&qc, topology.as_ref().len(), topology.as_ref().len())
            .expect("bitmap parses")
            .voting;
    assert_eq!(voting_signers, expected_signers);
    assert_eq!(present, 3);
}

