#[test]
fn validate_block_sync_qc_allows_signer_missing_from_block() {
    let chain: ChainId = "block-sync-forged-qc".parse().expect("chain id parses");
    let (keypairs, topology) = sample_bls_topology(3);
    let world = world_with_consensus_keys(topology.as_ref(), &keypairs);
    let world_view = world.view();
    let block_signers: BTreeSet<_> = [0_u32, 1_u32].into_iter().collect();
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x79; Hash::LENGTH]));
    // Bitmap claims signers 0, 1, and 2; signer index 2 never signed the block.
    let signers_bitmap = vec![0b0000_0111];
    let aggregate_signature = aggregate_signature_for_bitmap(
        &chain,
        super::PERMISSIONED_TAG,
        crate::sumeragi::consensus::Phase::Commit,
        block_hash,
        7,
        3,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let validator_set = topology.as_ref().to_vec();
    let qc = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 7,
        view: 3,
        epoch: 0,
        mode_tag: super::PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature: aggregate_signature,
        },
    };

    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    let result = super::validate_block_sync_qc(
        &qc,
        &topology,
        &world_view,
        &block_signers,
        qc.view,
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        None,
        None,
    );
    let (signers, present) =
        result.expect("QC should validate even when block omits some signatures");
    assert_eq!(signers.len(), 3);
    assert_eq!(present, 3);
}

#[test]
fn tally_qc_against_votes_counts_full_roster() {
    let chain: ChainId = "qc-tally-full-roster".parse().expect("chain id parses");
    let peer_keys: Vec<_> = (0..4)
        .map(|_| KeyPair::random_with_algorithm(Algorithm::BlsNormal))
        .collect();
    let peers: Vec<PeerId> = peer_keys
        .iter()
        .map(|kp| PeerId::new(kp.public_key().clone()))
        .collect();
    let topology = super::network_topology::Topology::new(peers);
    let world = world_with_consensus_keys(topology.as_ref(), &peer_keys);
    let world_view = world.view();
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x74; Hash::LENGTH]));
    let qc = qc_with_bitmap(
        &chain,
        block_hash,
        6,
        2,
        0,
        vec![0b0000_1111],
        crate::sumeragi::consensus::Phase::Commit,
        &topology,
        &peer_keys,
    );

    let mut vote_log = BTreeMap::new();
    for signer in 0..4u32 {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: crate::sumeragi::consensus::Phase::Commit,
            block_hash,
            parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            height: qc.height,
            view: qc.view,
            epoch: qc.epoch,
            highest_qc: None,
            signer,
            bls_sig: Vec::new(),
        };
        sign_vote_for_canonical_signer(&mut vote, &chain, &topology, &peer_keys);
        vote_log.insert(
            (vote.phase, vote.height, vote.view, vote.epoch, vote.signer),
            vote,
        );
    }

    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    let prf_seed = Some(prf_seed_for_chain(&chain));
    let tally = super::tally_qc_against_votes(
        &vote_log,
        &qc,
        &topology,
        &world_view,
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        prf_seed,
    )
    .expect("tally should succeed with four matching votes");

    assert_eq!(tally.voting_len(), 4);
    assert_eq!(tally.present_signers, 4);
    assert!(
        tally
            .voting_signers
            .contains(&ValidatorIndex::try_from(3).expect("validator index"))
    );
}

#[test]
fn tally_qc_against_votes_rejects_wrong_signature_key() {
    let chain: ChainId = "qc-tally-wrong-key".parse().expect("chain id parses");
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let peers = vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
    ];
    let topology = super::network_topology::Topology::new(peers);
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x75; Hash::LENGTH]));
    let peer_keys = vec![kp_a.clone(), kp_b.clone()];
    let world = world_with_consensus_keys(topology.as_ref(), &peer_keys);
    let world_view = world.view();
    let qc = qc_with_bitmap(
        &chain,
        block_hash,
        3,
        1,
        0,
        vec![0b0000_0011],
        crate::sumeragi::consensus::Phase::Commit,
        &topology,
        &peer_keys,
    );
    let prf_seed = Some(prf_seed_for_chain(&chain));

    let mut vote_log = BTreeMap::new();
    let mut vote_a = crate::sumeragi::consensus::Vote {
        phase: crate::sumeragi::consensus::Phase::Commit,
        block_hash,
        parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        height: qc.height,
        view: qc.view,
        epoch: qc.epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_canonical_signer(&mut vote_a, &chain, &topology, &peer_keys);
    vote_log.insert(
        (
            vote_a.phase,
            vote_a.height,
            vote_a.view,
            vote_a.epoch,
            vote_a.signer,
        ),
        vote_a,
    );

    // Second vote claims canonical signer 1 but is signed with the wrong peer key.
    let mut vote_b = crate::sumeragi::consensus::Vote {
        phase: crate::sumeragi::consensus::Phase::Commit,
        block_hash,
        parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        height: qc.height,
        view: qc.view,
        epoch: qc.epoch,
        highest_qc: None,
        signer: 1,
        bls_sig: Vec::new(),
    };
    sign_vote_for_canonical_signer(&mut vote_b, &chain, &topology, &peer_keys);
    let rotated = super::topology_for_view(
        &topology,
        qc.height,
        qc.view,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
    let signer_idx = usize::try_from(vote_b.signer).expect("signer fits usize");
    let expected = rotated
        .as_ref()
        .get(signer_idx)
        .expect("signer present in rotated topology");
    let wrong_kp = if expected.public_key() == kp_a.public_key() {
        &kp_b
    } else {
        &kp_a
    };
    let preimage_b = super::vote_preimage(&chain, super::PERMISSIONED_TAG, &vote_b);
    let sig_b = Signature::new(wrong_kp.private_key(), &preimage_b);
    vote_b.bls_sig = sig_b.payload().to_vec();
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let signature_topology = super::topology_for_view(
        &canonical_topology,
        qc.height,
        qc.view,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
    let mut claimed_view_signer = BTreeSet::new();
    claimed_view_signer.insert(ValidatorIndex::try_from(vote_b.signer).expect("signer fits u32"));
    let expected_invalid_signer = super::normalize_signer_indices_to_canonical(
        &claimed_view_signer,
        &signature_topology,
        &canonical_topology,
    )
    .into_iter()
    .next()
    .expect("view signer maps to canonical signer");
    vote_log.insert(
        (
            vote_b.phase,
            vote_b.height,
            vote_b.view,
            vote_b.epoch,
            vote_b.signer,
        ),
        vote_b,
    );

    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    let result = super::tally_qc_against_votes(
        &vote_log,
        &qc,
        &topology,
        &world_view,
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::PERMISSIONED_TAG,
        prf_seed,
    );
    assert!(
        matches!(
            result,
            Err(super::QcValidationError::InvalidSignature { .. })
        ),
        "expected InvalidSignature for signer {expected_invalid_signer}, got {result:?}"
    );
}

