#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_defers_reschedule_until_availability_timeout() {
    let mut harness = test_actor_harness(4).await;
    let _worker_guard = super::status::worker_queue_test_guard();
    super::status::reset_worker_loop_snapshot_for_tests();
    let actor = &mut harness.actor;
    actor.relay_backpressure.reset_to_current();
    actor.queue_drop_backpressure.reset_to_current();
    actor.queue_block_backpressure.reset_to_current();
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::prehashed([0xAA; Hash::LENGTH]);
    assert_ne!(
        Hash::new(&payload_bytes),
        payload_hash,
        "test requires mismatched payload hash"
    );
    let view_idx = block.header().view_change_index();
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view_idx),
    );
    let quorum_timeout = actor.quorum_timeout(true);
    let availability_timeout = actor.availability_timeout(quorum_timeout, true);
    {
        let pending = actor
            .pending
            .pending_blocks
            .get_mut(&block_hash)
            .expect("pending block");
        pending.validation_status = ValidationStatus::Valid;
        pending.inserted_at = Instant::now() - quorum_timeout - Duration::from_millis(1);
        pending.last_gate = Some(GateReason::ManifestGuard {
            lane: LaneId::new(2),
            epoch: 0,
            sequence: 1,
            kind: ManifestGateKind::Missing,
        });
    }
    assert!(
        quorum_timeout < availability_timeout,
        "availability timeout should exceed quorum timeout in DA mode"
    );
    assert!(actor.runtime_da_enabled(), "test requires DA to be enabled");
    actor.subsystems.da_rbc.rbc.sessions.clear();
    actor.subsystems.da_rbc.rbc.status_handle.clear();
    let payload_available = Hash::new(&payload_bytes) == payload_hash
        || super::rbc_payload_matches(
            &actor.subsystems.da_rbc.rbc.sessions,
            &actor.subsystems.da_rbc.rbc.status_handle,
            &block_hash,
            height,
            view_idx,
            &payload_hash,
        );
    assert!(!payload_available, "test requires missing local payload");
    actor.note_proposal_seen(height, view_idx, payload_hash);

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Event, None);

    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending retained");
    assert_eq!(
        pending_after.last_gate,
        Some(GateReason::MissingLocalData),
        "availability gate should record missing local data during commit processing"
    );
    assert!(
        pending_after.last_quorum_reschedule.is_none(),
        "commit pipeline should defer reschedule while availability is missing"
    );

    {
        let pending = actor
            .pending
            .pending_blocks
            .get_mut(&block_hash)
            .expect("pending retained");
        pending.inserted_at = Instant::now() - availability_timeout - Duration::from_millis(1);
    }

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Event, None);

    assert!(
        !actor.pending.pending_blocks.contains_key(&block_hash),
        "commit pipeline zero-vote reschedule should drop the pending block after availability timeout"
    );

    harness.shutdown.send();
}

