#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_accepts_stale_view_when_missing_block_requested() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let height = 6;
    let local_view = 2;
    let stale_view = 1;
    let now = Instant::now();
    let retry_window = Duration::from_secs(1);
    actor.phase_tracker.start_new_round(height, now);
    actor.phase_tracker.on_view_change(height, local_view, now);

    let topology_peers = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(topology_peers);
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology =
        super::topology_for_view(&topology, height, stale_view, mode_tag, prf_seed);
    let _leader_peer = signature_topology.as_ref().first().expect("leader present");
    let mut block = nonempty_block_for_actor(actor, &harness.key_pairs, height, stale_view, None);
    let required = signature_topology.min_votes_for_commit().max(1);
    let mut present = BTreeSet::new();
    for sig in block.signatures() {
        if let Ok(idx) = usize::try_from(sig.index()) {
            present.insert(idx);
        }
    }
    for (idx, peer) in signature_topology
        .as_ref()
        .iter()
        .enumerate()
        .take(required)
    {
        if present.contains(&idx) {
            continue;
        }
        let kp = harness
            .key_pairs
            .iter()
            .find(|kp| kp.public_key() == peer.public_key())
            .expect("signer keypair");
        let sig = SignatureOf::from_hash(kp.private_key(), block.header().hash());
        block
            .add_signature(BlockSignature::new(
                u64::try_from(idx).expect("signer index fits"),
                sig,
            ))
            .expect("signature added");
    }
    let block_hash = block.hash();

    actor.pending.missing_block_requests.insert(
        block_hash,
        MissingBlockRequest {
            height,
            view: stale_view,
            phase: Phase::Commit,
            priority: super::MissingBlockPriority::Consensus,
            retry_window,
            view_change_window: None,
            first_seen: now,
            last_requested: now,
            last_dependency_progress: now,
            last_rbc_observed: None,
            last_view_change_triggered: None,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );

    let update = super::message::BlockSyncUpdate::from(&block);
    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");
    assert!(actor.block_known_locally(block_hash));
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&block_hash)
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_keeps_aborted_next_height_payload_sparse_without_commit_evidence() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.da.enabled = true;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let genesis_hash = seed_genesis_block_for_state(&actor.state);
    let view = actor.state.view();
    let height = u64::try_from(view.height())
        .unwrap_or(u64::MAX)
        .saturating_add(1);
    drop(view);

    let block = nonempty_block_for_actor(actor, &harness.key_pairs, height, 0, Some(genesis_hash));
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block.clone(), payload_hash, height, 0);
    pending.mark_aborted();
    actor.pending.pending_blocks.insert(block_hash, pending);
    actor.pending.missing_block_requests.remove(&block_hash);

    assert!(
        !actor.block_known_locally(block_hash),
        "aborted pending payload should not be treated as known"
    );
    assert!(
        actor.block_payload_available_locally(block_hash),
        "aborted pending payload should still be locally available"
    );

    let update = super::message::BlockSyncUpdate::from(&block);
    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");

    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending block should remain cached");
    assert!(
        pending_after.aborted,
        "sparse next-height recovery traffic must not revive aborted pending without commit QC"
    );
    assert!(
        !actor.block_known_locally(block_hash),
        "aborted pending payload should remain unavailable for consensus progression without commit QC"
    );

    harness.shutdown.send();
}

