#[test]
fn pending_block_kura_retry_tracks_backoff_and_abort() {
    let parent = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x31; 32]));
    let block = sample_block(3, 1, Some(parent));
    let payload_hash = Hash::new(block.encode());
    let mut pending = PendingBlock::new(block, payload_hash, 3, 1);
    let now = Instant::now();
    let interval = Duration::from_millis(5);

    let first = pending.note_kura_failure(now, interval, 2);
    assert_eq!(
        first,
        super::kura::KuraRetryDecision::Retry {
            attempt: 1,
            next_in_ms: interval.as_millis().try_into().unwrap_or(u32::MAX)
        }
    );
    assert_eq!(pending.kura_retry_attempts, 1);
    assert!(pending.next_kura_retry.is_some());
    assert!(!pending.kura_aborted);
    assert!(!pending.kura_retry_due(now + Duration::from_millis(1)));

    let second = pending.note_kura_failure(now + interval, interval, 2);
    assert_eq!(
        second,
        super::kura::KuraRetryDecision::Abort { attempts: 2 }
    );
    assert!(pending.kura_aborted);
    assert!(!pending.kura_retry_due(now + interval));

    pending.reset_kura_retry();
    assert!(pending.kura_retry_due(now + interval));
    assert_eq!(pending.kura_retry_attempts, 0);
    assert!(!pending.kura_aborted);
}

#[tokio::test(flavor = "current_thread")]
async fn state_commit_failure_after_kura_store_keeps_partial_head_hidden() {
    use iroha_data_model::prelude::{Level, Log};

    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let genesis_key = KeyPair::random();
    let genesis_account_id = AccountId::new(genesis_key.public_key().clone());
    let genesis_domain = Domain::new(GENESIS_DOMAIN_ID.clone()).build(&genesis_account_id);
    let genesis_account = Account::new(
        genesis_account_id
            .clone()
            .to_account_id(GENESIS_DOMAIN_ID.clone()),
    )
    .build(&genesis_account_id);
    let world = World::with([genesis_domain], [genesis_account], []);
    let isolated_kura = Arc::new(Kura::blank_kura_for_testing());
    let query_handle = LiveQueryStore::start_test();
    let isolated_state = State::new_for_testing(world, Arc::clone(&isolated_kura), query_handle);
    let chain_id = isolated_state.view().chain_id().clone();
    let tx = TransactionBuilder::new(chain_id.clone(), genesis_account_id.clone())
        .with_instructions([Log::new(
            Level::DEBUG,
            "state commit failure visibility".to_string(),
        )])
        .sign(genesis_key.private_key());
    let block = SignedBlock::genesis(vec![tx], genesis_key.private_key(), None, None);
    let block_hash = block.hash();
    let height = block.header().height().get();
    let view = block.header().view_change_index();
    let commit_topology = actor.effective_commit_topology();

    let (events_sender, _events_rx) = tokio::sync::broadcast::channel(4);
    let (outcome, _timings) = commit::execute_commit_work(
        &isolated_state,
        isolated_kura.as_ref(),
        &chain_id,
        &genesis_account_id,
        commit::CommitWork {
            id: 77,
            block: block.clone(),
            validated_commit_artifact: None,
            commit_topology: commit_topology.clone(),
            signature_topology: commit_topology.clone(),
            consensus_mode: ConsensusMode::Permissioned,
            qc_signers: None,
            commit_qc: None,
            allow_quorum_bypass: false,
            allow_signature_index_recovery: false,
            persist_required: true,
            events_sender,
        },
    );
    let commit::CommitOutcome::Success {
        committed_block, ..
    } = outcome
    else {
        panic!("isolated commit should succeed");
    };
    actor
        .kura
        .store_block(committed_block.as_ref().clone())
        .expect("store committed block in actor kura");

    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let pending = PendingBlock::new(block, payload_hash, height, view);
    let lock = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        height,
        view,
        epoch: actor.epoch_for_height(height),
    };
    actor.subsystems.commit.inflight = Some(CommitInFlight {
        id: 42,
        lock,
        block_hash,
        pending,
        commit_topology: commit_topology.clone(),
        signature_topology: commit_topology.clone(),
        qc_signers: None,
        commit_qc: None,
        allow_quorum_bypass: false,
        post_commit_qc: None,
        enqueue_time: Instant::now(),
    });
    let (result_tx, result_rx) = mpsc::sync_channel(1);
    actor.subsystems.commit.result_rx = Some(result_rx);
    result_tx
        .send(commit::CommitResult {
            id: 42,
            outcome: commit::CommitOutcome::StateCommitFailed {
                committed_block,
                error: "injected state commit failure".to_string(),
            },
            timings: commit::CommitStageTimings::default(),
        })
        .expect("send commit result");

    assert!(
        actor.poll_commit_results(),
        "commit failure should be applied"
    );
    assert_eq!(actor.state.committed_height(), 0);
    assert!(
        actor.state.view().latest_block().is_none(),
        "committed head must remain hidden when state commit fails"
    );
    assert_eq!(
        actor.state.latest_block_hash_fast(),
        None,
        "fast head must remain unset when state commit fails"
    );
    assert_eq!(actor.kura.blocks_count(), 1);
    let pending = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("failed block should remain pending");
    assert!(
        pending.kura_persisted,
        "pending block should remember that Kura is already ahead"
    );

    harness.shutdown.send();
}

#[test]
fn handle_kura_store_failure_retries_and_preserves_state() {
    let _qc_guard = super::status::qc_status_test_guard();
    let _guard = super::status::kura_store_test_guard();
    super::status::reset_kura_store_counters_for_tests();
    let locked_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x31; 32]));
    let highest_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x32; 32]));
    super::status::set_locked_qc(5, 1, Some(locked_hash));
    super::status::set_highest_qc(6, 2);
    super::status::set_highest_qc_hash(highest_hash);

    let world = World::new();
    let kura = Kura::blank_kura_for_testing();
    let query = LiveQueryStore::start_test();
    let state = State::new_for_testing(world, Arc::clone(&kura), query);
    let events_sender = tokio::sync::broadcast::channel(4).0;
    let queue = Queue::from_config_with_router(
        QueueConfig::default(),
        events_sender,
        Arc::new(SingleLaneRouter),
    );

    let block = sample_block(3, 1, None);
    let payload_hash = Hash::new(block.encode());
    let block_hash = block.hash();
    let pending = PendingBlock::new(block.clone(), payload_hash, 3, 1);
    let now = Instant::now();
    let failure = Actor::handle_kura_store_failure(
        pending,
        block,
        block_hash,
        3,
        1,
        now,
        Duration::from_millis(5),
        3,
        &queue,
        &state,
        None,
    );

    let pending = failure
        .pending
        .expect("pending block should remain for retry");
    assert_eq!(pending.kura_retry_attempts, 1);
    assert!(!pending.kura_aborted);
    assert!(
        !pending.kura_retry_due(now),
        "backoff should defer immediate retry"
    );
    assert!(
        pending.kura_retry_due(now + Duration::from_millis(6)),
        "retry should become due after the backoff window"
    );
    assert_eq!(
        state.view().height(),
        0,
        "state height must not advance on kura store failure"
    );

    let snapshot = super::status::snapshot();
    assert_eq!(snapshot.locked_qc_height, 5);
    assert_eq!(snapshot.locked_qc_view, 1);
    assert_eq!(snapshot.highest_qc_height, 6);
    assert_eq!(snapshot.highest_qc_view, 2);
    assert_eq!(snapshot.kura_store.failures_total, 1);
    assert_eq!(snapshot.kura_store.last_retry_attempt, 1);
    assert_eq!(snapshot.kura_store.last_retry_backoff_ms, 5);
    assert_eq!(snapshot.kura_store.last_height, 3);
    assert_eq!(snapshot.kura_store.last_view, 1);
    assert_eq!(snapshot.kura_store.last_hash, Some(block_hash));

    super::status::set_locked_qc(0, 0, None);
    super::status::set_highest_qc(0, 0);
    super::status::set_highest_qc_hash(HashOf::from_untyped_unchecked(Hash::prehashed(
        [0; Hash::LENGTH],
    )));
    super::status::reset_kura_store_counters_for_tests();
}

