#[tokio::test(flavor = "current_thread")]
async fn pending_roster_activation_applies_at_activation_height_during_catchup() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;
    consensus_cfg.npos.epoch_length_blocks = 10;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let old_roster = actor.effective_commit_topology();
    let mut new_roster = old_roster.clone();
    new_roster.pop();
    assert!(
        new_roster.len() < old_roster.len(),
        "test roster should shrink"
    );

    let activate_at = 12u64;
    actor.pending_roster_activation = Some((activate_at, new_roster.clone()));
    actor.last_committed_height = 8;
    actor.block_count.0 = 8;

    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    for idx in 1_u8..=12 {
        let hash = HashOf::from_untyped_unchecked(Hash::prehashed([idx; Hash::LENGTH]));
        state.push_block_hash_for_testing(hash);
    }

    assert!(actor.poll_committed_blocks(), "commits should be processed");

    let view = actor.state.view();
    let record = view.world().vrf_epochs().get(&0).expect("epoch record");
    assert_eq!(
        record.roster_len,
        u32::try_from(old_roster.len()).unwrap_or(u32::MAX),
        "epoch snapshot should use pre-activation roster during catch-up"
    );
    assert_eq!(
        actor.effective_commit_topology(),
        new_roster,
        "commit topology should activate at or after the activation height"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn poll_committed_blocks_refreshes_p2p_topology_without_new_height() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let initial_topology: BTreeSet<_> = actor.state.view().world.peers().iter().cloned().collect();
    actor.last_advertised_topology = initial_topology.clone();
    actor.last_committed_height = actor.state.view().height() as u64;

    let (new_peer, _pop, _kp) = bls_peer("127.0.0.1:10005");
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut peers_block = state.world.peers.block();
        let mut peers_tx = peers_block.transaction();
        peers_tx.push(new_peer.id().clone());
        peers_tx.apply();
        peers_block.commit();
    }

    assert!(
        !actor.poll_committed_blocks(),
        "no new heights should be processed"
    );
    assert!(
        actor.last_advertised_topology.contains(new_peer.id()),
        "p2p topology should refresh when world peers change without height updates"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn refresh_p2p_topology_skips_removal_until_local_seen() {
    let _guard = LocalRemovedGuard::new(false);
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let local_peer = actor.common_config.peer.id().clone();

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut peers_block = state.world.peers.block();
        let mut peers_tx = peers_block.transaction();
        if let Some(idx) = peers_tx.iter().position(|peer| peer == &local_peer) {
            peers_tx.remove(idx);
        }
        peers_tx.apply();
        peers_block.commit();
    }

    actor.local_peer_seen_in_world = false;
    actor.refresh_p2p_topology();

    assert!(
        !super::status::local_peer_removed(),
        "local peer should not be marked removed before it is seen in world"
    );

    harness.shutdown.send();
}

